import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppState {
  ONBOARDING = 'ONBOARDING',
  DASHBOARD = 'DASHBOARD',
  GENERATING = 'GENERATING',
  PLAYING = 'PLAYING'
}

export interface UserInfo {
  name: string;
  mobile: string;
}

export interface SongRequest {
  prompt: string;
  genre: string;
  mood: string;
  durationSeconds: number;
  bpm: number;
}

export interface MacroStructure {
  earlyPhase: string;
  middleEvolution: string;
  lateResolution: string;
  phases: Array<{
    startTime: number;
    endTime: number;
    description: string;
    intensity: number;
  }>;
}

export interface GenerationStatus {
  progress: number;
  currentSegment: number;
  totalSegments: number;
  statusText: string;
  videoUrl?: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { SongRequest, MacroStructure } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function createMusicBlueprint(request: SongRequest): Promise<MacroStructure> {
  const isLongForm = request.durationSeconds > 600; // 10 minutes

  const systemPrompt = `You are a world-class AI music architect. 
  Your task is to design a detailed blueprint for a ${request.durationSeconds} second ${request.genre} track.

  RULES:
  1. For long-form content (>10 mins), ensure a macro-structure: Early, Middle, Late phases.
  2. Keep BPM (${request.bpm}) and key constant for continuity.
  3. Introduce slow evolution to avoid listener fatigue.
  4. Break the entire duration into distinct phases.
  5. The output MUST be valid JSON.`;

  const userPrompt = `Create a music blueprint for:
  Prompt: ${request.prompt}
  Genre: ${request.genre}
  Duration: ${request.durationSeconds}s
  Mood: ${request.mood}
  BPM: ${request.bpm}`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: userPrompt,
    config: {
      systemInstruction: systemPrompt,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          earlyPhase: { type: Type.STRING },
          middleEvolution: { type: Type.STRING },
          lateResolution: { type: Type.STRING },
          phases: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                startTime: { type: Type.NUMBER },
                endTime: { type: Type.NUMBER },
                description: { type: Type.STRING },
                intensity: { type: Type.NUMBER }
              },
              required: ["startTime", "endTime", "description", "intensity"]
            }
          }
        },
        required: ["earlyPhase", "middleEvolution", "lateResolution", "phases"]
      }
    }
  });

  return JSON.parse(response.text.trim());
}

export async function generateVisualPrompt(request: SongRequest): Promise<string> {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Create a highly descriptive visual prompt for a looping, non-fatiguing background video for a ${request.durationSeconds} second ${request.genre} track about: ${request.prompt}. The visuals should be atmospheric, cinematic, and complementary to focus/coding. Avoid high-contrast flickering.`
  });
  return response.text;
}

export async function generateSegmentMetadata(request: SongRequest, phase: string, segmentIndex: number): Promise<string> {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Describe the specific audio characteristics for Segment #${segmentIndex} of a ${request.genre} track. 
    Current Macro-Phase: ${phase}.
    Ensure smooth transition from the previous segment. Focus on: ${request.prompt}.`
  });
  return response.text;
}

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline';
  fullWidth?: boolean;
  loading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  fullWidth = false, 
  loading = false,
  className = '',
  ...props 
}) => {
  const baseStyles = "px-6 py-3 rounded-lg font-semibold transition-all duration-200 flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "caffeine-gradient text-white hover:brightness-110 neon-glow",
    secondary: "bg-zinc-800 text-zinc-100 hover:bg-zinc-700",
    outline: "border border-zinc-700 text-zinc-300 hover:border-zinc-500 hover:bg-zinc-900/50"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${fullWidth ? 'w-full' : ''} ${className}`}
      disabled={loading}
      {...props}
    >
      {loading ? (
        <svg className="animate-spin h-5 w-5 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
        </svg>
      ) : children}
    </button>
  );
};

import React from 'react';

interface InputProps extends React.InputHTMLAttributes<HTMLInputElement | HTMLTextAreaElement> {
  label?: string;
  error?: string;
  isTextArea?: boolean;
}

export const Input: React.FC<InputProps> = ({ label, error, isTextArea, className = '', ...props }) => {
  const Component = isTextArea ? 'textarea' : 'input';

  return (
    <div className="w-full space-y-1.5">
      {label && <label className="block text-sm font-medium text-zinc-400">{label}</label>}
      <Component
        className={`w-full bg-zinc-900/50 border border-zinc-800 rounded-lg px-4 py-3 text-zinc-100 placeholder-zinc-600 focus:outline-none focus:border-orange-500 focus:ring-1 focus:ring-orange-500/50 transition-all ${className}`}
        {...props as any}
      />
      {error && <p className="text-xs text-red-500 mt-1">{error}</p>}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { AppState, UserInfo, SongRequest, MacroStructure, GenerationStatus } from './types';
import { Button } from './components/Button';
import { Input } from './components/Input';
import { createMusicBlueprint, generateVisualPrompt, generateSegmentMetadata } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(AppState.ONBOARDING);
  const [user, setUser] = useState<UserInfo>({ name: '', mobile: '' });
  const [request, setRequest] = useState<SongRequest>({
    prompt: '',
    genre: 'Deep Techno',
    mood: 'Focus',
    durationSeconds: 3600, // 1 hour default
    bpm: 124
  });
  const [blueprint, setBlueprint] = useState<MacroStructure | null>(null);
  const [genStatus, setGenStatus] = useState<GenerationStatus>({
    progress: 0,
    currentSegment: 0,
    totalSegments: 0,
    statusText: 'Initializing engine...'
  });
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [videoUrl, setVideoUrl] = useState<string | null>(null);

  const handleOnboarding = (e: React.FormEvent) => {
    e.preventDefault();
    if (user.name && user.mobile) setState(AppState.DASHBOARD);
  };

  const startGeneration = async () => {
    setState(AppState.GENERATING);
    setGenStatus(prev => ({ ...prev, statusText: 'Analyzing long-form structure...' }));

    try {
      // 1. Planning phase
      const musicBlueprint = await createMusicBlueprint(request);
      setBlueprint(musicBlueprint);

      const totalSegs = Math.ceil(request.durationSeconds / 30); // 30s chunks
      setGenStatus(prev => ({ ...prev, totalSegments: totalSegs, progress: 5, statusText: 'Synthesizing visual environment...' }));

      // 2. Visual Generation
      const visPrompt = await generateVisualPrompt(request);
      // Simulated video generation for demo (using placeholder)
      // In a real scenario, we'd use veo-3.1-fast-generate-preview here
      setVideoUrl(`https://picsum.photos/seed/${encodeURIComponent(request.prompt)}/1920/1080`);

      // 3. Audio Orchestration Loop
      for (let i = 0; i < Math.min(totalSegs, 5); i++) { // Generate first few segments for instant play
        const phase = i / totalSegs < 0.3 ? musicBlueprint.earlyPhase : (i / totalSegs < 0.7 ? musicBlueprint.middleEvolution : musicBlueprint.lateResolution);
        const metadata = await generateSegmentMetadata(request, phase, i);

        setGenStatus(prev => ({
          ...prev,
          currentSegment: i + 1,
          progress: Math.floor(10 + (i / totalSegs) * 80),
          statusText: `Mastering segment ${i + 1}/${totalSegs}...`
        }));

        // Brief simulated delay for "generation"
        await new Promise(r => setTimeout(r, 1000));
      }

      setGenStatus(prev => ({ ...prev, progress: 100, statusText: 'Ready to stream.' }));
      // Use a sample long-form ambient track for demo
      setAudioUrl('https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3');
      setState(AppState.PLAYING);

    } catch (error) {
      console.error(error);
      setGenStatus(prev => ({ ...prev, statusText: 'Error initializing engine. Please retry.' }));
    }
  };

  const formatDuration = (sec: number) => {
    const hours = Math.floor(sec / 3600);
    const minutes = Math.floor((sec % 3600) / 60);
    const seconds = sec % 60;
    return `${hours > 0 ? hours + 'h ' : ''}${minutes}m ${seconds}s`;
  };

  if (state === AppState.ONBOARDING) {
    return (
      <div className="min-h-screen flex items-center justify-center p-4 bg-[url('https://images.unsplash.com/photo-1514467958574-23bceb9621f7?q=80&w=2070&auto=format&fit=crop')] bg-cover bg-center">
        <div className="absolute inset-0 bg-black/80 backdrop-blur-sm"></div>
        <div className="relative z-10 w-full max-w-md bg-zinc-950/80 border border-zinc-800 p-8 rounded-2xl shadow-2xl">
          <div className="mb-8 text-center">
            <h1 className="text-4xl font-space font-bold text-white mb-2">Caffeine<span className="text-orange-600">.ai</span></h1>
            <p className="text-zinc-400">Fuel your focus with infinite AI soundscapes.</p>
          </div>
          <form onSubmit={handleOnboarding} className="space-y-6">
            <Input 
              label="What's your name?" 
              placeholder="e.g. Satoshi" 
              value={user.name} 
              onChange={e => setUser({...user, name: e.target.value})}
              required
            />
            <Input 
              label="Mobile Number" 
              placeholder="+1 (555) 000-0000" 
