  }

  if (state === AppState.DASHBOARD) {
    return (
      <div className="min-h-screen p-4 md:p-12 max-w-6xl mx-auto">
        <header className="flex justify-between items-center mb-12">
          <h1 className="text-3xl font-space font-bold tracking-tight">Caffeine<span className="text-orange-500">.ai</span></h1>
          <div className="flex items-center gap-4 text-zinc-400">
            <span className="text-sm font-medium">Welcome, {user.name}</span>
            <div className="w-8 h-8 rounded-full caffeine-gradient"></div>
          </div>
        </header>

        <div className="grid md:grid-cols-2 gap-12">
          <div className="space-y-8">
            <h2 className="text-4xl font-space font-bold leading-tight">Create your next <br/><span className="text-orange-500">long-form</span> experience.</h2>
            <div className="space-y-6">
              <Input 
                isTextArea 
                label="Prompt" 
                placeholder="Describe the vibe... e.g. 12 hours of deep atmospheric techno for deep work in a rainy city."
                rows={4}
                value={request.prompt}
                onChange={e => setRequest({...request, prompt: e.target.value})}
              />
              <div className="grid grid-cols-2 gap-4">
                <Input 
                  label="Genre" 
