                  onChange={e => setRequest({...request, mood: e.target.value})}
                />
              </div>
              <div className="space-y-2">
                <div className="flex justify-between">
                  <label className="text-sm font-medium text-zinc-400">Duration</label>
                  <span className="text-sm font-bold text-orange-500">{formatDuration(request.durationSeconds)}</span>
                </div>
                <input 
                  type="range" 
                  min="30" 
                  max="72000" 
                  step="30"
                  className="w-full h-2 bg-zinc-800 rounded-lg appearance-none cursor-pointer accent-orange-500"
                  value={request.durationSeconds}
                  onChange={e => setRequest({...request, durationSeconds: parseInt(e.target.value)})}
                />
                <div className="flex justify-between text-[10px] text-zinc-600 uppercase font-bold">
                  <span>30s</span>
                  <span>10m</span>
                  <span>1h</span>
                  <span>5h</span>
                  <span>20h</span>
                </div>
              </div>
              <div className="pt-4">
                <Button fullWidth onClick={startGeneration} disabled={!request.prompt}>
                  Generate Infinite Stream
                </Button>
              </div>
            </div>
          </div>

          <div className="hidden md:block">
            <div className="relative rounded-3xl overflow-hidden aspect-square border border-zinc-800 group cursor-pointer">
              <img 
                src="https://images.unsplash.com/photo-1511671782779-c97d3d27a1d4?q=80&w=2070&auto=format&fit=crop" 
                alt="Studio" 
                className="w-full h-full object-cover opacity-60 group-hover:scale-105 transition-transform duration-700"
              />
              <div className="absolute inset-0 bg-gradient-to-t from-black via-black/20 to-transparent"></div>
              <div className="absolute bottom-8 left-8 right-8">
                <div className="p-4 bg-zinc-900/80 backdrop-blur-md rounded-xl border border-white/10">
                  <p className="text-xs font-bold text-orange-500 uppercase tracking-widest mb-1">Latest Master</p>
                  <p className="text-sm text-zinc-300">"Midnight Rain" - 4h Ambient Lo-fi</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  if (state === AppState.GENERATING) {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-black">
        <div className="w-full max-w-2xl text-center space-y-12">
          <div className="relative">
            <div className="w-32 h-32 mx-auto rounded-full border-4 border-orange-500/20 border-t-orange-500 animate-spin"></div>
            <div className="absolute inset-0 flex items-center justify-center">
              <span className="text-xl font-space font-bold">{genStatus.progress}%</span>
            </div>
          </div>

          <div className="space-y-4">
            <h2 className="text-3xl font-space font-bold animate-pulse-slow">{genStatus.statusText}</h2>
            <p className="text-zinc-500 max-w-md mx-auto">
              Caffeine.ai is mapping the macro-structure for your {formatDuration(request.durationSeconds)} experience. 
              {request.durationSeconds > 600 && " Designing multi-phase variations to prevent listener fatigue."}
            </p>
          </div>

          <div className="space-y-2">
             <div className="flex justify-between text-xs font-bold text-zinc-600 uppercase mb-1">
                <span>Phase: {blueprint?.phases.find(p => p.startTime <= (genStatus.progress/100 * request.durationSeconds) && p.endTime >= (genStatus.progress/100 * request.durationSeconds))?.description || 'Structural Mapping'}</span>
                <span>BPM: {request.bpm}</span>
             </div>
             <div className="w-full bg-zinc-900 h-1.5 rounded-full overflow-hidden">
                <div 
                  className="h-full caffeine-gradient transition-all duration-500" 
                  style={{ width: `${genStatus.progress}%` }}
