import { GoogleGenAI, Type } from "@google/genai";
import { SongRequest, MacroStructure } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getAISuggestion(field: keyof SongRequest, currentRequest: Partial<SongRequest>): Promise<string> {
  const context = JSON.stringify(currentRequest);
  const prompt = `You are a world-class music production consultant. 
  Suggest a 2-5 line mini-specification for the field "${field.toString()}" based on this context: ${context}.

  STRICT RULES:
  - Must explain *why* it fits.
  - Must describe impact on sound, structure, or feel.
  - Avoid poetic fluff.
  - Reference existing fields.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
  });

  return response.text.trim();
}

export async function createMusicBlueprint(request: SongRequest): Promise<MacroStructure> {
  const systemPrompt = `You are a world-class AI music architect. 
  Plan a ${request.durationSeconds}s ${request.genre} experience.

  RULES:
  1. For tracks >10 mins, ensure macro-structure: Early, Middle, Late phases.
  2. Maintain constant BPM (${request.bpm}) and Key (${request.keyScale}).
  3. Break duration into distinct phases (max 12 phases for extreme lengths).
  4. Each phase needs instrumentation focus and intensity mapping (0-100).
  5. The output MUST be valid JSON.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Plan the song: ${JSON.stringify(request)}`,
    config: {
      systemInstruction: systemPrompt,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          earlyPhase: { type: Type.STRING },
          middleEvolution: { type: Type.STRING },
          lateResolution: { type: Type.STRING },
          bpm: { type: Type.NUMBER },
          key: { type: Type.STRING },
          phases: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                startTime: { type: Type.NUMBER },
                endTime: { type: Type.NUMBER },
                description: { type: Type.STRING },
                intensity: { type: Type.NUMBER },
                instrumentationFocus: { type: Type.STRING }
              },
              required: ["startTime", "endTime", "description", "intensity", "instrumentationFocus"]
            }
          }
        },
        required: ["earlyPhase", "middleEvolution", "lateResolution", "phases", "bpm", "key"]
      }
    }
  });

  return JSON.parse(response.text.trim());
}

export async function generateBackgroundVisual(prompt: string): Promise<string> {
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: `High-quality cinematic background, non-fatiguing loop, atmospheric: ${prompt}`,
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return '';
}

