import { GoogleGenAI, Type } from "@google/genai";
import { SongRequest, ImmutableSongPlan } from "../types";

const API_KEY = process.env.API_KEY;

if (!API_KEY) {
  console.error("CRITICAL: GOOGLE_API_KEY environment variable is missing.");
}

const ai = new GoogleGenAI({ apiKey: API_KEY || '' });

export function checkApiKey() {
  if (!API_KEY) throw new Error("API Key Missing: Please ensure GOOGLE_API_KEY is configured.");
}

export async function getAISuggestion(field: keyof SongRequest, currentRequest: Partial<SongRequest>): Promise<string> {
  checkApiKey();
  const context = JSON.stringify(currentRequest);

  const prompt = `You are a world-class music production consultant. 
  Provide a high-precision mini-specification (2-5 sentences) for the field "${field.toString()}" in an AI music generation platform.

  CONTEXT: ${context}

  STRICT RULES:
  - Explain EXACTLY why this fits based on the other fields.
  - Describe the impact on sound architecture, arrangement density, and listener psychology.
  - No poetic fluff. Use technical but accessible production terminology.
  - Reference at least one other filled field.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
  });

  return response.text.trim();
}

export async function createImmutableSongPlan(request: SongRequest): Promise<ImmutableSongPlan> {
  checkApiKey();
  const systemPrompt = `You are the Core Planning Unit for a high-end music generation system.
  Before any audio is synthesized, you must create an immutable, mathematically consistent plan.

  BPM must be constant: ${request.bpm || 120}.
  Key must be constant: ${request.keyScale || 'C Minor'}.
  Duration: ${request.durationSeconds}s.

  For long tracks (>10 mins), ensure slow, controlled texture evolution strategies.

  OUTPUT FORMAT: JSON only.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Plan the song structure for: ${JSON.stringify(request)}`,
    config: {
      systemInstruction: systemPrompt,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          bpm: { type: Type.NUMBER },
          key: { type: Type.STRING },
          scale: { type: Type.STRING },
          timeSignature: { type: Type.STRING },
          instrumentPalette: { type: Type.ARRAY, items: { type: Type.STRING } },
          vocalPresenceMap: { type: Type.STRING },
          sections: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                startTime: { type: Type.NUMBER },
                endTime: { type: Type.NUMBER },
                label: { type: Type.STRING },
                energy: { type: Type.NUMBER },
                description: { type: Type.STRING }
              },
              required: ["startTime", "endTime", "label", "energy", "description"]
            }
          },
          macroEnergyCurve: { type: Type.ARRAY, items: { type: Type.NUMBER } },
          textureEvolutionStrategy: { type: Type.STRING }
        },
        required: ["bpm", "key", "scale", "timeSignature", "instrumentPalette", "sections", "macroEnergyCurve", "textureEvolutionStrategy"]
      }
    }
  });

  return JSON.parse(response.text.trim());
}

export async function generateVisualReference(prompt: string): Promise<string> {
  checkApiKey();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: `Cinematic loop background for music video, premium aesthetic, minimal, high-resolution: ${prompt}`,
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return '';
}

import React, { useState, useEffect, useMemo } from 'react';
import { AppState, UserLocalProfile, SongRequest, ImmutableSongPlan, SongHistoryItem, GenerationStatus } from './types';
import { Button } from './components/Button';
import { Input } from './components/Input';
import { getAISuggestion, createImmutableSongPlan, generateVisualReference, checkApiKey } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(AppState.ONBOARDING);
  const [user, setUser] = useState<UserLocalProfile | null>(null);
  const [error, setError] = useState<string | null>(null);

  const [request, setRequest] = useState<SongRequest>({
    title: '', description: '', genre: '', subGenre: '', mood: '',
    energyLevel: 'Medium', tempoPreference: 'Moderate', bpm: 124, keyScale: 'A Minor',
    language: 'English', lyricsMode: 'Instrumental', lyricsInput: '', 
    vocalPresence: 'None', vocalGender: 'Neutral', vocalStyle: 'None',
    instrumentation: 'Digital Synths, Ambient Pads', durationSeconds: 180,
    structure: 'Intro-Body-Outro', sectionLength: 'Moderate', energyCurve: 'Linear',
    referenceArtists: '', useCase: 'Personal Listening', videoStyle: 'Abstract Geometric',
    visualIntensity: 'Low', visualEvolution: 'Slow Morphing'
  });

  const [suggestions, setSuggestions] = useState<Record<string, string>>({});
  const [loadingSuggestion, setLoadingSuggestion] = useState<string | null>(null);
  const [history, setHistory] = useState<SongHistoryItem[]>([]);
  const [activeItem, setActiveItem] = useState<SongHistoryItem | null>(null);
  const [genStatus, setGenStatus] = useState<GenerationStatus>({ progress: 0, currentSegment: 0, totalSegments: 0, statusText: '' });

  useEffect(() => {
    try {
      checkApiKey();
    } catch (e: any) {
      setError(e.message);
    }

    const savedUser = localStorage.getItem('cf_user');
    const savedHistory = localStorage.getItem('cf_history');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
      setState(AppState.DASHBOARD);
    }
    if (savedHistory) setHistory(JSON.parse(savedHistory));
  }, []);

  const saveProfile = (e: React.FormEvent) => {
    e.preventDefault();
    const formData = new FormData(e.target as HTMLFormElement);
    const profile: UserLocalProfile = {
      user_id: crypto.randomUUID(),
      name: formData.get('name') as string,
      phone_number: formData.get('mobile') as string,
      created_at: Date.now(),
      last_active_at: Date.now()
    };
    localStorage.setItem('cf_user', JSON.stringify(profile));
    setUser(profile);
    setState(AppState.DASHBOARD);
  };

  const resetApp = () => {
    localStorage.clear();
    window.location.reload();
  };

  const fetchSuggestion = async (field: keyof SongRequest) => {
    setLoadingSuggestion(field as string);
    try {
      const spec = await getAISuggestion(field, request);
      setSuggestions(prev => ({ ...prev, [field]: spec }));
    } catch (e: any) {
      setError(e.message);
    } finally {
      setLoadingSuggestion(null);
    }
  };

  const startGenerationPipeline = async () => {
    setState(AppState.PLANNING);
    setGenStatus({ progress: 0, currentSegment: 0, totalSegments: 0, statusText: 'Initializing Planning Module...' });

    try {
      const plan = await createImmutableSongPlan(request);
      setGenStatus({ progress: 10, currentSegment: 0, totalSegments: 0, statusText: 'Finalizing Immutable Song Plan...' });

      const segDuration = 600; // 10 min segments
      const totalSegs = Math.ceil(request.durationSeconds / segDuration);

      setState(AppState.GENERATING);
      setGenStatus(prev => ({ ...prev, totalSegments: totalSegs, statusText: 'Synthesizing Visual Atmosphere...' }));

      const visRef = await generateVisualReference(`${request.videoStyle} ${request.description} ${plan.textureEvolutionStrategy}`);

      // Orchestration loop
      for (let i = 0; i < totalSegs; i++) {
        setGenStatus(prev => ({
          ...prev,
          currentSegment: i + 1,
          progress: Math.floor(20 + (i / totalSegs) * 75),
          statusText: `Synthesizing Audio Segment ${i + 1}/${totalSegs}...`
        }));
        await new Promise(r => setTimeout(r, 1500)); // Simulating production cycles
      }

      const newItem: SongHistoryItem = {
        id: crypto.randomUUID(),
        request: { ...request },
        plan,
        audioUrl: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-8.mp3',
        videoUrl: visRef,
        createdAt: Date.now()
      };

      const updatedHistory = [newItem, ...history];
      setHistory(updatedHistory);
      localStorage.setItem('cf_history', JSON.stringify(updatedHistory));
      setActiveItem(newItem);
      setState(AppState.PLAYING);

    } catch (e: any) {
      setError(e.message);
      setState(AppState.DASHBOARD);
    }
  };

  const formatDuration = (s: number) => {
    const h = Math.floor(s / 3600);
    const m = Math.floor((s % 3600) / 60);
    const sc = s % 60;
    return `${h > 0 ? h + 'h ' : ''}${m}m ${sc}s`;
  };

  if (error) {
    return (
      <div className="min-h-screen flex items-center justify-center p-8 text-center bg-black">
        <div className="max-w-md p-8 border border-red-900 bg-red-900/10 rounded-2xl">
          <h2 className="text-2xl font-bold text-red-500 mb-4">Execution Error</h2>
          <p className="text-zinc-400 mb-6">{error}</p>
          <Button onClick={() => window.location.reload()}>Retry System</Button>
        </div>
      </div>
    );
  }

  if (state === AppState.ONBOARDING) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-black p-4">
        <div className="w-full max-w-md bg-zinc-900/40 backdrop-blur-3xl p-10 border border-zinc-800 rounded-3xl shadow-2xl">
          <div className="text-center mb-10">
            <h1 className="text-4xl font-space font-black tracking-tight mb-2">Caffeine<span className="text-orange-500">.ai</span></h1>
            <p className="text-zinc-500 font-medium">Professional Soundscape Synthesis</p>
          </div>
          <form onSubmit={saveProfile} className="space-y-6">
            <Input name="name" label="Full Name" placeholder="Satoshi Nakamoto" required />
            <Input name="mobile" label="Mobile Number" placeholder="+1 (555) 000-0000" type="tel" required />
            <Button fullWidth type="submit">Initialize Engine</Button>
          </form>
        </div>
      </div>
    );
  }

  const InputGroup = ({ title, fields }: { title: string, fields: (keyof SongRequest)[] }) => (
    <div className="space-y-6 pt-6 first:pt-0">
      <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 mb-4 px-1">{title}</h3>
      <div className="space-y-6">
        {fields.map(f => (
          <div key={f} className="space-y-3 group">
            <div className="flex items-end gap-2">
              <div className="flex-1">
                {f === 'durationSeconds' ? (
                  <div className="space-y-2">
                    <div className="flex justify-between items-center">
                       <label className="text-xs font-bold text-zinc-500">Duration: {formatDuration(request.durationSeconds)}</label>
                    </div>
                    <input 
                      type="range" min="30" max="72000" step="30"
                      className="w-full h-1 bg-zinc-800 rounded-full appearance-none accent-orange-500 cursor-pointer"
                      value={request.durationSeconds}
                      onChange={e => setRequest({...request, durationSeconds: parseInt(e.target.value)})}
                    />
                  </div>
                ) : (
                  <Input 
                    label={f.charAt(0).toUpperCase() + f.slice(1).replace(/([A-Z])/g, ' $1')}
                    isTextArea={['description', 'lyricsInput', 'instrumentation'].includes(f)}
                    value={(request as any)[f]}
                    onChange={e => setRequest({...request, [f]: e.target.value})}
                    placeholder={`e.g. ${f === 'title' ? 'Starlight Echoes' : 'High quality spec...'}`}
                  />
                )}
              </div>
              <button 
                onClick={() => fetchSuggestion(f)}
                disabled={loadingSuggestion === f}
                className="mb-1 p-2.5 rounded-lg border border-zinc-800 bg-zinc-900 text-zinc-500 hover:text-orange-500 hover:border-orange-500/50 transition-all disabled:opacity-30"
                title="AI Suggest"
              >
                {loadingSuggestion === f ? <div className="w-4 h-4 border-2 border-orange-500/30 border-t-orange-500 rounded-full animate-spin"/> : '✨'}
              </button>
            </div>
            {suggestions[f] && (
              <div className="p-3 rounded-xl bg-orange-500/5 border border-orange-500/10 text-[11px] leading-relaxed text-orange-400/90 font-medium">
                {suggestions[f]}
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-black text-zinc-100 flex flex-col md:flex-row overflow-hidden">
      {/* Sidebar: Config Panel */}
      <div className="w-full md:w-[420px] h-screen border-r border-zinc-900 bg-zinc-950 flex flex-col overflow-hidden shadow-2xl z-20">
        <div className="p-6 border-b border-zinc-900 flex justify-between items-center bg-zinc-950/80 backdrop-blur-md">
           <h2 className="text-xl font-space font-black tracking-tight">Project <span className="text-orange-500">Master</span></h2>
           <button onClick={resetApp} className="text-[9px] font-black uppercase text-zinc-600 hover:text-red-500 tracking-widest transition-colors">Reset System</button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-12 scrollbar-hide">
          <InputGroup title="Identity & Concept" fields={['title', 'description', 'useCase', 'referenceArtists']} />
          <InputGroup title="Musical Architecture" fields={['genre', 'subGenre', 'mood', 'energyLevel', 'tempoPreference', 'bpm', 'keyScale']} />
          <InputGroup title="Voice & Narrative" fields={['lyricsMode', 'lyricsInput', 'vocalPresence', 'vocalGender', 'vocalStyle', 'language']} />
          <InputGroup title="Arrangement Logic" fields={['durationSeconds', 'structure', 'sectionLength', 'energyCurve', 'instrumentation']} />
          <InputGroup title="Visual Aesthetic" fields={['videoStyle', 'visualIntensity', 'visualEvolution']} />
        </div>

        <div className="p-6 border-t border-zinc-900 bg-zinc-950">
           <Button fullWidth onClick={startGenerationPipeline} disabled={!request.title || !request.description}>
             Begin Synthesis Pipeline
           </Button>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 relative flex flex-col h-screen overflow-hidden bg-[#020202]">
        {state === AppState.PLANNING || state === AppState.GENERATING ? (
          <div className="flex-1 flex flex-col items-center justify-center p-12 text-center">
            <div className="relative mb-12">
               <div className="w-32 h-32 rounded-full border border-orange-500/10 flex items-center justify-center">
                  <div className="w-24 h-24 rounded-full border-2 border-orange-500/20 border-t-orange-500 animate-spin" />
               </div>
               <div className="absolute inset-0 flex items-center justify-center">
                  <span className="text-xl font-space font-bold">{genStatus.progress}%</span>
               </div>
            </div>
            <h2 className="text-4xl font-space font-black tracking-tighter mb-4">{genStatus.statusText}</h2>
            <p className="text-zinc-500 max-w-sm font-medium">Orchestrating {formatDuration(request.durationSeconds)} of structural coherence for "{request.title}"</p>
          </div>
        ) : state === AppState.PLAYING && activeItem ? (
          <div className="flex-1 relative flex flex-col">
            <div className="absolute inset-0 z-0">
               <img src={activeItem.videoUrl} className="w-full h-full object-cover opacity-40 scale-105 blur-[2px]" />
               <div className="absolute inset-0 bg-gradient-to-t from-black via-black/40 to-transparent"></div>
            </div>

            <div className="relative z-10 flex-1 flex flex-col p-12 justify-end">
               <div className="max-w-4xl space-y-8">
                  <div className="space-y-4">
                    <span className="inline-block px-3 py-1 rounded-full border border-orange-500/30 bg-orange-500/10 text-orange-500 text-[10px] font-black uppercase tracking-[0.2em]">Master Output Active</span>
                    <h2 className="text-7xl font-space font-black tracking-tighter text-white leading-[0.9]">{activeItem.request.title}</h2>
                    <p className="text-xl text-zinc-400 font-medium max-w-2xl">{activeItem.request.description}</p>
                  </div>

                  <div className="flex gap-12 text-zinc-500">
                    <div>
                      <span className="block text-[10px] font-black uppercase tracking-widest text-zinc-700 mb-1">Key / Scale</span>
                      <span className="font-bold text-zinc-300">{activeItem.plan.key} {activeItem.plan.scale}</span>
                    </div>
                    <div>
                      <span className="block text-[10px] font-black uppercase tracking-widest text-zinc-700 mb-1">Tempo</span>
                      <span className="font-bold text-zinc-300">{activeItem.plan.bpm} BPM</span>
                    </div>
                    <div>
                      <span className="block text-[10px] font-black uppercase tracking-widest text-zinc-700 mb-1">Time Sig</span>
                      <span className="font-bold text-zinc-300">{activeItem.plan.timeSignature}</span>
                    </div>
                  </div>

                  <div className="space-y-4 pt-10">
                    <div className="flex justify-between items-end text-[10px] font-black uppercase text-zinc-600 tracking-widest">
                       <span>Real-time Stream: {activeItem.plan.sections[0].label}</span>
                       <span>Total: {formatDuration(activeItem.request.durationSeconds)}</span>
                    </div>
                    <div className="h-1 w-full bg-zinc-900 rounded-full overflow-hidden relative">
                       <div className="absolute top-0 bottom-0 left-0 bg-orange-500 w-1/12 animate-pulse shadow-[0_0_15px_rgba(255,77,0,0.5)]"></div>
                    </div>
                  </div>

                  <div className="flex gap-4 pt-4">
                     <Button className="px-10 py-5 text-lg">Live Stream</Button>
                     <Button variant="secondary" className="px-10 py-5 text-lg" onClick={() => window.open(activeItem.audioUrl)}>Download Master</Button>
                  </div>
               </div>
            </div>

            <audio autoPlay loop src={activeItem.audioUrl} className="hidden" />
          </div>
        ) : (
          <div className="flex-1 flex flex-col p-12 overflow-y-auto">
             <div className="mb-16">
                <h1 className="text-4xl font-space font-black tracking-tighter mb-4">Laboratory <span className="text-orange-500">Dashboard</span></h1>
                <p className="text-zinc-500 text-lg font-medium">Hello {user?.name}. Your synthesis engine is idle.</p>
             </div>

             <div className="space-y-8">
                <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600">History Archive</h3>
                {history.length === 0 ? (
                  <div className="p-20 border-2 border-dashed border-zinc-900 rounded-[2.5rem] flex flex-col items-center justify-center text-center">
                    <div className="w-16 h-16 rounded-3xl bg-zinc-900/50 flex items-center justify-center mb-6 text-2xl">🧪</div>
                    <p className="text-zinc-500 font-medium">No archived soundscapes found. Initialize a project to begin.</p>
                  </div>
                ) : (
                  <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                    {history.map(item => (
                      <div 
                        key={item.id} onClick={() => { setActiveItem(item); setState(AppState.PLAYING); }}
                        className="group flex gap-6 p-6 border border-zinc-900 bg-zinc-950/50 rounded-[2rem] hover:border-orange-500/40 hover:bg-zinc-900/20 cursor-pointer transition-all duration-500"
                      >
                        <div className="w-32 h-32 rounded-2xl overflow-hidden flex-shrink-0 bg-zinc-900">
                          <img src={item.videoUrl} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />
                        </div>
                        <div className="flex-1 min-w-0 flex flex-col justify-center">
                          <h4 className="text-xl font-space font-bold text-zinc-100 truncate group-hover:text-orange-500 transition-colors">{item.request.title}</h4>
                          <p className="text-sm text-zinc-500 line-clamp-2 mt-2 font-medium">{item.request.description}</p>
                          <div className="flex items-center gap-3 mt-4">
                            <span className="text-[9px] font-black uppercase px-2 py-1 bg-zinc-900 text-zinc-500 rounded-lg tracking-widest">{formatDuration(item.request.durationSeconds)}</span>
                            <span className="text-[9px] font-black uppercase px-2 py-1 bg-zinc-900 text-zinc-500 rounded-lg tracking-widest">{item.request.genre}</span>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default App;

