import { GoogleGenAI, Type } from "@google/genai";
import { SongRequest, ImmutableSongPlan, VideoType } from "../types";

const API_KEY = process.env.API_KEY;

const ai = new GoogleGenAI({ apiKey: API_KEY || '' });

export function checkApiKey() {
  if (!API_KEY) {
    throw new Error("Configuration error: GOOGLE_API_KEY is missing or invalid.");
  }
}

export async function getAISuggestion(field: keyof SongRequest, currentRequest: Partial<SongRequest>): Promise<{ suggestedValue: string, justification: string }> {
  checkApiKey();
  const context = JSON.stringify(currentRequest);

  const prompt = `You are a high-end music and video production consultant. 
  Provide a concrete suggestion for the field "${field.toString()}" in an AI generation platform.

  CONTEXT: ${context}

  STRICT RULES:
  - Return the suggested value and a brief justification.
  - suggestedValue: The exact text or number that should go into the input field.
  - justification: Explain why this fits based on other filled fields. Describe the impact on sound or visual narrative. Max 2 sentences.
  - For VideoType: Official, Lyrical, or Abstract.
  - No theory or meta-language.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          suggestedValue: { type: Type.STRING },
          justification: { type: Type.STRING }
        },
        required: ["suggestedValue", "justification"]
      }
    }
  });

  return JSON.parse(response.text.trim());
}

export async function createImmutableSongPlan(request: SongRequest): Promise<ImmutableSongPlan> {
  checkApiKey();
  const systemPrompt = `You are the Core Planning Unit for a Suno-like music generation system.
  Create an immutable, mathematically consistent plan for both AUDIO and VIDEO.

  AUDIO RULES: Constant BPM (${request.bpm}), Constant Key (${request.keyScale}).
  VIDEO RULES: Strictly follow Video Type: ${request.videoType}.

  DURATION: ${request.durationSeconds}s.

  OUTPUT FORMAT: JSON only.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Plan the song and video architecture for: ${JSON.stringify(request)}`,
    config: {
      systemInstruction: systemPrompt,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          bpm: { type: Type.NUMBER },
          key: { type: Type.STRING },
          scale: { type: Type.STRING },
          timeSignature: { type: Type.STRING },
          instrumentPalette: { type: Type.ARRAY, items: { type: Type.STRING } },
          vocalPresenceMap: { type: Type.STRING },
          sections: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                startTime: { type: Type.NUMBER },
                endTime: { type: Type.NUMBER },
                label: { type: Type.STRING },
                energy: { type: Type.NUMBER },
                description: { type: Type.STRING }
              },
              required: ["startTime", "endTime", "label", "energy", "description"]
            }
          },
          macroEnergyCurve: { type: Type.ARRAY, items: { type: Type.NUMBER } },
          textureEvolutionStrategy: { type: Type.STRING },
          videoPlan: {
            type: Type.OBJECT,
            properties: {
              visualDescription: { type: Type.STRING },
              pacingStrategy: { type: Type.STRING },
              typeSpecificInstructions: { type: Type.STRING }
            },
            required: ["visualDescription", "pacingStrategy", "typeSpecificInstructions"]
          }
        },
        required: ["bpm", "key", "scale", "timeSignature", "instrumentPalette", "sections", "macroEnergyCurve", "textureEvolutionStrategy", "videoPlan"]
      }
    }
  });

  return JSON.parse(response.text.trim());
}

export async function generateVisualReference(prompt: string, videoType: VideoType): Promise<string> {
  checkApiKey();
  const typeContext = videoType === VideoType.LYRICAL ? "Clean legible background for typography" : "Rich cinematic atmosphere";
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: `${typeContext}, non-fatiguing high-quality visual reference for: ${prompt}`,
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return '';
}

import React, { useState, useEffect, useRef } from 'react';
import { AppState, UserLocalProfile, SongRequest, ImmutableSongPlan, SongHistoryItem, GenerationStatus, VideoType } from './types';
import { Button } from './components/Button';
import { Input } from './components/Input';
import { getAISuggestion, createImmutableSongPlan, generateVisualReference, checkApiKey } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(AppState.ONBOARDING);
  const [user, setUser] = useState<UserLocalProfile | null>(null);
  const [error, setError] = useState<string | null>(null);

  const [request, setRequest] = useState<SongRequest>({
    title: '', description: '', genre: '', subGenre: '', mood: '',
    energyLevel: 'Medium', tempoPreference: 'Moderate', bpm: 120, keyScale: 'C Minor',
    language: 'English', lyricsMode: 'Instrumental', lyricsInput: '', 
    vocalPresence: 'None', vocalGender: 'Neutral', vocalStyle: 'None',
    instrumentation: 'Digital Synths', durationSeconds: 180,
    structure: 'Standard', sectionLength: 'Medium', energyCurve: 'Linear',
    referenceArtists: '', useCase: 'Focus', videoType: VideoType.ABSTRACT,
    videoStyle: '', visualIntensity: 'Medium', visualEvolutionStyle: 'Slow'
  });

  const [suggestions, setSuggestions] = useState<Record<string, string>>({});
  const [loadingSuggestion, setLoadingSuggestion] = useState<string | null>(null);
  const [history, setHistory] = useState<SongHistoryItem[]>([]);
  const [activeItem, setActiveItem] = useState<SongHistoryItem | null>(null);
  const [genStatus, setGenStatus] = useState<GenerationStatus>({ progress: 0, currentSegment: 0, totalSegments: 0, statusText: '' });

  useEffect(() => {
    try {
      checkApiKey();
    } catch (e: any) {
      setError(e.message);
    }

    const savedUser = localStorage.getItem('caffeine_profile');
    const savedHistory = localStorage.getItem('caffeine_archive');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
      setState(AppState.DASHBOARD);
    }
    if (savedHistory) setHistory(JSON.parse(savedHistory));
  }, []);

  const saveProfile = (e: React.FormEvent) => {
    e.preventDefault();
    const formData = new FormData(e.target as HTMLFormElement);
    const profile: UserLocalProfile = {
      user_id: crypto.randomUUID(),
      name: formData.get('name') as string,
      phone_number: formData.get('mobile') as string,
      created_at: Date.now(),
      last_active_at: Date.now()
    };
    localStorage.setItem('caffeine_profile', JSON.stringify(profile));
    setUser(profile);
    setState(AppState.DASHBOARD);
  };

  const resetApp = () => {
    if (confirm("Reset application? This will clear your identity and all generation history.")) {
      localStorage.clear();
      window.location.reload();
    }
  };

  const fetchSuggestion = async (field: keyof SongRequest) => {
    setLoadingSuggestion(field as string);
    try {
      const { suggestedValue, justification } = await getAISuggestion(field, request);

      // Store justification as a note below the field
      setSuggestions(prev => ({ ...prev, [field]: justification }));

      // Fill the field content with only the suggestedValue
      if (field === 'durationSeconds' || field === 'bpm') {
        const numericValue = parseInt(suggestedValue.replace(/\D/g, ''));
        if (!isNaN(numericValue)) {
          setRequest(prev => ({ ...prev, [field]: numericValue }));
        }
      } else {
        setRequest(prev => ({ ...prev, [field]: suggestedValue }));
      }
    } catch (e: any) {
      setError(e.message);
    } finally {
      setLoadingSuggestion(null);
    }
  };

  const startPipeline = async () => {
    if (!request.title || !request.description) {
      alert("Title and Primary Description are required.");
      return;
    }

    setState(AppState.PLANNING);
    setGenStatus({ progress: 0, currentSegment: 0, totalSegments: 0, statusText: 'Synthesizing Mathematical Plan...' });

    try {
      const plan = await createImmutableSongPlan(request);
      setGenStatus({ progress: 15, currentSegment: 0, totalSegments: 0, statusText: 'Locking Song Blueprint...' });

      const segDuration = 600; // 10 min
      const totalSegs = Math.ceil(request.durationSeconds / segDuration);

      setState(AppState.GENERATING);
      setGenStatus(prev => ({ ...prev, totalSegments: totalSegs, statusText: 'Synthesizing Visual Atmosphere...' }));

      const visRef = await generateVisualReference(`${request.videoStyle} ${plan.textureEvolutionStrategy}`, request.videoType);

      for (let i = 0; i < totalSegs; i++) {
        setGenStatus(prev => ({
          ...prev,
          currentSegment: i + 1,
          progress: Math.floor(25 + (i / totalSegs) * 70),
          statusText: `Mastering Segment ${i + 1}/${totalSegs}...`
        }));
        await new Promise(r => setTimeout(r, 1200)); 
      }

      const newItem: SongHistoryItem = {
        id: crypto.randomUUID(),
        request: { ...request },
        plan,
        audioUrl: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-2.mp3',
        videoUrl: visRef,
        createdAt: Date.now()
      };

      const updatedHistory = [newItem, ...history];
      setHistory(updatedHistory);
      localStorage.setItem('caffeine_archive', JSON.stringify(updatedHistory));
      setActiveItem(newItem);
      setState(AppState.PLAYING);
    } catch (e: any) {
      setError(e.message);
      setState(AppState.DASHBOARD);
    }
  };

  const formatDuration = (s: number) => {
    const h = Math.floor(s / 3600);
    const m = Math.floor((s % 3600) / 60);
    const sc = s % 60;
    return `${h > 0 ? h + 'h ' : ''}${m}m ${sc}s`;
  };

  if (error) {
    return (
      <div className="min-h-screen bg-black flex items-center justify-center p-8">
        <div className="max-w-md w-full bg-red-950/20 border border-red-900/50 p-8 rounded-2xl text-center">
          <div className="text-red-500 mb-6 flex justify-center">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
            </svg>
          </div>
          <h2 className="text-2xl font-bold text-red-500 mb-2">System Error</h2>
          <p className="text-zinc-400 mb-8">{error}</p>
          <Button fullWidth onClick={() => window.location.reload()}>Retry Boot</Button>
        </div>
      </div>
    );
  }

  if (state === AppState.ONBOARDING) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-black p-4">
        <div className="w-full max-w-md bg-zinc-900/40 backdrop-blur-3xl p-10 border border-zinc-800 rounded-3xl shadow-2xl">
          <div className="text-center mb-10">
            <h1 className="text-4xl font-space font-black tracking-tight mb-2">Caffeine<span className="text-orange-500">.ai</span></h1>
            <p className="text-zinc-500 font-medium">Next-Generation Music Synthesis</p>
          </div>
          <form onSubmit={saveProfile} className="space-y-6">
            <Input name="name" label="Full Name" placeholder="e.g. Satoshi Nakamoto" required />
            <Input name="mobile" label="Mobile Number" placeholder="+1 (555) 000-0000" type="tel" required />
            <Button fullWidth type="submit">Continue</Button>
          </form>
        </div>
      </div>
    );
  }

  const getPlaceholder = (f: keyof SongRequest): string => {
    const samples: Record<string, string> = {
      title: "e.g. Midnight Horizon",
      description: "e.g. A slow-burning atmospheric techno track...",
      genre: "e.g. Deep House",
      subGenre: "e.g. Melodic Progressive",
      mood: "e.g. Melancholic yet hopeful",
      energyLevel: "e.g. Very High",
      tempoPreference: "e.g. Fast Driving",
      bpm: "e.g. 128",
      keyScale: "e.g. F Minor",
      language: "e.g. English",
      lyricsInput: "e.g. Lost in the lights of the city tonight...",
      vocalGender: "e.g. Ethereal Female",
      vocalStyle: "e.g. Soft breathy whispers",
      instrumentation: "e.g. Analog bass, shimmer pads",
      structure: "e.g. Extended intro, 2 drops",
      sectionLength: "e.g. Long cinematic sections",
      energyCurve: "e.g. Gradual build to peak",
      referenceArtists: "e.g. Lane 8 style pads",
      useCase: "e.g. Coding / Deep Work",
      videoStyle: "e.g. Abstract neon grid",
      visualIntensity: "e.g. High energy strobe",
      visualEvolutionStyle: "e.g. Scene shifts every 32 bars"
    };
    return samples[f as string] || "e.g. Sample value...";
  };

  const FormSection = ({ title, fields }: { title: string, fields: (keyof SongRequest)[] }) => (
    <div className="space-y-6 pt-10 first:pt-0 border-t border-zinc-900 first:border-0">
      <h3 className="text-[11px] font-black uppercase tracking-[0.2em] text-zinc-500">{title}</h3>
      <div className="space-y-6">
        {fields.map(f => (
          <div key={f} className="space-y-3">
            <div className="flex items-end gap-2">
              <div className="flex-1">
                {f === 'videoType' ? (
                  <div className="space-y-1.5">
                    <label className="block text-sm font-medium text-zinc-400">Video Type</label>
                    <select 
                      className="w-full bg-zinc-900 border border-zinc-800 rounded-lg px-4 py-3 text-zinc-100 focus:outline-none focus:border-orange-500"
                      value={request.videoType}
                      onChange={e => setRequest({...request, videoType: e.target.value as VideoType})}
                    >
                      {Object.values(VideoType).map(v => <option key={v} value={v}>{v}</option>)}
                    </select>
                  </div>
                ) : f === 'durationSeconds' ? (
                  <div className="space-y-2">
                    <label className="text-xs font-bold text-zinc-500">Duration: {formatDuration(request.durationSeconds)}</label>
                    <input 
                      type="range" min="30" max="72000" step="30"
                      className="w-full h-1 bg-zinc-800 rounded-full appearance-none accent-orange-500 cursor-pointer"
                      value={request.durationSeconds}
                      onChange={e => setRequest({...request, durationSeconds: parseInt(e.target.value)})}
                    />
                  </div>
                ) : (
                  <Input 
                    label={f.replace(/([A-Z])/g, ' $1').replace(/^./, str => str.toUpperCase())}
                    isTextArea={['description', 'lyricsInput', 'instrumentation'].includes(f)}
                    value={(request as any)[f]}
                    onChange={e => setRequest({...request, [f]: e.target.value})}
                    placeholder={getPlaceholder(f)}
                  />
                )}
              </div>
              <button 
                onClick={() => fetchSuggestion(f)}
                disabled={loadingSuggestion === f}
                className="mb-1 p-2.5 rounded-lg border border-zinc-800 bg-zinc-900 text-zinc-500 hover:text-orange-500 hover:border-orange-500 transition-all disabled:opacity-30"
              >
                {loadingSuggestion === f ? <div className="w-4 h-4 border-2 border-orange-500/30 border-t-orange-500 rounded-full animate-spin"/> : '✨'}
              </button>
            </div>
            {suggestions[f] && (
              <div className="px-1 text-[11px] text-orange-400/80 font-medium leading-relaxed italic">
                Note: {suggestions[f]}
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-black text-zinc-100 flex flex-col md:flex-row overflow-hidden">
      {/* Sidebar: Config */}
      <div className="w-full md:w-[450px] h-screen border-r border-zinc-900 bg-zinc-950 flex flex-col z-20">
        <div className="p-6 border-b border-zinc-900 flex justify-between items-center bg-zinc-950/80 backdrop-blur-md sticky top-0 z-10">
           <h2 className="text-xl font-space font-black tracking-tight">Project <span className="text-orange-500">Master</span></h2>
           <button onClick={resetApp} className="text-[10px] font-black uppercase text-zinc-600 hover:text-red-500 tracking-widest">Reset App</button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-12 scrollbar-hide">
          <FormSection title="Core Concept" fields={['title', 'description', 'useCase', 'referenceArtists']} />
          <FormSection title="Music Architecture" fields={['genre', 'subGenre', 'mood', 'energyLevel', 'tempoPreference', 'bpm', 'keyScale']} />
          <FormSection title="Lyrics & Vocals" fields={['lyricsMode', 'lyricsInput', 'vocalPresence', 'vocalGender', 'vocalStyle', 'language']} />
          <FormSection title="Structure & Pacing" fields={['durationSeconds', 'structure', 'sectionLength', 'energyCurve', 'instrumentation']} />
          <FormSection title="Video Synthesis" fields={['videoType', 'videoStyle', 'visualIntensity', 'visualEvolutionStyle']} />
        </div>

        <div className="p-6 border-t border-zinc-900 bg-zinc-950">
           <Button fullWidth onClick={startPipeline} disabled={!request.title}>
             Begin Generation Pipeline
           </Button>
        </div>
      </div>

      {/* Main Panel */}
      <div className="flex-1 relative bg-[#020202] h-screen overflow-hidden">
        {state === AppState.PLANNING || state === AppState.GENERATING ? (
          <div className="flex-1 h-full flex flex-col items-center justify-center p-12 text-center">
            <div className="relative mb-12">
               <div className="w-40 h-40 rounded-full border border-orange-500/10 flex items-center justify-center">
                  <div className="w-28 h-28 rounded-full border-2 border-orange-500/20 border-t-orange-500 animate-spin" />
               </div>
               <div className="absolute inset-0 flex items-center justify-center">
                  <span className="text-2xl font-space font-black">{genStatus.progress}%</span>
               </div>
            </div>
            <h2 className="text-4xl font-space font-black tracking-tighter mb-4 uppercase">{genStatus.statusText}</h2>
            <p className="text-zinc-500 max-w-md font-medium">Orchestrating {formatDuration(request.durationSeconds)} of structural coherence for "{request.title || 'Untitled Project'}"</p>
          </div>
        ) : state === AppState.PLAYING && activeItem ? (
          <div className="h-full relative flex flex-col">
            <div className="absolute inset-0 z-0">
               <img src={activeItem.videoUrl} className="w-full h-full object-cover opacity-30 blur-[1px] scale-105" alt="Visual reference" />
               <div className="absolute inset-0 bg-gradient-to-t from-black via-black/40 to-transparent"></div>
            </div>

            <div className="relative z-10 flex-1 flex flex-col p-16 justify-end">
               <div className="max-w-5xl space-y-10">
                  <div className="space-y-6">
                    <div className="flex gap-3">
                      <span className="px-3 py-1 rounded-full border border-orange-500/30 bg-orange-500/10 text-orange-500 text-[10px] font-black uppercase tracking-widest">Master File Active</span>
                      <span className="px-3 py-1 rounded-full border border-zinc-800 bg-zinc-900/50 text-zinc-400 text-[10px] font-black uppercase tracking-widest">{activeItem.request.videoType}</span>
                    </div>
                    <h2 className="text-8xl font-space font-black tracking-tighter text-white leading-[0.85]">{activeItem.request.title}</h2>
                    <p className="text-2xl text-zinc-400 font-medium max-w-3xl leading-relaxed">{activeItem.request.description}</p>
                  </div>

                  <div className="grid grid-cols-4 gap-12 text-zinc-500 py-4 border-y border-zinc-900">
                    <div>
                      <span className="block text-[10px] font-black uppercase tracking-widest text-zinc-700 mb-2">Key / Scale</span>
                      <span className="text-xl font-bold text-zinc-200">{activeItem.plan.key} {activeItem.plan.scale}</span>
                    </div>
                    <div>
                      <span className="block text-[10px] font-black uppercase tracking-widest text-zinc-700 mb-2">Tempo</span>
                      <span className="text-xl font-bold text-zinc-200">{activeItem.plan.bpm} BPM</span>
                    </div>
                    <div>
                      <span className="block text-[10px] font-black uppercase tracking-widest text-zinc-700 mb-2">Duration</span>
                      <span className="text-xl font-bold text-zinc-200">{formatDuration(activeItem.request.durationSeconds)}</span>
                    </div>
                    <div>
                      <span className="block text-[10px] font-black uppercase tracking-widest text-zinc-700 mb-2">Instruments</span>
                      <span className="text-sm font-bold text-zinc-400 truncate block">{activeItem.plan.instrumentPalette.slice(0, 2).join(', ')}...</span>
                    </div>
                  </div>

                  <div className="space-y-4 pt-10">
                    <div className="flex justify-between items-end text-[10px] font-black uppercase text-zinc-600 tracking-widest">
                       <span>Phase: {activeItem.plan.sections[0].label} — {activeItem.plan.sections[0].description}</span>
                       <span>{activeItem.request.bpm} BPM Sync</span>
                    </div>
                    <div className="h-1.5 w-full bg-zinc-900 rounded-full overflow-hidden relative shadow-inner">
                       <div className="absolute top-0 bottom-0 left-0 bg-orange-500 w-1/12 animate-pulse shadow-[0_0_20px_rgba(255,77,0,0.6)]"></div>
                    </div>
                  </div>

                  <div className="flex gap-6 pt-6">
                     <Button className="px-12 py-5 text-lg h-16">Live Output</Button>
                     <Button variant="secondary" className="px-12 py-5 text-lg h-16" onClick={() => window.open(activeItem.audioUrl)}>Download Master</Button>
                  </div>
               </div>
            </div>
            <audio autoPlay loop src={activeItem.audioUrl} className="hidden" />
          </div>
        ) : (
          <div className="h-full flex flex-col p-16 overflow-y-auto">
             <div className="mb-20 flex justify-between items-end">
                <div>
                   <h1 className="text-6xl font-space font-black tracking-tighter mb-4 uppercase">Synthesis <span className="text-orange-500">Suite</span></h1>
                   <p className="text-zinc-500 text-xl font-medium tracking-tight">Active Terminal: {user?.name}. System ready for deployment.</p>
                </div>
                <div className="text-right">
                   <p className="text-[10px] font-black uppercase text-zinc-700 tracking-[0.3em]">Caffeine.ai Kernel v4.0.1</p>
                </div>
             </div>

             <div className="space-y-12">
                <h3 className="text-[11px] font-black uppercase tracking-[0.2em] text-zinc-600 border-b border-zinc-900 pb-4">Production Archive</h3>
                {history.length === 0 ? (
                  <div className="py-32 border-2 border-dashed border-zinc-900 rounded-[3rem] flex flex-col items-center justify-center text-center">
                    <div className="w-20 h-20 rounded-full bg-zinc-900/40 flex items-center justify-center mb-8 text-3xl">🎚️</div>
                    <p className="text-zinc-500 text-lg font-medium max-w-sm">No production files found in local storage. Start a new project to initialize synthesis.</p>
                  </div>
                ) : (
                  <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                    {history.map(item => (
                      <div 
                        key={item.id} onClick={() => { setActiveItem(item); setState(AppState.PLAYING); }}
                        className="group flex gap-8 p-8 border border-zinc-900 bg-zinc-950/40 rounded-[2.5rem] hover:border-orange-500/30 hover:bg-zinc-900/20 cursor-pointer transition-all duration-700"
                      >
                        <div className="w-40 h-40 rounded-3xl overflow-hidden flex-shrink-0 bg-zinc-900 shadow-2xl">
                          <img src={item.videoUrl} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000" />
                        </div>
                        <div className="flex-1 min-w-0 flex flex-col justify-center">
                          <span className="text-[10px] font-black uppercase text-orange-500 mb-2 tracking-widest">{item.request.genre}</span>
                          <h4 className="text-2xl font-space font-black text-zinc-100 truncate group-hover:text-orange-500 transition-colors leading-tight">{item.request.title}</h4>
                          <p className="text-base text-zinc-500 line-clamp-2 mt-3 font-medium leading-relaxed">{item.request.description}</p>
                          <div className="flex items-center gap-4 mt-6">
                            <span className="text-[10px] font-black uppercase px-3 py-1.5 bg-zinc-900 text-zinc-500 rounded-xl tracking-widest">{formatDuration(item.request.durationSeconds)}</span>
                            <span className="text-[10px] font-black uppercase px-3 py-1.5 bg-zinc-900 text-zinc-500 rounded-xl tracking-widest">{item.plan.bpm} BPM</span>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { AppState, UserLocalProfile, SongRequest, ImmutableSongPlan, SongHistoryItem, GenerationStatus, VideoType } from './types';
import { Button } from './components/Button';
import { Input } from './components/Input';
import { getAISuggestion, createImmutableSongPlan, generateVisualReference, checkApiKey } from './services/geminiService';

const INDIAN_MOBILE_REGEX = /^[6789]\d{9}$/;

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(AppState.ONBOARDING);
  const [user, setUser] = useState<UserLocalProfile | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [onboardingError, setOnboardingError] = useState<string | null>(null);

  const [request, setRequest] = useState<SongRequest>({
    title: '', description: '', genre: '', subGenre: '', mood: '',
    energyLevel: 'Medium', tempoPreference: 'Moderate', bpm: 120, keyScale: 'C Minor',
    language: 'English', lyricsMode: 'Instrumental', lyricsInput: '', 
    vocalPresence: 'None', vocalGender: 'Neutral', vocalStyle: 'None',
    instrumentation: 'Digital Synths', durationSeconds: 180,
    structure: 'Standard', sectionLength: 'Medium', energyCurve: 'Linear',
    referenceArtists: '', useCase: 'Focus', videoType: VideoType.ABSTRACT,
    videoStyle: '', visualIntensity: 'Medium', visualEvolutionStyle: 'Slow'
  });

  const [suggestions, setSuggestions] = useState<Record<string, string>>({});
  const [loadingSuggestion, setLoadingSuggestion] = useState<string | null>(null);
  const [history, setHistory] = useState<SongHistoryItem[]>([]);
  const [activeItem, setActiveItem] = useState<SongHistoryItem | null>(null);
  const [genStatus, setGenStatus] = useState<GenerationStatus>({ progress: 0, currentSegment: 0, totalSegments: 0, statusText: '' });

  useEffect(() => {
    try {
      checkApiKey();
    } catch (e: any) {
      setError(e.message);
    }

    const savedUser = localStorage.getItem('caffeine_profile');
    const savedHistory = localStorage.getItem('caffeine_archive');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
      setState(AppState.DASHBOARD);
    }
    if (savedHistory) setHistory(JSON.parse(savedHistory));
  }, []);

  const saveProfile = (e: React.FormEvent) => {
    e.preventDefault();
    setOnboardingError(null);
    const formData = new FormData(e.target as HTMLFormElement);
    const name = formData.get('name') as string;
    const mobile = formData.get('mobile') as string;

    // Strict Indian Mobile Validation
    const cleanMobile = mobile.replace(/\D/g, '');
    if (!INDIAN_MOBILE_REGEX.test(cleanMobile)) {
      setOnboardingError("Invalid Indian Mobile Number. Must be 10 digits starting with 6-9.");
      return;
    }

    const profile: UserLocalProfile = {
      user_id: crypto.randomUUID(),
      name,
      phone_number: `+91${cleanMobile}`,
      created_at: Date.now(),
      last_active_at: Date.now()
    };

    localStorage.setItem('caffeine_profile', JSON.stringify(profile));
    setUser(profile);
    setState(AppState.DASHBOARD);
  };

  const resetApp = () => {
    if (confirm("Reset application? This will clear your identity and all generation history.")) {
      localStorage.clear();
      window.location.reload();
    }
  };

  const fetchSuggestion = async (field: keyof SongRequest) => {
    setLoadingSuggestion(field as string);
    try {
      const { suggestedValue, justification } = await getAISuggestion(field, request);

      setSuggestions(prev => ({ ...prev, [field]: justification }));

      if (field === 'durationSeconds' || field === 'bpm') {
        const numericValue = parseInt(suggestedValue.replace(/\D/g, ''));
        if (!isNaN(numericValue)) {
          setRequest(prev => ({ ...prev, [field]: numericValue }));
        }
      } else {
        setRequest(prev => ({ ...prev, [field]: suggestedValue }));
      }
    } catch (e: any) {
      setError(e.message);
    } finally {
      setLoadingSuggestion(null);
    }
  };

  const startPipeline = async () => {
    if (!request.title || !request.description) {
      alert("Title and Primary Description are required.");
      return;
    }

    setState(AppState.PLANNING);
    setGenStatus({ progress: 0, currentSegment: 0, totalSegments: 0, statusText: 'Synthesizing Mathematical Plan...' });

    try {
      const plan = await createImmutableSongPlan(request);
      setGenStatus({ progress: 15, currentSegment: 0, totalSegments: 0, statusText: 'Locking Song Blueprint...' });

      const segDuration = 600; 
      const totalSegs = Math.ceil(request.durationSeconds / segDuration);

      setState(AppState.GENERATING);
      setGenStatus(prev => ({ ...prev, totalSegments: totalSegs, statusText: 'Synthesizing Visual Atmosphere...' }));

      const visRef = await generateVisualReference(`${request.videoStyle} ${plan.textureEvolutionStrategy}`, request.videoType);

      for (let i = 0; i < totalSegs; i++) {
        setGenStatus(prev => ({
          ...prev,
          currentSegment: i + 1,
          progress: Math.floor(25 + (i / totalSegs) * 70),
          statusText: `Mastering Segment ${i + 1}/${totalSegs}...`
        }));
        await new Promise(r => setTimeout(r, 1200)); 
      }

      const newItem: SongHistoryItem = {
        id: crypto.randomUUID(),
        request: { ...request },
        plan,
        audioUrl: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-2.mp3',
        videoUrl: visRef,
        createdAt: Date.now()
      };

      const updatedHistory = [newItem, ...history];
      setHistory(updatedHistory);
      localStorage.setItem('caffeine_archive', JSON.stringify(updatedHistory));
      setActiveItem(newItem);
      setState(AppState.PLAYING);
    } catch (e: any) {
      setError(e.message);
      setState(AppState.DASHBOARD);
    }
  };

  const formatDuration = (s: number) => {
    const h = Math.floor(s / 3600);
    const m = Math.floor((s % 3600) / 60);
    const sc = s % 60;
    return `${h > 0 ? h + 'h ' : ''}${m}m ${sc}s`;
  };

  if (error) {
    return (
      <div className="min-h-screen bg-black flex items-center justify-center p-8">
        <div className="max-w-md w-full bg-red-950/20 border border-red-900/50 p-8 rounded-2xl text-center">
          <div className="text-red-500 mb-6 flex justify-center">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
            </svg>
          </div>
          <h2 className="text-2xl font-bold text-red-500 mb-2">System Error</h2>
          <p className="text-zinc-400 mb-8">{error}</p>
          <Button fullWidth onClick={() => window.location.reload()}>Retry Boot</Button>
        </div>
      </div>
    );
  }

  if (state === AppState.ONBOARDING) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-black p-4 relative overflow-hidden">
        {/* Animated background elements */}
        <div className="absolute top-0 left-0 w-full h-full pointer-events-none opacity-20">
          <div className="absolute top-[-10%] right-[-10%] w-[500px] h-[500px] bg-orange-600 rounded-full blur-[120px] animate-pulse"></div>
          <div className="absolute bottom-[-10%] left-[-10%] w-[500px] h-[500px] bg-zinc-800 rounded-full blur-[120px]"></div>
        </div>

        <div className="w-full max-w-md bg-zinc-900/40 backdrop-blur-3xl p-10 border border-zinc-800 rounded-3xl shadow-2xl relative z-10">
          <div className="text-center mb-10">
            <h1 className="text-4xl font-space font-black tracking-tight mb-2">Caffeine<span className="text-orange-500">.ai</span></h1>
            <p className="text-zinc-500 font-medium">Regional Terminal: India (IN)</p>
          </div>
          <form onSubmit={saveProfile} className="space-y-6">
            <Input name="name" label="Full Name" placeholder="e.g. Satoshi Nakamoto" required />
            <div className="space-y-1.5">
              <label className="block text-sm font-medium text-zinc-400">Mobile Number (India 🇮🇳)</label>
              <div className="flex gap-2">
                <div className="bg-zinc-800 border border-zinc-700 rounded-lg px-3 py-3 text-zinc-400 font-semibold flex items-center">
                  +91
                </div>
                <Input 
                  name="mobile" 
                  placeholder="9876543210" 
                  type="tel" 
                  maxLength={10}
                  required 
                  className="flex-1"
                />
              </div>
              <p className="text-[10px] text-zinc-600 uppercase tracking-widest font-bold">Indian mobile numbers only</p>
            </div>
            {onboardingError && (
              <p className="text-xs text-red-500 font-medium bg-red-500/10 p-3 rounded-lg border border-red-500/20">
                {onboardingError}
              </p>
            )}
            <Button fullWidth type="submit" className="h-14 text-lg">Initialize Terminal</Button>
          </form>
          <p className="mt-8 text-center text-zinc-600 text-xs uppercase tracking-[0.2em] font-black">
            Secure Authentication Pipeline Active
          </p>
        </div>
      </div>
    );
  }

  const getPlaceholder = (f: keyof SongRequest): string => {
    const samples: Record<string, string> = {
      title: "e.g. Midnight Horizon",
      description: "e.g. A slow-burning atmospheric techno track...",
      genre: "e.g. Deep House",
      subGenre: "e.g. Melodic Progressive",
      mood: "e.g. Melancholic yet hopeful",
      energyLevel: "e.g. Very High",
      tempoPreference: "e.g. Fast Driving",
      bpm: "e.g. 128",
      keyScale: "e.g. F Minor",
      language: "e.g. English",
      lyricsInput: "e.g. Lost in the lights of the city tonight...",
      vocalGender: "e.g. Ethereal Female",
      vocalStyle: "e.g. Soft breathy whispers",
      instrumentation: "e.g. Analog bass, shimmer pads",
      structure: "e.g. Extended intro, 2 drops",
      sectionLength: "e.g. Long cinematic sections",
      energyCurve: "e.g. Gradual build to peak",
      referenceArtists: "e.g. Lane 8 style pads",
      useCase: "e.g. Coding / Deep Work",
      videoStyle: "e.g. Abstract neon grid",
      visualIntensity: "e.g. High energy strobe",
      visualEvolutionStyle: "e.g. Scene shifts every 32 bars"
    };
    return samples[f as string] || "e.g. Sample value...";
  };

  const FormSection = ({ title, fields }: { title: string, fields: (keyof SongRequest)[] }) => (
    <div className="space-y-6 pt-10 first:pt-0 border-t border-zinc-900 first:border-0">
      <h3 className="text-[11px] font-black uppercase tracking-[0.2em] text-zinc-500">{title}</h3>
      <div className="space-y-6">
        {fields.map(f => (
          <div key={f} className="space-y-3">
            <div className="flex items-end gap-2">
              <div className="flex-1">
                {f === 'videoType' ? (
                  <div className="space-y-1.5">
                    <label className="block text-sm font-medium text-zinc-400">Video Type</label>
                    <select 
                      className="w-full bg-zinc-900 border border-zinc-800 rounded-lg px-4 py-3 text-zinc-100 focus:outline-none focus:border-orange-500"
                      value={request.videoType}
                      onChange={e => setRequest({...request, videoType: e.target.value as VideoType})}
                    >
                      {Object.values(VideoType).map(v => <option key={v} value={v}>{v}</option>)}
                    </select>
                  </div>
                ) : f === 'durationSeconds' ? (
                  <div className="space-y-2">
                    <label className="text-xs font-bold text-zinc-500">Duration: {formatDuration(request.durationSeconds)}</label>
                    <input 
                      type="range" min="30" max="72000" step="30"
                      className="w-full h-1 bg-zinc-800 rounded-full appearance-none accent-orange-500 cursor-pointer"
                      value={request.durationSeconds}
                      onChange={e => setRequest({...request, durationSeconds: parseInt(e.target.value)})}
                    />
                  </div>
                ) : (
                  <Input 
                    label={f.replace(/([A-Z])/g, ' $1').replace(/^./, str => str.toUpperCase())}
                    isTextArea={['description', 'lyricsInput', 'instrumentation'].includes(f)}
                    value={(request as any)[f]}
                    onChange={e => setRequest({...request, [f]: e.target.value})}
                    placeholder={getPlaceholder(f)}
                  />
                )}
              </div>
              <button 
                onClick={() => fetchSuggestion(f)}
                disabled={loadingSuggestion === f}
                className="mb-1 p-2.5 rounded-lg border border-zinc-800 bg-zinc-900 text-zinc-500 hover:text-orange-500 hover:border-orange-500 transition-all disabled:opacity-30"
              >
                {loadingSuggestion === f ? <div className="w-4 h-4 border-2 border-orange-500/30 border-t-orange-500 rounded-full animate-spin"/> : '✨'}
              </button>
            </div>
            {suggestions[f] && (
              <div className="px-1 text-[11px] text-orange-400/80 font-medium leading-relaxed italic">
                Note: {suggestions[f]}
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-black text-zinc-100 flex flex-col md:flex-row overflow-hidden">
      {/* Sidebar: Config */}
      <div className="w-full md:w-[450px] h-screen border-r border-zinc-900 bg-zinc-950 flex flex-col z-20">
        <div className="p-6 border-b border-zinc-900 flex justify-between items-center bg-zinc-950/80 backdrop-blur-md sticky top-0 z-10">
           <h2 className="text-xl font-space font-black tracking-tight">Project <span className="text-orange-500">Master</span></h2>
           <button onClick={resetApp} className="text-[10px] font-black uppercase text-zinc-600 hover:text-red-500 tracking-widest">Reset App</button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-12 scrollbar-hide">
          <FormSection title="Core Concept" fields={['title', 'description', 'useCase', 'referenceArtists']} />
          <FormSection title="Music Architecture" fields={['genre', 'subGenre', 'mood', 'energyLevel', 'tempoPreference', 'bpm', 'keyScale']} />
          <FormSection title="Lyrics & Vocals" fields={['lyricsMode', 'lyricsInput', 'vocalPresence', 'vocalGender', 'vocalStyle', 'language']} />
          <FormSection title="Structure & Pacing" fields={['durationSeconds', 'structure', 'sectionLength', 'energyCurve', 'instrumentation']} />
          <FormSection title="Video Synthesis" fields={['videoType', 'videoStyle', 'visualIntensity', 'visualEvolutionStyle']} />
        </div>

        <div className="p-6 border-t border-zinc-900 bg-zinc-950">
           <Button fullWidth onClick={startPipeline} disabled={!request.title}>
             Begin Generation Pipeline
           </Button>
        </div>
      </div>

      {/* Main Panel */}
      <div className="flex-1 relative bg-[#020202] h-screen overflow-hidden">
        {state === AppState.PLANNING || state === AppState.GENERATING ? (
          <div className="flex-1 h-full flex flex-col items-center justify-center p-12 text-center">
            <div className="relative mb-12">
               <div className="w-40 h-40 rounded-full border border-orange-500/10 flex items-center justify-center">
                  <div className="w-28 h-28 rounded-full border-2 border-orange-500/20 border-t-orange-500 animate-spin" />
               </div>
               <div className="absolute inset-0 flex items-center justify-center">
                  <span className="text-2xl font-space font-black">{genStatus.progress}%</span>
               </div>
            </div>
            <h2 className="text-4xl font-space font-black tracking-tighter mb-4 uppercase">{genStatus.statusText}</h2>
            <p className="text-zinc-500 max-w-md font-medium">Orchestrating {formatDuration(request.durationSeconds)} of structural coherence for "{request.title || 'Untitled Project'}"</p>
          </div>
        ) : state === AppState.PLAYING && activeItem ? (
          <div className="h-full relative flex flex-col">
            <div className="absolute inset-0 z-0">
               <img src={activeItem.videoUrl} className="w-full h-full object-cover opacity-30 blur-[1px] scale-105" alt="Visual reference" />
               <div className="absolute inset-0 bg-gradient-to-t from-black via-black/40 to-transparent"></div>
            </div>

            <div className="relative z-10 flex-1 flex flex-col p-16 justify-end">
               <div className="max-w-5xl space-y-10">
                  <div className="space-y-6">
                    <div className="flex gap-3">
                      <span className="px-3 py-1 rounded-full border border-orange-500/30 bg-orange-500/10 text-orange-500 text-[10px] font-black uppercase tracking-widest">Master File Active</span>
                      <span className="px-3 py-1 rounded-full border border-zinc-800 bg-zinc-900/50 text-zinc-400 text-[10px] font-black uppercase tracking-widest">{activeItem.request.videoType}</span>
                    </div>
                    <h2 className="text-8xl font-space font-black tracking-tighter text-white leading-[0.85]">{activeItem.request.title}</h2>
                    <p className="text-2xl text-zinc-400 font-medium max-w-3xl leading-relaxed">{activeItem.request.description}</p>
                  </div>

                  <div className="grid grid-cols-4 gap-12 text-zinc-500 py-4 border-y border-zinc-900">
                    <div>
                      <span className="block text-[10px] font-black uppercase tracking-widest text-zinc-700 mb-2">Key / Scale</span>
                      <span className="text-xl font-bold text-zinc-200">{activeItem.plan.key} {activeItem.plan.scale}</span>
                    </div>
                    <div>
                      <span className="block text-[10px] font-black uppercase tracking-widest text-zinc-700 mb-2">Tempo</span>
                      <span className="text-xl font-bold text-zinc-200">{activeItem.plan.bpm} BPM</span>
                    </div>
                    <div>
                      <span className="block text-[10px] font-black uppercase tracking-widest text-zinc-700 mb-2">Duration</span>
                      <span className="text-xl font-bold text-zinc-200">{formatDuration(activeItem.request.durationSeconds)}</span>
                    </div>
                    <div>
                      <span className="block text-[10px] font-black uppercase tracking-widest text-zinc-700 mb-2">Instruments</span>
                      <span className="text-sm font-bold text-zinc-400 truncate block">{activeItem.plan.instrumentPalette.slice(0, 2).join(', ')}...</span>
                    </div>
                  </div>

                  <div className="space-y-4 pt-10">
                    <div className="flex justify-between items-end text-[10px] font-black uppercase text-zinc-600 tracking-widest">
                       <span>Phase: {activeItem.plan.sections[0].label} — {activeItem.plan.sections[0].description}</span>
                       <span>{activeItem.request.bpm} BPM Sync</span>
                    </div>
                    <div className="h-1.5 w-full bg-zinc-900 rounded-full overflow-hidden relative shadow-inner">
                       <div className="absolute top-0 bottom-0 left-0 bg-orange-500 w-1/12 animate-pulse shadow-[0_0_20px_rgba(255,77,0,0.6)]"></div>
                    </div>
                  </div>

                  <div className="flex gap-6 pt-6">
                     <Button className="px-12 py-5 text-lg h-16">Live Output</Button>
                     <Button variant="secondary" className="px-12 py-5 text-lg h-16" onClick={() => window.open(activeItem.audioUrl)}>Download Master</Button>
                  </div>
               </div>
            </div>
            <audio autoPlay loop src={activeItem.audioUrl} className="hidden" />
          </div>
        ) : (
          <div className="h-full flex flex-col p-16 overflow-y-auto">
             <div className="mb-20 flex justify-between items-end">
                <div>
                   <h1 className="text-6xl font-space font-black tracking-tighter mb-4 uppercase">Synthesis <span className="text-orange-500">Suite</span></h1>
                   <p className="text-zinc-500 text-xl font-medium tracking-tight">Active Terminal: {user?.name} ({user?.phone_number})</p>
                </div>
                <div className="text-right">
                   <p className="text-[10px] font-black uppercase text-zinc-700 tracking-[0.3em]">Caffeine.ai Kernel v4.0.1</p>
                </div>
             </div>

             <div className="space-y-12">
                <h3 className="text-[11px] font-black uppercase tracking-[0.2em] text-zinc-600 border-b border-zinc-900 pb-4">Production Archive</h3>
                {history.length === 0 ? (
                  <div className="py-32 border-2 border-dashed border-zinc-900 rounded-[3rem] flex flex-col items-center justify-center text-center">
                    <div className="w-20 h-20 rounded-full bg-zinc-900/40 flex items-center justify-center mb-8 text-3xl">🎚️</div>
                    <p className="text-zinc-500 text-lg font-medium max-w-sm">No production files found in local storage. Start a new project to initialize synthesis.</p>
                  </div>
                ) : (
                  <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                    {history.map(item => (
                      <div 
                        key={item.id} onClick={() => { setActiveItem(item); setState(AppState.PLAYING); }}
                        className="group flex gap-8 p-8 border border-zinc-900 bg-zinc-950/40 rounded-[2.5rem] hover:border-orange-500/30 hover:bg-zinc-900/20 cursor-pointer transition-all duration-700"
                      >
                        <div className="w-40 h-40 rounded-3xl overflow-hidden flex-shrink-0 bg-zinc-900 shadow-2xl">
                          <img src={item.videoUrl} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000" />
                        </div>
                        <div className="flex-1 min-w-0 flex flex-col justify-center">
                          <span className="text-[10px] font-black uppercase text-orange-500 mb-2 tracking-widest">{item.request.genre}</span>
                          <h4 className="text-2xl font-space font-black text-zinc-100 truncate group-hover:text-orange-500 transition-colors leading-tight">{item.request.title}</h4>
                          <p className="text-base text-zinc-500 line-clamp-2 mt-3 font-medium leading-relaxed">{item.request.description}</p>
                          <div className="flex items-center gap-4 mt-6">
                            <span className="text-[10px] font-black uppercase px-3 py-1.5 bg-zinc-900 text-zinc-500 rounded-xl tracking-widest">{formatDuration(item.request.durationSeconds)}</span>
                            <span className="text-[10px] font-black uppercase px-3 py-1.5 bg-zinc-900 text-zinc-500 rounded-xl tracking-widest">{item.plan.bpm} BPM</span>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default App;

export enum AppState {
  ONBOARDING = 'ONBOARDING',
  DASHBOARD = 'DASHBOARD',
  PLANNING = 'PLANNING',
  GENERATING = 'GENERATING',
  PLAYING = 'PLAYING'
}

export enum VideoType {
  OFFICIAL = 'Official Music Video',
  LYRICAL = 'Lyrical Video',
  ABSTRACT = 'Abstract Video'
}

export enum ItemStatus {
  PLANNING = 'Planning',
  GENERATING = 'Generating',
  STITCHING = 'Stitching',
  RENDERING = 'Rendering Video',
  COMPLETED = 'Completed',
  FAILED = 'Failed'
}

export interface UserLocalProfile {
  user_id: string;
  name: string;
  phone_number: string;
  created_at: number;
  last_active_at: number;
}

export interface SongRequest {
  title: string;
  description: string;
  genre: string;
  subGenre: string;
  mood: string;
  energyLevel: string;
  tempoPreference: string;
  bpm: number;
  keyScale: string;
  language: string;
  lyricsMode: 'Instrumental' | 'AI' | 'User';
  lyricsInput: string;
  vocalPresence: 'None' | 'Sparse' | 'Full';
  vocalGender: string;
  vocalStyle: string;
  instrumentation: string;
  durationSeconds: number;
  structure: string;
  sectionLength: string;
  energyCurve: string;
  referenceArtists: string;
  useCase: string;
  videoType: VideoType;
  videoStyle: string;
  visualIntensity: string;
  visualEvolutionStyle: string;
}

export interface SongSection {
  startTime: number;
  endTime: number;
  label: string;
  energy: number;
  description: string;
}

export interface ImmutableSongPlan {
  bpm: number;
  key: string;
  scale: string;
  timeSignature: string;
  instrumentPalette: string[];
  vocalPresenceMap: string;
  sections: SongSection[];
  macroEnergyCurve: number[];
  textureEvolutionStrategy: string;
  videoPlan: {
    visualDescription: string;
    pacingStrategy: string;
    typeSpecificInstructions: string;
  };
}

export interface SongHistoryItem {
  id: string;
  request: SongRequest;
  plan: ImmutableSongPlan;
  audioUrl: string;
  videoUrl: string;
  status: ItemStatus;
  playbackPosition: number;
  createdAt: number;
}

export interface GenerationStatus {
  progress: number;
  currentSegment: number;
  totalSegments: number;
  statusText: string;
}

import React, { useState, useEffect, useMemo } from 'react';
import { AppState, UserLocalProfile, SongRequest, ImmutableSongPlan, SongHistoryItem, GenerationStatus, VideoType, ItemStatus } from './types';
import { Button } from './components/Button';
import { Input } from './components/Input';
import { getAISuggestion, createImmutableSongPlan, generateVisualReference, checkApiKey } from './services/geminiService';

const INDIAN_MOBILE_REGEX = /^[6789]\d{9}$/;

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(AppState.ONBOARDING);
  const [user, setUser] = useState<UserLocalProfile | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [onboardingError, setOnboardingError] = useState<string | null>(null);

  // Filter and Sort states for Dashboard
  const [sortBy, setSortBy] = useState<'newest' | 'oldest'>('newest');
  const [filterVideoType, setFilterVideoType] = useState<string>('all');
  const [filterDuration, setFilterDuration] = useState<'all' | 'short' | 'long'>('all');

  const [request, setRequest] = useState<SongRequest>({
    title: '', description: '', genre: '', subGenre: '', mood: '',
    energyLevel: 'Medium', tempoPreference: 'Moderate', bpm: 120, keyScale: 'C Minor',
    language: 'English', lyricsMode: 'Instrumental', lyricsInput: '', 
    vocalPresence: 'None', vocalGender: 'Neutral', vocalStyle: 'None',
    instrumentation: 'Digital Synths', durationSeconds: 180,
    structure: 'Standard', sectionLength: 'Medium', energyCurve: 'Linear',
    referenceArtists: '', useCase: 'Focus', videoType: VideoType.ABSTRACT,
    videoStyle: '', visualIntensity: 'Medium', visualEvolutionStyle: 'Slow'
  });

  const [suggestions, setSuggestions] = useState<Record<string, string>>({});
  const [loadingSuggestion, setLoadingSuggestion] = useState<string | null>(null);
  const [history, setHistory] = useState<SongHistoryItem[]>([]);
  const [activeItem, setActiveItem] = useState<SongHistoryItem | null>(null);
  const [genStatus, setGenStatus] = useState<GenerationStatus>({ progress: 0, currentSegment: 0, totalSegments: 0, statusText: '' });

  useEffect(() => {
    try {
      checkApiKey();
    } catch (e: any) {
      setError(e.message);
    }

    const savedUser = localStorage.getItem('caffeine_profile');
    const savedHistory = localStorage.getItem('caffeine_archive');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
      setState(AppState.DASHBOARD);
    }
    if (savedHistory) setHistory(JSON.parse(savedHistory));
  }, []);

  const saveProfile = (e: React.FormEvent) => {
    e.preventDefault();
    setOnboardingError(null);
    const formData = new FormData(e.target as HTMLFormElement);
    const name = formData.get('name') as string;
    const mobile = formData.get('mobile') as string;

    const cleanMobile = mobile.replace(/\D/g, '');
    if (!INDIAN_MOBILE_REGEX.test(cleanMobile)) {
      setOnboardingError("Invalid Indian Mobile Number. Must be 10 digits starting with 6-9.");
      return;
    }

    const profile: UserLocalProfile = {
      user_id: crypto.randomUUID(),
      name,
      phone_number: `+91${cleanMobile}`,
      created_at: Date.now(),
      last_active_at: Date.now()
    };

    localStorage.setItem('caffeine_profile', JSON.stringify(profile));
    setUser(profile);
    setState(AppState.DASHBOARD);
  };

  const resetApp = () => {
    if (confirm("Reset application? This will clear your identity and all generation history.")) {
      localStorage.clear();
      window.location.reload();
    }
  };

  const fetchSuggestion = async (field: keyof SongRequest) => {
    setLoadingSuggestion(field as string);
    try {
      const { suggestedValue, justification } = await getAISuggestion(field, request);
      setSuggestions(prev => ({ ...prev, [field]: justification }));

      if (field === 'durationSeconds' || field === 'bpm') {
        const numericValue = parseInt(suggestedValue.replace(/\D/g, ''));
        if (!isNaN(numericValue)) setRequest(prev => ({ ...prev, [field]: numericValue }));
      } else {
        setRequest(prev => ({ ...prev, [field]: suggestedValue }));
      }
    } catch (e: any) {
      setError(e.message);
    } finally {
      setLoadingSuggestion(null);
    }
  };

  const startPipeline = async () => {
    if (!request.title || !request.description) {
      alert("Title and Primary Description are required.");
      return;
    }

    setState(AppState.PLANNING);
    setGenStatus({ progress: 0, currentSegment: 0, totalSegments: 0, statusText: 'Synthesizing Mathematical Plan...' });

    try {
      const plan = await createImmutableSongPlan(request);
      setGenStatus({ progress: 15, currentSegment: 0, totalSegments: 0, statusText: 'Locking Song Blueprint...' });

      const segDuration = 600; 
      const totalSegs = Math.ceil(request.durationSeconds / segDuration);

      setState(AppState.GENERATING);
      setGenStatus(prev => ({ ...prev, totalSegments: totalSegs, statusText: 'Synthesizing Visual Atmosphere...' }));

      const visRef = await generateVisualReference(`${request.videoStyle} ${plan.textureEvolutionStrategy}`, request.videoType);

      for (let i = 0; i < totalSegs; i++) {
        setGenStatus(prev => ({
          ...prev,
          currentSegment: i + 1,
          progress: Math.floor(25 + (i / totalSegs) * 70),
          statusText: `Mastering Segment ${i + 1}/${totalSegs}...`
        }));
        await new Promise(r => setTimeout(r, 1200)); 
      }

      const newItem: SongHistoryItem = {
        id: crypto.randomUUID(),
        request: { ...request },
        plan,
        audioUrl: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-2.mp3',
        videoUrl: visRef,
        status: ItemStatus.COMPLETED,
        playbackPosition: 0,
        createdAt: Date.now()
      };

      const updatedHistory = [newItem, ...history];
      setHistory(updatedHistory);
      localStorage.setItem('caffeine_archive', JSON.stringify(updatedHistory));
      setActiveItem(newItem);
      setState(AppState.PLAYING);
    } catch (e: any) {
      setError(e.message);
      setState(AppState.DASHBOARD);
    }
  };

  const formatDuration = (s: number) => {
    const h = Math.floor(s / 3600);
    const m = Math.floor((s % 3600) / 60);
    const sc = s % 60;
    return `${h > 0 ? h + 'h ' : ''}${m}m ${sc}s`;
  };

  const filteredHistory = useMemo(() => {
    let result = [...history];

    if (filterVideoType !== 'all') {
      result = result.filter(item => item.request.videoType === filterVideoType);
    }

    if (filterDuration === 'short') {
      result = result.filter(item => item.request.durationSeconds < 600);
    } else if (filterDuration === 'long') {
      result = result.filter(item => item.request.durationSeconds >= 600);
    }

    return result.sort((a, b) => {
      return sortBy === 'newest' ? b.createdAt - a.createdAt : a.createdAt - b.createdAt;
    });
  }, [history, sortBy, filterVideoType, filterDuration]);

  if (error) {
    return (
      <div className="min-h-screen bg-black flex items-center justify-center p-8">
        <div className="max-w-md w-full bg-red-950/20 border border-red-900/50 p-8 rounded-2xl text-center">
          <h2 className="text-2xl font-bold text-red-500 mb-2">System Error</h2>
          <p className="text-zinc-400 mb-8">{error}</p>
          <Button fullWidth onClick={() => window.location.reload()}>Retry Boot</Button>
        </div>
      </div>
    );
  }

  if (state === AppState.ONBOARDING) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-black p-4 relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-full pointer-events-none opacity-20">
          <div className="absolute top-[-10%] right-[-10%] w-[500px] h-[500px] bg-orange-600 rounded-full blur-[120px] animate-pulse"></div>
        </div>
        <div className="w-full max-w-md bg-zinc-900/40 backdrop-blur-3xl p-10 border border-zinc-800 rounded-3xl shadow-2xl relative z-10">
          <div className="text-center mb-10">
            <h1 className="text-4xl font-space font-black tracking-tight mb-2">Caffeine<span className="text-orange-500">.ai</span></h1>
            <p className="text-zinc-500 font-medium">Regional Terminal: India (IN)</p>
          </div>
          <form onSubmit={saveProfile} className="space-y-6">
            <Input name="name" label="Full Name" placeholder="e.g. Satoshi Nakamoto" required />
            <div className="space-y-1.5">
              <label className="block text-sm font-medium text-zinc-400">Mobile Number (India 🇮🇳)</label>
              <div className="flex gap-2">
                <div className="bg-zinc-800 border border-zinc-700 rounded-lg px-3 py-3 text-zinc-400 font-semibold flex items-center">+91</div>
                <Input name="mobile" placeholder="9876543210" type="tel" maxLength={10} required className="flex-1" />
              </div>
            </div>
            {onboardingError && <p className="text-xs text-red-500 font-medium bg-red-500/10 p-3 rounded-lg border border-red-500/20">{onboardingError}</p>}
            <Button fullWidth type="submit" className="h-14 text-lg">Initialize Terminal</Button>
          </form>
        </div>
      </div>
    );
  }

  const getPlaceholder = (f: keyof SongRequest): string => {
    const samples: Record<string, string> = {
      title: "e.g. Midnight Horizon", description: "e.g. A slow-burning atmospheric techno track...",
      genre: "e.g. Deep House", subGenre: "e.g. Melodic Progressive", mood: "e.g. Melancholic yet hopeful",
      energyLevel: "e.g. Very High", tempoPreference: "e.g. Fast Driving", bpm: "e.g. 128", keyScale: "e.g. F Minor",
      language: "e.g. English", lyricsInput: "e.g. Lost in the lights of the city tonight...",
      vocalGender: "e.g. Female", vocalStyle: "e.g. Breathy whispers", instrumentation: "e.g. Analog bass, shimmer pads",
      structure: "e.g. Extended intro", sectionLength: "e.g. Long cinematic sections", energyCurve: "e.g. Gradual build",
      referenceArtists: "e.g. Lane 8 style", useCase: "e.g. Deep Work", videoStyle: "e.g. Abstract neon grid",
      visualIntensity: "e.g. High", visualEvolutionStyle: "e.g. Scene shifts every 32 bars"
    };
    return samples[f as string] || "e.g. Sample value...";
  };

  const CreationPanel = () => (
    <div className="flex-1 flex flex-col md:flex-row h-screen overflow-hidden">
      <div className="w-full md:w-[450px] h-full border-r border-zinc-900 bg-zinc-950 flex flex-col z-20 overflow-hidden">
        <div className="p-6 border-b border-zinc-900 flex justify-between items-center bg-zinc-950/80 backdrop-blur-md sticky top-0 z-10">
           <h2 className="text-xl font-space font-black tracking-tight uppercase">Creation <span className="text-orange-500">Suite</span></h2>
           <button onClick={() => setState(AppState.DASHBOARD)} className="text-[10px] font-black uppercase text-zinc-600 hover:text-orange-500 tracking-widest transition-colors">Cancel</button>
        </div>
        <div className="flex-1 overflow-y-auto p-6 space-y-12 scrollbar-hide">
          <FormSection title="Concept" fields={['title', 'description', 'useCase', 'referenceArtists']} />
          <FormSection title="Harmony" fields={['genre', 'subGenre', 'mood', 'energyLevel', 'tempoPreference', 'bpm', 'keyScale']} />
          <FormSection title="Voices" fields={['lyricsMode', 'lyricsInput', 'vocalPresence', 'vocalGender', 'vocalStyle', 'language']} />
          <FormSection title="Structure" fields={['durationSeconds', 'structure', 'sectionLength', 'energyCurve', 'instrumentation']} />
          <FormSection title="Visuals" fields={['videoType', 'videoStyle', 'visualIntensity', 'visualEvolutionStyle']} />
        </div>
        <div className="p-6 border-t border-zinc-900 bg-zinc-950">
           <Button fullWidth onClick={startPipeline} disabled={!request.title || !request.description}>Initialize Synthesis</Button>
        </div>
      </div>
      <div className="hidden md:flex flex-1 items-center justify-center p-20 text-center">
         <div className="max-w-md space-y-6">
            <div className="w-20 h-20 bg-zinc-900 rounded-3xl mx-auto flex items-center justify-center text-3xl">🏗️</div>
            <h2 className="text-3xl font-space font-black tracking-tighter uppercase">Building your blueprint</h2>
            <p className="text-zinc-500 leading-relaxed font-medium">Use the left panel to define the DNA of your track. Our engine will then orchestrate a seamless long-form audio-visual experience.</p>
         </div>
      </div>
    </div>
  );

  const FormSection = ({ title, fields }: { title: string, fields: (keyof SongRequest)[] }) => (
    <div className="space-y-6 pt-10 first:pt-0 border-t border-zinc-900 first:border-0">
      <h3 className="text-[11px] font-black uppercase tracking-[0.2em] text-zinc-500">{title}</h3>
      <div className="space-y-6">
        {fields.map(f => (
          <div key={f} className="space-y-3">
            <div className="flex items-end gap-2">
              <div className="flex-1">
                {f === 'videoType' ? (
                  <div className="space-y-1.5">
                    <label className="block text-sm font-medium text-zinc-400">Video Type</label>
                    <select 
                      className="w-full bg-zinc-900 border border-zinc-800 rounded-lg px-4 py-3 text-zinc-100 focus:outline-none focus:border-orange-500"
                      value={request.videoType}
                      onChange={e => setRequest({...request, videoType: e.target.value as VideoType})}
                    >
                      {Object.values(VideoType).map(v => <option key={v} value={v}>{v}</option>)}
                    </select>
                  </div>
                ) : f === 'durationSeconds' ? (
                  <div className="space-y-2">
                    <label className="text-xs font-bold text-zinc-500">Duration: {formatDuration(request.durationSeconds)}</label>
                    <input type="range" min="30" max="72000" step="30" className="w-full h-1 bg-zinc-800 rounded-full appearance-none accent-orange-500 cursor-pointer" value={request.durationSeconds} onChange={e => setRequest({...request, durationSeconds: parseInt(e.target.value)})} />
                  </div>
                ) : (
                  <Input label={f.replace(/([A-Z])/g, ' $1').replace(/^./, str => str.toUpperCase())} isTextArea={['description', 'lyricsInput', 'instrumentation'].includes(f)} value={(request as any)[f]} onChange={e => setRequest({...request, [f]: e.target.value})} placeholder={getPlaceholder(f)} />
                )}
              </div>
              <button onClick={() => fetchSuggestion(f)} disabled={loadingSuggestion === f} className="mb-1 p-2.5 rounded-lg border border-zinc-800 bg-zinc-900 text-zinc-500 hover:text-orange-500 transition-all disabled:opacity-30">
                {loadingSuggestion === f ? <div className="w-4 h-4 border-2 border-orange-500/30 border-t-orange-500 rounded-full animate-spin"/> : '✨'}
              </button>
            </div>
            {suggestions[f] && <div className="px-1 text-[11px] text-orange-400/80 font-medium italic">Note: {suggestions[f]}</div>}
          </div>
        ))}
      </div>
    </div>
  );

  const Dashboard = () => (
    <div className="flex-1 h-screen flex flex-col bg-[#020202] overflow-hidden">
      <header className="p-8 border-b border-zinc-900 flex justify-between items-end shrink-0 bg-zinc-950/40 backdrop-blur-xl">
        <div className="space-y-1">
          <h1 className="text-5xl font-space font-black tracking-tighter uppercase">Studio <span className="text-orange-500">Terminal</span></h1>
          <p className="text-zinc-500 text-lg font-medium">Hello {user?.name}. {history.length} active soundscapes found.</p>
        </div>
        <div className="flex items-center gap-6">
          <div className="flex flex-col items-end">
            <span className="text-[10px] font-black uppercase text-zinc-700 tracking-[0.2em] mb-2">Account Status</span>
            <span className="text-xs font-bold text-zinc-400">{user?.phone_number} / INDIA Terminal</span>
