          <Button onClick={() => setState(AppState.PLANNING)} className="px-8 h-14 text-lg">Create New Track</Button>
          <button onClick={resetApp} className="p-3 bg-zinc-900 text-zinc-600 rounded-xl hover:text-red-500 transition-colors">Reset</button>
        </div>
      </header>

      <div className="flex-1 overflow-y-auto p-8 space-y-12">
        <div className="flex items-center justify-between border-b border-zinc-900/50 pb-6">
          <h3 className="text-[11px] font-black uppercase tracking-[0.2em] text-zinc-600">Production History</h3>
          <div className="flex gap-4 items-center">
            <select className="bg-zinc-900 text-zinc-400 text-xs px-4 py-2 rounded-lg border border-zinc-800 outline-none" value={filterVideoType} onChange={e => setFilterVideoType(e.target.value)}>
