              {Object.values(VideoType).map(v => <option key={v} value={v}>{v}</option>)}
            </select>
            <select className="bg-zinc-900 text-zinc-400 text-xs px-4 py-2 rounded-lg border border-zinc-800 outline-none" value={filterDuration} onChange={e => setFilterDuration(e.target.value as any)}>
              <option value="all">Any Duration</option>
              <option value="short">Short (&lt;10m)</option>
              <option value="long">Long (10m+)</option>
            </select>
            <select className="bg-zinc-900 text-zinc-400 text-xs px-4 py-2 rounded-lg border border-zinc-800 outline-none" value={sortBy} onChange={e => setSortBy(e.target.value as any)}>
              <option value="newest">Newest First</option>
              <option value="oldest">Oldest First</option>
            </select>
          </div>
        </div>

        {filteredHistory.length === 0 ? (
          <div className="py-40 border-2 border-dashed border-zinc-900 rounded-[3rem] flex flex-col items-center justify-center text-center">
            <div className="text-5xl mb-8 opacity-40">💿</div>
            <p className="text-zinc-500 text-xl font-medium max-w-sm">No archive matching filters. Your journey starts with a single pulse.</p>
            <Button variant="secondary" className="mt-8" onClick={() => setState(AppState.PLANNING)}>New Production</Button>
          </div>
        ) : (
          <div className="grid grid-cols-1 xl:grid-cols-2 2xl:grid-cols-3 gap-8 pb-20">
            {filteredHistory.map(item => (
              <div key={item.id} className="group relative bg-zinc-950/40 border border-zinc-900 rounded-[2.5rem] p-8 hover:border-orange-500/30 transition-all duration-700 flex flex-col">
                <div className="flex gap-6 mb-8">
                  <div className="w-32 h-32 rounded-3xl overflow-hidden bg-zinc-900 flex-shrink-0 group-hover:scale-105 transition-transform duration-1000">
                    <img src={item.videoUrl} className="w-full h-full object-cover opacity-80" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <span className="text-[10px] font-black uppercase text-orange-500 tracking-[0.1em]">{item.request.genre} • {item.request.mood}</span>
                    <h4 className="text-2xl font-space font-black text-zinc-100 truncate mt-1 leading-tight">{item.request.title}</h4>
                    <p className="text-zinc-500 text-sm line-clamp-2 mt-2 font-medium">{item.request.description}</p>
                    <div className="flex gap-2 mt-4">
                      <span className="px-2 py-1 bg-zinc-900 rounded-lg text-[9px] font-black uppercase tracking-widest text-zinc-500">{item.status}</span>
                      {item.request.durationSeconds >= 600 && <span className="px-2 py-1 bg-orange-500/10 rounded-lg text-[9px] font-black uppercase tracking-widest text-orange-500">Long Duration</span>}
                    </div>
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-4 border-y border-zinc-900/50 py-4 mb-8">
                  <div className="text-center">
                    <span className="block text-[9px] font-black uppercase text-zinc-700 tracking-widest mb-1">Duration</span>
                    <span className="text-sm font-bold text-zinc-300">{formatDuration(item.request.durationSeconds)}</span>
                  </div>
                  <div className="text-center">
                    <span className="block text-[9px] font-black uppercase text-zinc-700 tracking-widest mb-1">Tempo</span>
                    <span className="text-sm font-bold text-zinc-300">{item.plan.bpm} BPM</span>
                  </div>
                </div>
                <div className="mt-auto grid grid-cols-2 gap-4">
                  <Button variant="secondary" className="h-12 text-sm" onClick={() => { setActiveItem(item); setState(AppState.PLAYING); }}>Play Stream</Button>
                  <Button variant="outline" className="h-12 text-sm" onClick={() => window.open(item.audioUrl)}>Download</Button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-black text-zinc-100 flex flex-col overflow-hidden">
      {state === AppState.ONBOARDING ? null : (
        state === AppState.PLANNING ? <CreationPanel /> :
        state === AppState.DASHBOARD ? <Dashboard /> :
        state === AppState.GENERATING || state === AppState.PLANNING ? (
          <div className="flex-1 flex flex-col items-center justify-center p-12 text-center bg-black">
            <div className="relative mb-12">
               <div className="w-40 h-40 rounded-full border border-orange-500/10 flex items-center justify-center">
                  <div className="w-28 h-28 rounded-full border-2 border-orange-500/20 border-t-orange-500 animate-spin" />
               </div>
               <div className="absolute inset-0 flex items-center justify-center">
                  <span className="text-2xl font-space font-black">{genStatus.progress}%</span>
               </div>
            </div>
            <h2 className="text-4xl font-space font-black tracking-tighter mb-4 uppercase">{genStatus.statusText}</h2>
            <p className="text-zinc-500 max-w-md font-medium italic">Maintaining structural coherence for "{request.title}" across {genStatus.totalSegments > 1 ? genStatus.totalSegments + ' segments' : 'single block'}.</p>
          </div>
        ) : state === AppState.PLAYING && activeItem ? (
          <div className="h-screen relative flex flex-col bg-black">
            <div className="absolute inset-0 z-0">
               <img src={activeItem.videoUrl} className="w-full h-full object-cover opacity-30 blur-[1px] scale-105" />
               <div className="absolute inset-0 bg-gradient-to-t from-black via-black/20 to-transparent"></div>
            </div>
            <div className="relative z-10 flex-1 flex flex-col p-16 justify-end">
               <div className="max-w-5xl space-y-10">
                  <div className="space-y-6">
                    <div className="flex gap-4">
                      <span className="px-3 py-1 rounded-full border border-orange-500/30 bg-orange-500/10 text-orange-500 text-[10px] font-black uppercase tracking-widest">Master File Active</span>
                      <button onClick={() => setState(AppState.DASHBOARD)} className="px-3 py-1 rounded-full border border-zinc-700 bg-zinc-900/50 text-zinc-400 text-[10px] font-black uppercase tracking-widest hover:text-white transition-colors">Return to Dashboard</button>
                    </div>
                    <h2 className="text-8xl font-space font-black tracking-tighter text-white leading-[0.85]">{activeItem.request.title}</h2>
                    <p className="text-2xl text-zinc-400 font-medium max-w-3xl leading-relaxed italic">"{activeItem.request.description}"</p>
                  </div>
                  <div className="grid grid-cols-4 gap-12 text-zinc-500 py-6 border-y border-zinc-900">
                    <div><span className="block text-[10px] font-black uppercase text-zinc-700 mb-2 tracking-widest">Key</span><span className="text-xl font-bold text-zinc-200">{activeItem.plan.key} {activeItem.plan.scale}</span></div>
                    <div><span className="block text-[10px] font-black uppercase text-zinc-700 mb-2 tracking-widest">Tempo</span><span className="text-xl font-bold text-zinc-200">{activeItem.plan.bpm} BPM</span></div>
                    <div><span className="block text-[10px] font-black uppercase text-zinc-700 mb-2 tracking-widest">Duration</span><span className="text-xl font-bold text-zinc-200">{formatDuration(activeItem.request.durationSeconds)}</span></div>
                    <div><span className="block text-[10px] font-black uppercase text-zinc-700 mb-2 tracking-widest">Type</span><span className="text-sm font-bold text-zinc-400 uppercase tracking-widest">{activeItem.request.videoType}</span></div>
                  </div>
                  <div className="space-y-4 pt-10">
                    <div className="flex justify-between items-end text-[10px] font-black uppercase text-zinc-600 tracking-widest">
                       <span>Phase: {activeItem.plan.sections[0].label} — {activeItem.plan.sections[0].description}</span>
                       <span>Auto-Resume Active</span>
                    </div>
                    <div className="h-2 w-full bg-zinc-900 rounded-full overflow-hidden relative shadow-inner">
                       <div className="absolute top-0 bottom-0 left-0 bg-orange-500 w-1/12 animate-pulse shadow-[0_0_25px_rgba(255,77,0,0.7)]"></div>
                    </div>
                  </div>
                  <div className="flex gap-6 pt-6">
                     <Button className="px-14 py-6 text-xl h-20">Live Broadcast</Button>
                     <Button variant="secondary" className="px-14 py-6 text-xl h-20" onClick={() => window.open(activeItem.audioUrl)}>Export Master</Button>
                  </div>
               </div>
            </div>
            <audio autoPlay loop src={activeItem.audioUrl} className="hidden" />
          </div>
        ) : null
      )}
    </div>
  );
};

