           <button onClick={() => setState(AppState.DASHBOARD)} className="text-[10px] font-black uppercase text-zinc-600 hover:text-orange-500 tracking-widest transition-colors">Cancel</button>
        </div>
        <div className="flex-1 overflow-y-auto p-6 space-y-12 scrollbar-hide">
          <FormSection title="Concept" fields={['title', 'description', 'genre', 'mood', 'energyLevel', 'bpm']} />
          <FormSection title="Composition" fields={['durationSeconds', 'referenceArtists']} />
          <FormSection title="Voices" fields={['lyricsMode', 'lyricsInput', 'vocalStyle']} />

          <div className="space-y-6 pt-10 border-t border-zinc-900">
             <h3 className="text-[11px] font-black uppercase tracking-[0.2em] text-zinc-500">Video Integration</h3>
             <div className="space-y-4">
                <label className="block text-sm font-medium text-zinc-400">Select Video Types (Multi-select)</label>
                <div className="grid grid-cols-1 gap-2">
                   {Object.values(VideoType).map(v => (
                     <button 
                       key={v} onClick={() => toggleVideoType(v)}
                       className={`px-4 py-3 rounded-xl border text-left text-xs font-bold uppercase tracking-widest transition-all ${request.videoTypes.includes(v) ? 'bg-orange-500/10 border-orange-500/50 text-orange-500' : 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:border-zinc-700'}`}
                     >
                       {request.videoTypes.includes(v) ? '✓ ' : '+ '}{v}
