             </div>
             <FormSection title="" fields={['videoStyle']} />
          </div>
        </div>
        <div className="p-6 border-t border-zinc-900 bg-zinc-950">
           <Button fullWidth onClick={startPipeline} disabled={!request.title || !request.description}>Begin Generation</Button>
        </div>
      </div>
      <div className="hidden md:flex flex-1 items-center justify-center p-20 text-center bg-[#020202]">
         <div className="max-w-md space-y-8">
            <div className="w-24 h-24 bg-zinc-900/50 border border-zinc-800 rounded-[2rem] mx-auto flex items-center justify-center text-4xl shadow-2xl">⚡</div>
            <h2 className="text-4xl font-space font-black tracking-tighter uppercase leading-none">Architecture Mode</h2>
            <p className="text-zinc-500 text-lg leading-relaxed font-medium">Simplified inputs. Maximum depth. Our engine orchestrates long-form coherence based on your core choices.</p>
