                    <label className="block text-sm font-medium text-zinc-400">Lyrics Mode</label>
                    <div className="flex gap-2">
                      {['Instrumental', 'AI', 'User'].map(m => (
                        <button key={m} onClick={() => setRequest({...request, lyricsMode: m as any})} className={`flex-1 py-3 rounded-lg border text-[10px] font-black uppercase tracking-widest transition-all ${request.lyricsMode === m ? 'bg-orange-500 border-orange-500 text-white' : 'bg-zinc-900 border-zinc-800 text-zinc-500'}`}>{m}</button>
