          </div>
        ) : (
          <div className="grid grid-cols-1 xl:grid-cols-2 2xl:grid-cols-3 gap-8 pb-32">
            {filteredHistory.map(item => (
              <div key={item.id} className="group relative bg-zinc-950/40 border border-zinc-900 rounded-[2.5rem] p-8 hover:border-orange-500/40 transition-all duration-700 flex flex-col hover:bg-zinc-900/10">
                <div className="flex gap-6 mb-8">
                  <div className="w-32 h-32 rounded-[2rem] overflow-hidden bg-zinc-900 flex-shrink-0 group-hover:scale-105 transition-all duration-1000 shadow-2xl relative">
                    <img src={item.videoUrl} className="w-full h-full object-cover opacity-70 group-hover:opacity-100 transition-opacity" />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent"></div>
                  </div>
                  <div className="flex-1 min-w-0 flex flex-col justify-center">
                    <div className="flex gap-2 flex-wrap mb-1">
                       {item.request.videoTypes.map(vt => (
                         <span key={vt} className="text-[8px] font-black uppercase text-orange-500 bg-orange-500/10 px-2 py-0.5 rounded-md border border-orange-500/20">{vt.split(' ')[0]}</span>
                       ))}
                    </div>
                    <h4 className="text-2xl font-space font-black text-zinc-100 truncate mt-1 leading-tight group-hover:text-orange-500 transition-colors">{item.request.title}</h4>
                    <p className="text-zinc-600 text-xs line-clamp-2 mt-2 font-medium italic">{item.request.genre} — {item.request.mood}</p>
                  </div>
                </div>

                <div className="grid grid-cols-3 gap-4 border-y border-zinc-900/50 py-5 mb-8">
                  <div className="text-center">
                    <span className="block text-[8px] font-black uppercase text-zinc-700 tracking-widest mb-1">Length</span>
                    <span className="text-sm font-bold text-zinc-300">{formatDuration(item.request.durationSeconds)}</span>
                  </div>
                  <div className="text-center">
                    <span className="block text-[8px] font-black uppercase text-zinc-700 tracking-widest mb-1">Status</span>
                    <span className="text-sm font-bold text-orange-500">{item.status}</span>
                  </div>
                  <div className="text-center">
                    <span className="block text-[8px] font-black uppercase text-zinc-700 tracking-widest mb-1">Resumed</span>
                    <span className="text-sm font-bold text-zinc-300">0%</span>
                  </div>
                </div>

                <div className="mt-auto flex gap-4">
                  <Button variant="secondary" className="flex-1 h-14 text-xs font-black uppercase tracking-widest" onClick={() => { setActiveItem(item); setState(AppState.PLAYING); }}>Launch</Button>
                  <Button variant="outline" className="p-0 w-14 h-14" onClick={() => window.open(item.audioUrl)}>⬇</Button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-black text-zinc-100 flex flex-col overflow-hidden">
      {state === AppState.ONBOARDING ? null : (
        state === AppState.PLANNING ? <CreationPanel /> :
        state === AppState.DASHBOARD ? <Dashboard /> :
        state === AppState.GENERATING || state === AppState.PLANNING ? (
          <div className="flex-1 flex flex-col items-center justify-center p-12 text-center bg-[#020202]">
            <div className="relative mb-16">
               <div className="w-56 h-56 rounded-full border border-orange-500/10 flex items-center justify-center">
                  <div className="w-40 h-40 rounded-full border-[3px] border-orange-500/10 border-t-orange-500 animate-spin" />
               </div>
               <div className="absolute inset-0 flex flex-col items-center justify-center">
                  <span className="text-4xl font-space font-black">{genStatus.progress}%</span>
                  <span className="text-[9px] font-black uppercase tracking-widest text-zinc-600 mt-1">Syncing</span>
               </div>
            </div>
            <h2 className="text-5xl font-space font-black tracking-tighter mb-6 uppercase max-w-2xl">{genStatus.statusText}</h2>
            <div className="flex items-center gap-4 text-zinc-500 font-bold uppercase text-[10px] tracking-[0.3em]">
               <span>MASTER: {request.title}</span>
               <span className="w-1 h-1 rounded-full bg-zinc-800"></span>
               <span>{formatDuration(request.durationSeconds)}</span>
            </div>
          </div>
        ) : state === AppState.PLAYING && activeItem ? (
          <div className="h-screen relative flex flex-col bg-black">
            <div className="absolute inset-0 z-0">
               <img src={activeItem.videoUrl} className="w-full h-full object-cover opacity-40 blur-[2px] scale-110" />
               <div className="absolute inset-0 bg-gradient-to-t from-black via-black/40 to-transparent"></div>
            </div>
            <div className="relative z-10 flex-1 flex flex-col p-16 justify-end">
               <div className="max-w-6xl space-y-12">
                  <div className="space-y-6">
                    <div className="flex gap-4">
                      <span className="px-4 py-1.5 rounded-full border border-orange-500/30 bg-orange-500/10 text-orange-500 text-[10px] font-black uppercase tracking-widest flex items-center gap-2">
                        <span className="w-1.5 h-1.5 rounded-full bg-orange-500 animate-pulse"></span> Production Active
                      </span>
                      <button onClick={() => setState(AppState.DASHBOARD)} className="px-4 py-1.5 rounded-full border border-zinc-800 bg-zinc-950/50 text-zinc-500 text-[10px] font-black uppercase tracking-widest hover:text-white transition-all">Close Terminal</button>
                    </div>
                    <h2 className="text-[10rem] font-space font-black tracking-tighter text-white leading-[0.75] opacity-90">{activeItem.request.title}</h2>
                    <p className="text-3xl text-zinc-400 font-medium max-w-4xl leading-relaxed italic border-l-4 border-orange-500/30 pl-8">"{activeItem.request.description}"</p>
                  </div>

                  <div className="grid grid-cols-4 gap-12 text-zinc-500 py-10 border-y border-zinc-900/50">
                    <div><span className="block text-[10px] font-black uppercase text-zinc-700 mb-3 tracking-[0.3em]">Signature</span><span className="text-2xl font-bold text-zinc-200">{activeItem.plan.bpm} BPM / 4/4</span></div>
                    <div><span className="block text-[10px] font-black uppercase text-zinc-700 mb-3 tracking-[0.3em]">Palette</span><span className="text-2xl font-bold text-zinc-200 truncate block">{activeItem.plan.instrumentPalette.slice(0, 2).join(' + ')}</span></div>
                    <div><span className="block text-[10px] font-black uppercase text-zinc-700 mb-3 tracking-[0.3em]">Terminal</span><span className="text-2xl font-bold text-zinc-200 uppercase">{activeItem.request.genre}</span></div>
                    <div><span className="block text-[10px] font-black uppercase text-zinc-700 mb-3 tracking-[0.3em]">Duration</span><span className="text-2xl font-bold text-zinc-200">{formatDuration(activeItem.request.durationSeconds)}</span></div>
                  </div>

                  <div className="space-y-6 pt-4">
                    <div className="flex justify-between items-end text-[11px] font-black uppercase text-zinc-600 tracking-[0.2em]">
                       <span>Phase: {activeItem.plan.sections[0].label} — {activeItem.plan.sections[0].description}</span>
                       <span className="text-orange-500/50">Seamless Resync Enabled</span>
                    </div>
                    <div className="h-2 w-full bg-zinc-900/50 rounded-full overflow-hidden relative border border-zinc-800/50">
                       <div className="absolute top-0 bottom-0 left-0 bg-orange-500 w-[8%] shadow-[0_0_30px_rgba(255,77,0,0.8)]"></div>
                    </div>
                  </div>

                  <div className="flex gap-8 pt-8">
                     <Button className="px-20 py-8 text-2xl h-24 uppercase tracking-[0.2em] font-black">Broadcast</Button>
                     <Button variant="secondary" className="px-20 py-8 text-2xl h-24 uppercase tracking-[0.2em] font-black" onClick={() => window.open(activeItem.audioUrl)}>Export File</Button>
                  </div>
               </div>
            </div>
            <audio autoPlay loop src={activeItem.audioUrl} className="hidden" />
          </div>
        ) : null
      )}
    </div>
  );
};

export default App;

