            className="text-[10px] font-bold text-brand/60 hover:text-brand transition-colors flex items-center gap-1 uppercase tracking-tighter disabled:opacity-30"
          >
            {isSuggesting ? (
              <span className="w-2 h-2 border-t-2 border-brand rounded-full animate-spin"></span>
            ) : '✨ AI Suggest'}
