        <Component
          className={`w-full bg-surface border border-border rounded-xl px-4 py-3.5 text-zinc-100 text-sm placeholder-zinc-700 focus:outline-none focus:border-brand/40 focus:ring-4 focus:ring-brand/5 transition-all ${isTextArea ? 'min-h-[100px] resize-none' : ''} ${className}`}
          {...props as any}
        />
      </div>

      {helperText && (
        <p className="text-[11px] text-zinc-500 leading-relaxed font-medium pl-1 italic">
          {helperText}
        </p>
      )}
    </div>
  );
};

