  const [suggestions, setSuggestions] = useState<Record<string, string>>({});
  const [loadingSuggestion, setLoadingSuggestion] = useState<string | null>(null);
  const [history, setHistory] = useState<SongHistoryItem[]>([]);
  const [activeItem, setActiveItem] = useState<SongHistoryItem | null>(null);
  const [genStatus, setGenStatus] = useState<GenerationStatus>({ progress: 0, currentSegment: 0, totalSegments: 0, statusText: '' });

  useEffect(() => {
    try {
      checkApiKey();
    } catch (e: any) {
      setError(e.message);
    }

    const savedUser = localStorage.getItem('musewave_profile');
    const savedHistory = localStorage.getItem('musewave_archive');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
      setState(AppState.DASHBOARD);
    }
    if (savedHistory) setHistory(JSON.parse(savedHistory));
  }, []);

  const saveProfile = (e: React.FormEvent) => {
    e.preventDefault();
    setOnboardingError(null);
    const formData = new FormData(e.target as HTMLFormElement);
    const name = formData.get('name') as string;
    const mobile = formData.get('mobile') as string;

    const cleanMobile = mobile.replace(/\D/g, '');
    if (!INDIAN_MOBILE_REGEX.test(cleanMobile)) {
      setOnboardingError("Please enter a valid 10-digit Indian mobile number.");
      return;
    }

    const profile: UserLocalProfile = {
      user_id: crypto.randomUUID(),
      name,
      phone_number: `+91${cleanMobile}`,
      created_at: Date.now(),
      last_active_at: Date.now()
    };

    localStorage.setItem('musewave_profile', JSON.stringify(profile));
    setUser(profile);
    setState(AppState.DASHBOARD);
  };

  const resetApp = () => {
    if (confirm("Reset MuseWave? This will clear your profile and history.")) {
      localStorage.clear();
      window.location.reload();
    }
  };

  const fetchSuggestion = async (field: keyof SongRequest) => {
    setLoadingSuggestion(field as string);
    try {
      const { suggestedValue, justification } = await getAISuggestion(field, request);
      setSuggestions(prev => ({ ...prev, [field]: justification }));

      if (field === 'durationSeconds' || field === 'bpm') {
        const numericValue = parseInt(suggestedValue.replace(/\D/g, ''));
        if (!isNaN(numericValue)) setRequest(prev => ({ ...prev, [field]: numericValue }));
      } else {
        setRequest(prev => ({ ...prev, [field]: suggestedValue }));
      }
    } catch (e: any) {
      setError(e.message);
    } finally {
      setLoadingSuggestion(null);
    }
  };

  const toggleVideoType = (type: VideoType) => {
    setRequest(prev => {
      const exists = prev.videoTypes.includes(type);
      if (exists) {
        if (prev.videoTypes.length === 1) return prev;
        return { ...prev, videoTypes: prev.videoTypes.filter(t => t !== type) };
      }
      return { ...prev, videoTypes: [...prev.videoTypes, type] };
    });
  };

  const startPipeline = async () => {
    if (!request.title || !request.description) {
      alert("Please provide a Title and Primary Description.");
      return;
    }

    setState(AppState.PLANNING);
    setGenStatus({ progress: 0, currentSegment: 0, totalSegments: 0, statusText: 'Synthesizing Architecture...' });

    try {
      const plan = await createImmutableSongPlan(request);
      setGenStatus({ progress: 20, currentSegment: 0, totalSegments: 0, statusText: 'Locking Sound Blueprint...' });

      const segDuration = 600; 
      const totalSegs = Math.ceil(request.durationSeconds / segDuration);

      setState(AppState.GENERATING);
      setGenStatus(prev => ({ ...prev, totalSegments: totalSegs, statusText: 'Synthesizing Atmosphere...' }));

      const visRef = await generateVisualReference(`${request.videoStyle} ${plan.textureEvolutionStrategy}`, request.videoTypes);

      for (let i = 0; i < totalSegs; i++) {
        setGenStatus(prev => ({
          ...prev,
          currentSegment: i + 1,
          progress: Math.floor(30 + (i / totalSegs) * 60),
          statusText: `Weaving Segment ${i + 1}/${totalSegs}...`
        }));
        await new Promise(r => setTimeout(r, 1000)); 
      }

      const newItem: SongHistoryItem = {
        id: crypto.randomUUID(),
        request: { ...request },
        plan,
        audioUrl: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-2.mp3',
        videoUrl: visRef,
        status: ItemStatus.COMPLETED,
        playbackPosition: 0,
        createdAt: Date.now()
      };

      const updatedHistory = [newItem, ...history];
      setHistory(updatedHistory);
      localStorage.setItem('musewave_archive', JSON.stringify(updatedHistory));
      setActiveItem(newItem);
      setState(AppState.PLAYING);
    } catch (e: any) {
      setError(e.message);
      setState(AppState.DASHBOARD);
    }
  };

  const formatDuration = (s: number) => {
    const h = Math.floor(s / 3600);
    const m = Math.floor((s % 3600) / 60);
    const sc = s % 60;
    if (h > 0) return `${h}h ${m}m ${sc}s`;
    return `${m}m ${sc}s`;
  };

  const filteredHistory = useMemo(() => {
    let result = [...history];
    if (filterVideoType !== 'all') {
      result = result.filter(item => item.request.videoTypes.includes(filterVideoType as VideoType));
    }
    if (filterDuration === 'short') {
      result = result.filter(item => item.request.durationSeconds < 600);
    } else if (filterDuration === 'long') {
      result = result.filter(item => item.request.durationSeconds >= 600);
    }
    return result.sort((a, b) => sortBy === 'newest' ? b.createdAt - a.createdAt : a.createdAt - b.createdAt);
  }, [history, sortBy, filterVideoType, filterDuration]);

