import { GoogleGenAI, Type } from "@google/genai";
import { SongRequest, ImmutableSongPlan } from "../types";

// Note: API Key is handled by environment variable process.env.API_KEY
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export async function getAISuggestion(field: keyof SongRequest, currentRequest: Partial<SongRequest>): Promise<{ suggestedValue: string, explanation: string }> {
  if (!process.env.API_KEY) throw new Error("Configuration error: GOOGLE_API_KEY is missing or invalid.");

  const context = JSON.stringify(currentRequest);
  const prompt = `You are a world-class AI music producer for MuseWave. 
  Suggest a high-end, production-ready value for the field: "${field.toString()}".

  CURRENT CONTEXT: ${context}

  RULES:
  - Return ONLY JSON.
  - suggestedValue: A single string or numeric string representing the field's value.
  - explanation: A single short sentence (max 12 words) explaining why this fits.
  - No conversational text or meta-explanation.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          suggestedValue: { type: Type.STRING },
          explanation: { type: Type.STRING }
        },
        required: ["suggestedValue", "explanation"]
      }
    }
  });

  return JSON.parse(response.text || "{}");
}

export async function createImmutableSongPlan(request: SongRequest): Promise<ImmutableSongPlan> {
  if (!process.env.API_KEY) throw new Error("Configuration error: GOOGLE_API_KEY is missing or invalid.");

  const prompt = `Act as the Master Architect for MuseWave. Generate a complete, immutable SONG PLAN for: ${JSON.stringify(request)}.

  The plan must define the structural backbone for a ${request.duration} track.

  REQUIREMENTS:
  - bpm: must be a number based on tempo preference.
  - key/scale: musical foundation.
  - sections: split duration into logical musical parts.
  - macroEnergyCurve: 0.0 to 1.0 values representing evolution.

  Return ONLY JSON.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          bpm: { type: Type.NUMBER },
          key: { type: Type.STRING },
          scale: { type: Type.STRING },
          timeSignature: { type: Type.STRING },
          instrumentPalette: { type: Type.ARRAY, items: { type: Type.STRING } },
          sections: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                startTime: { type: Type.NUMBER },
                endTime: { type: Type.NUMBER },
                label: { type: Type.STRING },
                energy: { type: Type.NUMBER },
                description: { type: Type.STRING }
              }
            }
          },
          macroEnergyCurve: { type: Type.ARRAY, items: { type: Type.NUMBER } },
          textureEvolutionStrategy: { type: Type.STRING }
        },
        required: ["bpm", "key", "scale", "timeSignature", "instrumentPalette", "sections", "macroEnergyCurve", "textureEvolutionStrategy"]
      }
    }
  });

  return JSON.parse(response.text || "{}");
}

export async function generatePlaceholderVisual(prompt: string): Promise<string> {
  if (!process.env.API_KEY) return "https://images.unsplash.com/photo-1614613535308-eb5fbd3d2c17?auto=format&fit=crop&q=80&w=1000";

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: `Cinematic, ultra-high-definition, moody visual art for a music video. Theme: ${prompt}. Non-fatiguing, loopable aesthetic.` }] }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return "https://images.unsplash.com/photo-1614613535308-eb5fbd3d2c17?auto=format&fit=crop&q=80&w=1000";
}

import React, { useState, useEffect, useRef } from 'react';
import { AppState, UserLocalProfile, SongRequest, VideoType, SongHistoryItem, ItemStatus, GenerationStatus } from './types';
import { Input } from './components/Input';
import { Button } from './components/Button';
import { getAISuggestion, createImmutableSongPlan, generatePlaceholderVisual } from './services/geminiService';

const INITIAL_REQUEST: SongRequest = {
  title: '', description: '', genre: '', subGenre: '', mood: '', energyLevel: '',
  tempo: '', bpm: '', musicalKey: '', language: '', lyricsMode: '', lyricsInput: '',
  vocalPresence: '', vocalGender: '', vocalStyle: '', instrumentation: '',
  duration: '', structure: '', sectionLength: '', energyCurve: '',
  referenceArtists: '', useCase: '', videoType: VideoType.ABSTRACT,
  videoStyle: '', visualIntensity: '', visualEvolution: ''
};

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.ONBOARDING);
  const [user, setUser] = useState<UserLocalProfile | null>(null);
  const [history, setHistory] = useState<SongHistoryItem[]>([]);
  const [request, setRequest] = useState<SongRequest>(INITIAL_REQUEST);
  const [explanations, setExplanations] = useState<Record<string, string>>({});
  const [isSuggesting, setIsSuggesting] = useState<Record<string, boolean>>({});
  const [genStatus, setGenStatus] = useState<GenerationStatus | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  const outputRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const savedProfile = localStorage.getItem('musewave_profile');
    const savedHistory = localStorage.getItem('musewave_history');
    if (savedProfile) {
      setUser(JSON.parse(savedProfile));
      setAppState(AppState.HOME);
    }
    if (savedHistory) setHistory(JSON.parse(savedHistory));
  }, []);

  const handleOnboard = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserLocalProfile = {
      user_id: crypto.randomUUID(),
      name: formData.get('name') as string,
      phone_number: formData.get('mobile') as string,
      created_at: Date.now(),
      last_active_at: Date.now()
    };
    localStorage.setItem('musewave_profile', JSON.stringify(profile));
    setUser(profile);
    setAppState(AppState.HOME);
  };

  const handleSuggest = async (field: keyof SongRequest) => {
    setIsSuggesting(prev => ({ ...prev, [field]: true }));
    try {
      const { suggestedValue, explanation } = await getAISuggestion(field, request);
      setRequest(prev => ({ ...prev, [field]: suggestedValue }));
      setExplanations(prev => ({ ...prev, [field]: explanation }));
    } catch (err) {
      console.error(err);
    } finally {
      setIsSuggesting(prev => ({ ...prev, [field]: false }));
    }
  };

  const handleGenerate = async () => {
    if (!request.title || !request.description) {
      alert("Please provide at least a title and description.");
      return;
    }

    setGenStatus({ progress: 10, statusText: ItemStatus.PLANNING });

    // Smooth scroll to output area
    setTimeout(() => outputRef.current?.scrollIntoView({ behavior: 'smooth' }), 100);

    try {
      const plan = await createImmutableSongPlan(request);
      setGenStatus({ progress: 25, statusText: ItemStatus.GENERATING });

      const visual = await generatePlaceholderVisual(request.videoStyle || request.mood);

      // Simulate segmentation logic (Long-duration handling)
      await new Promise(r => setTimeout(r, 2000));
      setGenStatus({ progress: 50, statusText: ItemStatus.STITCHING });
      await new Promise(r => setTimeout(r, 1500));
      setGenStatus({ progress: 80, statusText: ItemStatus.RENDERING });
      await new Promise(r => setTimeout(r, 2000));

      const newItem: SongHistoryItem = {
        id: crypto.randomUUID(),
        request: { ...request },
        plan,
        audioUrl: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3",
        videoUrl: visual,
        status: ItemStatus.COMPLETED,
        playbackPosition: 0,
        createdAt: Date.now()
      };

      const newHistory = [newItem, ...history];
      setHistory(newHistory);
      localStorage.setItem('musewave_history', JSON.stringify(newHistory));
      setGenStatus({ progress: 100, statusText: ItemStatus.COMPLETED });
    } catch (err) {
      setGenStatus({ progress: 0, statusText: ItemStatus.FAILED });
      alert(err instanceof Error ? err.message : "Generation failed.");
    }
  };

  const resetApp = () => {
    if (confirm("Reset MuseWave? This will purge all local data.")) {
      localStorage.clear();
      window.location.reload();
    }
  };

  if (!process.env.API_KEY) {
    return <div className="p-20 text-red-500 font-black text-center text-2xl uppercase tracking-tighter">Configuration error: GOOGLE_API_KEY is missing or invalid.</div>;
  }

  if (appState === AppState.ONBOARDING) {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-deep">
        <div className="glass max-w-lg w-full p-12 rounded-[3rem] shadow-[0_0_100px_rgba(255,77,0,0.1)] space-y-10 border border-white/5 relative overflow-hidden">
          <div className="absolute -top-24 -left-24 w-48 h-48 bg-brand/10 blur-[100px] rounded-full"></div>
          <div className="text-center relative z-10">
            <h1 className="text-5xl font-space font-black tracking-tighter text-glow uppercase">MuseWave</h1>
            <p className="text-zinc-500 text-[10px] font-black uppercase tracking-[0.5em] mt-4">Initialize Terminal Identity</p>
          </div>
          <form onSubmit={handleOnboard} className="space-y-8 relative z-10">
            <Input label="Full Name" name="name" placeholder="Johnathan Miller" required />
            <Input label="Mobile Identity" name="mobile" placeholder="+1 000-000-0000" type="tel" required />
            <Button fullWidth type="submit" className="h-16 text-lg tracking-widest uppercase font-black">Link Terminal</Button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex bg-deep font-sans">
      {/* LHS Sidebar */}
      <aside className={`fixed h-full bg-surface border-r border-border transition-all duration-500 z-50 ${isSidebarOpen ? 'w-64' : 'w-20'}`}>
        <div className="flex flex-col h-full">
          <div className="p-8 flex items-center justify-between">
            <h2 className={`text-2xl font-space font-black tracking-tighter text-brand uppercase transition-opacity ${isSidebarOpen ? 'opacity-100' : 'opacity-0 hidden'}`}>MW</h2>
            <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="text-zinc-500 hover:text-brand transition-colors">
              {isSidebarOpen ? '❮' : '❯'}
            </button>
          </div>

          <nav className="flex-1 px-4 space-y-3 mt-10">
            <SidebarItem icon="🏠" label="Home" active={appState === AppState.HOME} collapsed={!isSidebarOpen} onClick={() => setAppState(AppState.HOME)} />
