const INITIAL_REQUEST: SongRequest = {
  title: '', description: '', genre: '', subGenre: '', mood: '', energyLevel: '',
  tempo: '', bpm: '', musicalKey: '', language: '', lyricsMode: '', lyricsInput: '',
  vocalPresence: '', vocalGender: '', vocalStyle: '', instrumentation: '',
  duration: '', structure: '', sectionLength: '', energyCurve: '',
  referenceArtists: '', useCase: '', videoTypes: [VideoType.ABSTRACT],
  videoStyle: '', visualIntensity: '', visualEvolution: ''
};

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.ONBOARDING);
  const [user, setUser] = useState<UserLocalProfile | null>(null);
  const [history, setHistory] = useState<SongHistoryItem[]>([]);
  const [request, setRequest] = useState<SongRequest>(INITIAL_REQUEST);
  const [explanations, setExplanations] = useState<Record<string, string>>({});
  const [isSuggesting, setIsSuggesting] = useState<Record<string, boolean>>({});
  const [genStatus, setGenStatus] = useState<GenerationStatus | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  const outputRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const savedProfile = localStorage.getItem('musewave_profile');
    const savedHistory = localStorage.getItem('musewave_history');
    if (savedProfile) {
      setUser(JSON.parse(savedProfile));
      setAppState(AppState.HOME);
    }
    if (savedHistory) setHistory(JSON.parse(savedHistory));
  }, []);

  const handleOnboard = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserLocalProfile = {
      user_id: crypto.randomUUID(),
      name: formData.get('name') as string,
      phone_number: formData.get('mobile') as string,
      created_at: Date.now(),
      last_active_at: Date.now()
    };
    localStorage.setItem('musewave_profile', JSON.stringify(profile));
    setUser(profile);
    setAppState(AppState.HOME);
  };

  const handleSuggest = async (field: keyof SongRequest) => {
    setIsSuggesting(prev => ({ ...prev, [field]: true }));
    try {
      const { suggestedValue, explanation } = await getAISuggestion(field, request);
      setRequest(prev => ({ ...prev, [field]: suggestedValue }));
      setExplanations(prev => ({ ...prev, [field]: explanation }));
    } catch (err) {
      console.error(err);
    } finally {
      setIsSuggesting(prev => ({ ...prev, [field]: false }));
    }
  };

  const handleToggleVideoType = (type: VideoType) => {
    setRequest(prev => {
      const exists = prev.videoTypes.includes(type);
      if (exists) {
        if (prev.videoTypes.length === 1) return prev; // Keep at least one
        return { ...prev, videoTypes: prev.videoTypes.filter(t => t !== type) };
      }
      return { ...prev, videoTypes: [...prev.videoTypes, type] };
    });
  };

  const handleGenerate = async () => {
    if (!request.title || !request.description) {
      alert("Please provide at least a title and description.");
      return;
    }

    setGenStatus({ progress: 5, statusText: ItemStatus.PLANNING });

    // Smooth scroll to output area
    setTimeout(() => outputRef.current?.scrollIntoView({ behavior: 'smooth' }), 100);

    try {
      const plan = await createImmutableSongPlan(request);
      setGenStatus({ progress: 25, statusText: ItemStatus.GENERATING });

      const visual = await generatePlaceholderVisual(`${request.videoStyle} ${request.mood} ${request.videoTypes.join(' ')}`);

      await new Promise(r => setTimeout(r, 2000));
      setGenStatus({ progress: 50, statusText: ItemStatus.STITCHING });
      await new Promise(r => setTimeout(r, 1500));
      setGenStatus({ progress: 80, statusText: ItemStatus.RENDERING });
      await new Promise(r => setTimeout(r, 2000));

      const newItem: SongHistoryItem = {
        id: crypto.randomUUID(),
        request: { ...request },
        plan,
        audioUrl: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3",
        videoUrl: visual,
        status: ItemStatus.COMPLETED,
        playbackPosition: 0,
        createdAt: Date.now()
      };

      const newHistory = [newItem, ...history];
      setHistory(newHistory);
      localStorage.setItem('musewave_history', JSON.stringify(newHistory));
      setGenStatus({ progress: 100, statusText: ItemStatus.COMPLETED });
    } catch (err) {
      setGenStatus({ progress: 0, statusText: ItemStatus.FAILED });
      alert(err instanceof Error ? err.message : "Generation failed.");
    }
  };

  const resetApp = () => {
    if (confirm("Reset MuseWave Terminal? This will permanently purge your local signal archives.")) {
      localStorage.clear();
      window.location.reload();
    }
  };

  if (!process.env.API_KEY) {
    return (
      <div className="min-h-screen bg-deep flex items-center justify-center p-20">
        <div className="glass p-12 rounded-[2rem] border border-red-500/20 text-center space-y-4">
          <div className="text-red-500 text-6xl mb-4">⚠️</div>
          <h1 className="text-red-500 font-black text-2xl uppercase tracking-tighter">Configuration error</h1>
          <p className="text-zinc-500 font-mono text-xs uppercase tracking-widest">GOOGLE_API_KEY is missing or invalid.</p>
        </div>
      </div>
    );
  }

  if (appState === AppState.ONBOARDING) {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-deep">
        <div className="glass max-w-lg w-full p-16 rounded-[4rem] shadow-[0_0_120px_rgba(255,77,0,0.15)] space-y-12 border border-white/5 relative overflow-hidden animate-in fade-in zoom-in duration-700">
          <div className="absolute -top-32 -left-32 w-64 h-64 bg-brand/10 blur-[120px] rounded-full"></div>
          <div className="text-center relative z-10 space-y-2">
            <h1 className="text-6xl font-space font-black tracking-tighter text-glow uppercase">MuseWave</h1>
            <p className="text-zinc-600 text-[10px] font-black uppercase tracking-[0.6em] mt-4">Establish Terminal Handshake</p>
          </div>
          <form onSubmit={handleOnboard} className="space-y-10 relative z-10">
            <Input label="Biological Identity" name="name" placeholder="Johnathan Miller" required />
            <Input label="Neural Frequency (Mobile)" name="mobile" placeholder="+1 000-000-0000" type="tel" required />
            <Button fullWidth type="submit" className="h-20 text-xl tracking-[0.3em] uppercase font-black muse-gradient rounded-[2.5rem]">Initiate Connection</Button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex bg-deep font-sans selection:bg-brand selection:text-white">
      {/* LHS Sidebar */}
      <aside className={`fixed h-full bg-[#050505] border-r border-white/5 transition-all duration-700 z-50 ${isSidebarOpen ? 'w-72' : 'w-24'}`}>
        <div className="flex flex-col h-full">
          <div className="p-10 flex items-center justify-between">
            <h2 className={`text-3xl font-space font-black tracking-tighter text-brand uppercase transition-opacity duration-500 ${isSidebarOpen ? 'opacity-100' : 'opacity-0 hidden'}`}>MW</h2>
            <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="w-10 h-10 rounded-full border border-white/5 flex items-center justify-center text-zinc-600 hover:text-brand transition-all hover:bg-white/5">
              {isSidebarOpen ? '❮' : '❯'}
            </button>
          </div>

          <nav className="flex-1 px-6 space-y-4 mt-12">
            <SidebarItem icon="🏠" label="Home" active={appState === AppState.HOME} collapsed={!isSidebarOpen} onClick={() => setAppState(AppState.HOME)} />
            <SidebarItem icon="✨" label="Creative Hub" active={appState === AppState.CREATE} collapsed={!isSidebarOpen} onClick={() => setAppState(AppState.CREATE)} badge={genStatus?.statusText} />
            <SidebarItem icon="📚" label="Archive" active={appState === AppState.DASHBOARD} collapsed={!isSidebarOpen} onClick={() => setAppState(AppState.DASHBOARD)} />
          </nav>

          <div className="p-8 border-t border-white/5 bg-black/40">
            <div className={`flex items-center gap-4 mb-8 transition-all duration-500 ${isSidebarOpen ? 'opacity-100' : 'opacity-0 translate-x-4'}`}>
              <div className="w-12 h-12 rounded-2xl bg-zinc-900 flex items-center justify-center text-sm font-black border border-white/10 text-brand">{user?.name[0]}</div>
              <div className="min-w-0">
                <p className="text-xs font-black truncate uppercase tracking-tighter text-zinc-200">{user?.name}</p>
                <p className="text-[9px] font-bold text-zinc-600 truncate uppercase tracking-widest">{user?.phone_number}</p>
              </div>
            </div>
            <button onClick={resetApp} className="w-full text-[9px] font-black uppercase tracking-[0.3em] text-zinc-700 hover:text-red-500 transition-all text-left px-2 flex items-center gap-2">
              <span className="w-1 h-1 rounded-full bg-zinc-800"></span> Reset Terminal
            </button>
          </div>
        </div>
      </aside>

      {/* Main Container */}
      <main className={`flex-1 transition-all duration-700 ${isSidebarOpen ? 'ml-72' : 'ml-24'}`}>
        <div className="max-w-7xl mx-auto w-full min-h-screen relative">
          {appState === AppState.HOME && <HomePage onStart={() => setAppState(AppState.CREATE)} />}
          {appState === AppState.CREATE && (
            <CreatePage 
              request={request} 
              setRequest={setRequest} 
              onSuggest={handleSuggest} 
              isSuggesting={isSuggesting}
              explanations={explanations}
              onGenerate={handleGenerate}
              genStatus={genStatus}
              outputRef={outputRef}
              history={history}
              onToggleVideoType={handleToggleVideoType}
            />
          )}
          {appState === AppState.DASHBOARD && <DashboardPage history={history} setAppState={setAppState} />}
        </div>
      </main>
    </div>
  );
};

