                  </div>
                  <div className="flex gap-4">
                    <button className="w-16 h-16 rounded-[1.5rem] border border-white/5 bg-white/5 hover:bg-brand hover:text-white transition-all duration-500 flex items-center justify-center text-xl">💾</button>
                    <button className="w-16 h-16 rounded-[1.5rem] border border-white/5 bg-white/5 hover:bg-brand hover:text-white transition-all duration-500 flex items-center justify-center text-xl">🔗</button>
                  </div>
