import { GoogleGenAI, Type } from "@google/genai";
import { SongRequest, ImmutableSongPlan } from "../types";

// Always initialize with process.env.API_KEY directly
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getAISuggestion(field: keyof SongRequest, currentRequest: Partial<SongRequest>): Promise<string> {
  const ai = getAI();
  const context = JSON.stringify(currentRequest);

  const prompt = `You are a world-class AI music producer for MuseWave. 
  Suggest a high-end value for the field: "${field.toString()}".

  CONTEXT: ${context}

  STRICT RULES:
  - Return ONLY the suggested value as a plain string.
  - Do NOT include explanations, quotes, or JSON.
  - Value must be unique, realistic, and production-ready.
  - If field is "title", create a cinematic title.
  - If field is "description", create a creative brief.
  - If field is "genre", suggest a modern style.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text.trim() || "";
  } catch (e) {
    console.error("AI Suggest Error:", e);
    return "";
  }
}

export async function createImmutableSongPlan(request: SongRequest): Promise<ImmutableSongPlan> {
  const ai = getAI();
  const systemPrompt = `Master Architect Unit. Generate an immutable SONG PLAN for duration: ${request.durationSeconds}s.
  The plan must handle BPM, key, and structural segments perfectly.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Create a technical blueprint for: ${JSON.stringify(request)}`,
    config: {
      systemInstruction: systemPrompt,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          bpm: { type: Type.NUMBER },
          key: { type: Type.STRING },
          scale: { type: Type.STRING },
          instrumentPalette: { type: Type.ARRAY, items: { type: Type.STRING } },
          sections: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                startTime: { type: Type.NUMBER },
                endTime: { type: Type.NUMBER },
                label: { type: Type.STRING },
                energy: { type: Type.NUMBER },
                description: { type: Type.STRING }
              }
            }
          },
          macroEnergyCurve: { type: Type.ARRAY, items: { type: Type.NUMBER } },
          textureEvolutionStrategy: { type: Type.STRING }
        },
        required: ["bpm", "key", "scale", "instrumentPalette", "sections", "macroEnergyCurve", "textureEvolutionStrategy"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("Failed to generate plan");
  return JSON.parse(text);
}

export async function generateVisualReference(prompt: string): Promise<string> {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: `Cinematic high-fidelity visual art, loopable aesthetic, non-fatiguing, high contrast: ${prompt}` }] }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return "https://images.unsplash.com/photo-1614613535308-eb5fbd3d2c17?auto=format&fit=crop&q=80&w=1000";
}

import React, { useState, useEffect, useRef } from 'react';
import { 
  AppState, 
  UserLocalProfile, 
  SongRequest, 
  VideoType, 
  SongRecord, 
  ItemStatus, 
  VocalMode,
  GenerationState 
} from './types';
import { Button } from './components/Button';
import { Input } from './components/Input';
import { getAISuggestion, createImmutableSongPlan, generateVisualReference } from './services/geminiService';

const INITIAL_REQUEST: SongRequest = {
  title: '',
  description: '',
  duration: '00:03:00',
  durationSeconds: 180,
  energyCurve: '',
  structure: '',
  genre: '',
  subGenre: '',
  bpm: '',
  musicalKey: '',
  vocalMode: VocalMode.INSTRUMENTAL,
  vocalTheme: '',
  vocalStyle: '',
  styleReferences: '',
  useCase: '',
  videoTypes: [VideoType.ABSTRACT],
  videoStyle: '',
  visualIntensity: 'Medium',
  visualEvolution: ''
};

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.ONBOARDING);
  const [user, setUser] = useState<UserLocalProfile | null>(null);
  const [library, setLibrary] = useState<SongRecord[]>([]);
  const [request, setRequest] = useState<SongRequest>(INITIAL_REQUEST);
  const [genState, setGenState] = useState<GenerationState>({ isGenerating: false, currentStatus: ItemStatus.IDLE, progress: 0 });
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [activeTab, setActiveTab] = useState<AppState>(AppState.HOME);

  const outputRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const savedProfile = localStorage.getItem('musewave_profile');
    const savedLibrary = localStorage.getItem('musewave_library');
    if (savedProfile) {
      setUser(JSON.parse(savedProfile));
      setAppState(AppState.HOME);
    }
    if (savedLibrary) setLibrary(JSON.parse(savedLibrary));
  }, []);

  const handleOnboard = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserLocalProfile = {
      user_id: crypto.randomUUID(),
      name: formData.get('name') as string,
      phone_number: formData.get('mobile') as string,
      created_at: Date.now(),
      last_active_at: Date.now()
    };
    localStorage.setItem('musewave_profile', JSON.stringify(profile));
    setUser(profile);
    setAppState(AppState.HOME);
    setActiveTab(AppState.HOME);
  };

  const handleSuggest = async (field: keyof SongRequest) => {
    const val = await getAISuggestion(field, request);
    if (val) setRequest(prev => ({ ...prev, [field]: val }));
  };

  const toggleVideoType = (type: VideoType) => {
    setRequest(prev => {
      const exists = prev.videoTypes.includes(type);
      if (exists) {
        if (prev.videoTypes.length === 1) return prev;
        return { ...prev, videoTypes: prev.videoTypes.filter(t => t !== type) };
      }
      return { ...prev, videoTypes: [...prev.videoTypes, type] };
    });
  };

  const handleGenerate = async () => {
    if (!request.title || !request.description) return;

    setGenState({ isGenerating: true, currentStatus: ItemStatus.PLANNING, progress: 10 });
    setTimeout(() => outputRef.current?.scrollIntoView({ behavior: 'smooth' }), 100);

    try {
      const plan = await createImmutableSongPlan(request);
      setGenState(prev => ({ ...prev, currentStatus: ItemStatus.GENERATING_AUDIO, progress: 40 }));

      const visualUrl = await generateVisualReference(`${request.videoStyle} ${request.mood || request.description}`);

      // Simulate segmentation logic
      await new Promise(r => setTimeout(r, 2000));
      setGenState(prev => ({ ...prev, currentStatus: ItemStatus.STITCHING, progress: 60 }));
      await new Promise(r => setTimeout(r, 1500));
      setGenState(prev => ({ ...prev, currentStatus: ItemStatus.GENERATING_VIDEO, progress: 85 }));
      await new Promise(r => setTimeout(r, 2000));

      const newSong: SongRecord = {
        id: crypto.randomUUID(),
        request: { ...request },
        plan,
        audioUrl: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3",
        videos: request.videoTypes.map(type => ({ type, url: visualUrl, status: ItemStatus.COMPLETED })),
        status: ItemStatus.COMPLETED,
        createdAt: Date.now(),
        lastPlaybackPosition: 0
      };

      const newLibrary = [newSong, ...library];
      setLibrary(newLibrary);
      localStorage.setItem('musewave_library', JSON.stringify(newLibrary));
      setGenState({ isGenerating: false, currentStatus: ItemStatus.COMPLETED, progress: 100, activeSongId: newSong.id });
    } catch (e) {
      setGenState({ isGenerating: false, currentStatus: ItemStatus.FAILED, progress: 0 });
      alert("Generation failed. Check kernel logs.");
    }
  };

  const resetApp = () => {
    if (confirm("Purge all terminal data?")) {
      localStorage.clear();
      window.location.reload();
    }
  };

  if (!process.env.API_KEY) {
    return <div className="p-20 text-red-500 font-black text-center text-2xl uppercase">Configuration error: GOOGLE_API_KEY is missing or invalid.</div>;
  }

  if (appState === AppState.ONBOARDING) {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-deep">
        <div className="glass max-w-lg w-full p-16 rounded-[4rem] border border-white/5 space-y-12 shadow-[0_0_150px_rgba(255,77,0,0.1)]">
          <div className="text-center">
            <h1 className="text-6xl font-space font-black tracking-tighter text-glow uppercase">MuseWave</h1>
            <p className="text-zinc-600 text-[10px] font-black uppercase tracking-[0.6em] mt-4">Terminal Handshake required</p>
          </div>
          <form onSubmit={handleOnboard} className="space-y-8">
            <Input label="Biological Identity" name="name" placeholder="Johnathan Miller" required />
            <Input label="Mobile Neural Link" name="mobile" placeholder="+1 000-000-0000" type="tel" required />
            <Button fullWidth type="submit" className="h-20 text-xl tracking-[0.3em] font-black muse-gradient rounded-[2rem]">Initiate Link</Button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex bg-deep font-sans">
      {/* LHS MENU BAR */}
      <aside className={`fixed h-full bg-[#050505] border-r border-white/5 transition-all duration-500 z-50 ${isSidebarOpen ? 'w-72' : 'w-24'}`}>
        <div className="flex flex-col h-full">
          <div className="p-10 flex items-center justify-between">
            <h2 className={`text-3xl font-space font-black tracking-tighter text-brand uppercase ${isSidebarOpen ? 'opacity-100' : 'opacity-0 hidden'}`}>MW</h2>
            <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="w-10 h-10 rounded-full border border-white/5 flex items-center justify-center text-zinc-600 hover:text-brand transition-all">
              {isSidebarOpen ? '❮' : '❯'}
            </button>
          </div>
          <nav className="flex-1 px-6 space-y-4 mt-12">
            <SidebarItem icon="🏠" label="Home" active={activeTab === AppState.HOME} collapsed={!isSidebarOpen} onClick={() => setActiveTab(AppState.HOME)} />
            <SidebarItem icon="✨" label="Create Music" active={activeTab === AppState.CREATE} collapsed={!isSidebarOpen} onClick={() => setActiveTab(AppState.CREATE)} badge={genState.isGenerating ? genState.currentStatus : undefined} />
            <SidebarItem icon="📚" label="Dashboard" active={activeTab === AppState.DASHBOARD} collapsed={!isSidebarOpen} onClick={() => setActiveTab(AppState.DASHBOARD)} />
          </nav>
          <div className="p-8 border-t border-white/5 bg-black/40">
            <div className={`flex items-center gap-4 mb-8 ${isSidebarOpen ? 'opacity-100' : 'opacity-0'}`}>
              <div className="w-10 h-10 rounded-2xl bg-zinc-900 flex items-center justify-center text-xs font-black border border-white/10 text-brand">{user?.name[0]}</div>
              <div className="min-w-0">
                <p className="text-xs font-black truncate uppercase text-zinc-200">{user?.name}</p>
                <p className="text-[9px] font-bold text-zinc-600 truncate uppercase">{user?.phone_number}</p>
              </div>
            </div>
            <button onClick={resetApp} className="w-full text-[9px] font-black uppercase tracking-[0.3em] text-zinc-800 hover:text-red-500 transition-all text-left px-2">Reset Terminal</button>
          </div>
        </div>
      </aside>

      {/* MAIN CONTENT AREA */}
      <main className={`flex-1 transition-all duration-500 ${isSidebarOpen ? 'ml-72' : 'ml-24'}`}>
        <div className="max-w-7xl mx-auto w-full min-h-screen">
          {activeTab === AppState.HOME && <HomePage onStart={() => setActiveTab(AppState.CREATE)} />}
          {activeTab === AppState.CREATE && (
            <CreatePage 
              request={request} 
              setRequest={setRequest} 
              onSuggest={handleSuggest} 
              onGenerate={handleGenerate}
              onToggleVideoType={toggleVideoType}
              genState={genState}
              outputRef={outputRef}
              lastSong={library.find(s => s.id === genState.activeSongId)}
            />
          )}
          {activeTab === AppState.DASHBOARD && <DashboardPage library={library} onNavigateCreate={() => setActiveTab(AppState.CREATE)} />}
        </div>
      </main>
    </div>
  );
};

