import { GoogleGenAI, Type } from "@google/genai";
import { SongRequest, ImmutableSongPlan } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

/**
 * AI Suggest: Generates field-specific, context-aware values.
 * Strictly adheres to "Value ONLY" output rule.
 */
export async function getAISuggestion(field: keyof SongRequest, currentRequest: Partial<SongRequest>): Promise<string> {
  if (!process.env.API_KEY) throw new Error("GOOGLE_API_KEY is missing or invalid.");

  const context = JSON.stringify(currentRequest);
  const prompt = `You are a high-end music production consultant for MuseWave.
  Suggest a UNIQUE, realistic value for the field: "${field.toString()}".

  CONTEXT (Current Configuration): ${context}

  STRICT RULES:
  - Return ONLY the suggested value as a plain string.
  - No explanations, no markdown, no quotes, no conversational filler.
  - If field is "title", generate a cinematic track title.
  - If field is "description", generate a 1-2 sentence creative brief.
  - If field is "energyCurve", describe the rise and fall of intensity.
  - Never repeat suggestions verbatim from context.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text.trim();
  } catch (error) {
    console.error("AI Suggest failure:", error);
    return "Dynamic Error Sync";
  }
}

/**
 * Immutable Song Plan: Creates the structural backbone for the song.
 */
export async function createProductionPlan(request: SongRequest): Promise<ImmutableSongPlan> {
  const prompt = `Act as the Master Architect for MuseWave. Generate an immutable production plan for a ${request.durationSeconds}s track.
  Title: ${request.title}
  Description: ${request.description}
  Genre: ${request.genre}
  Energy Curve: ${request.energyCurve}

  The plan must split the duration into logical segments.
  Max duration supported is 20 hours. For durations > 10m, ensure 10m segment logic is consistent.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          bpm: { type: Type.NUMBER },
          key: { type: Type.STRING },
          scale: { type: Type.STRING },
          instrumentPalette: { type: Type.ARRAY, items: { type: Type.STRING } },
          sections: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                startTime: { type: Type.NUMBER },
                endTime: { type: Type.NUMBER },
                label: { type: Type.STRING },
                energy: { type: Type.NUMBER },
                description: { type: Type.STRING }
              },
              required: ["startTime", "endTime", "label", "energy", "description"]
            }
          },
          macroEnergyCurve: { type: Type.ARRAY, items: { type: Type.NUMBER } },
          textureEvolutionStrategy: { type: Type.STRING }
        },
        required: ["bpm", "key", "scale", "instrumentPalette", "sections", "macroEnergyCurve", "textureEvolutionStrategy"]
      }
    }
  });

  return JSON.parse(response.text);
}

/**
 * Visual Render Synthesis: Generates image references based on video type and song mood.
 */
export async function synthesizeVisual(prompt: string): Promise<string> {
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: `High-fidelity, loopable cinematic aesthetic for a music video. Style: ${prompt}. Cinematic lighting, ultra-wide, moody.` }] }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return "https://images.unsplash.com/photo-1614613535308-eb5fbd3d2c17?auto=format&fit=crop&q=80&w=1000";
}

import React, { useState, useEffect, useRef } from 'react';
import { 
  AppState, 
  UserLocalProfile, 
  SongRequest, 
  VideoType, 
  SongRecord, 
  ItemStatus, 
  VocalMode,
  GlobalProductionState 
} from './types';
import { Button } from './components/Button';
import { Input } from './components/Input';
import { getAISuggestion, createProductionPlan, synthesizeVisual } from './services/geminiService';

const INITIAL_REQUEST: SongRequest = {
  title: '', description: '',
  durationSeconds: 180, energyCurve: '', structure: '',
  genre: '', subGenre: '', bpm: '', musicalKey: '',
  vocalMode: VocalMode.INSTRUMENTAL, vocalTheme: '', vocalStyle: '',
  styleReferences: '', useCase: '',
  videoTypes: [VideoType.ABSTRACT], videoStyle: '',
  visualIntensity: 'Medium', visualEvolution: ''
};

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.ONBOARDING);
  const [user, setUser] = useState<UserLocalProfile | null>(null);
  const [library, setLibrary] = useState<SongRecord[]>([]);
  const [request, setRequest] = useState<SongRequest>(INITIAL_REQUEST);
  const [production, setProduction] = useState<GlobalProductionState>({ isGenerating: false, currentProgress: 0, statusText: ItemStatus.IDLE });
  const [activePage, setActivePage] = useState<AppState>(AppState.HOME);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  const outputRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const profile = localStorage.getItem('musewave_profile');
    const lib = localStorage.getItem('musewave_library');
    if (profile) {
      setUser(JSON.parse(profile));
      setAppState(AppState.HOME);
    }
    if (lib) setLibrary(JSON.parse(lib));
  }, []);

  const handleOnboard = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const fd = new FormData(e.currentTarget);
    const prof: UserLocalProfile = {
      user_id: crypto.randomUUID(),
      name: fd.get('name') as string,
      phone_number: fd.get('mobile') as string,
      created_at: Date.now(),
      last_active_at: Date.now()
    };
    localStorage.setItem('musewave_profile', JSON.stringify(prof));
    setUser(prof);
    setAppState(AppState.HOME);
    setActivePage(AppState.HOME);
  };

  const handleSuggest = async (field: keyof SongRequest) => {
    const val = await getAISuggestion(field, request);
    setRequest(prev => ({ ...prev, [field]: val }));
  };

  const handleGenerate = async () => {
    if (!request.title || !request.description) {
      alert("Terminal requires Title and Description to initiate signal.");
      return;
    }

    setProduction({ isGenerating: true, statusText: ItemStatus.PLANNING, currentProgress: 10 });
    setTimeout(() => outputRef.current?.scrollIntoView({ behavior: 'smooth' }), 100);

    try {
      const plan = await createProductionPlan(request);
      setProduction(prev => ({ ...prev, statusText: ItemStatus.GENERATING_AUDIO, currentProgress: 40 }));

      const visualUrl = await synthesizeVisual(`${request.videoStyle} ${request.genre} ${request.mood || ''}`);

      // Artificial delay for synthesis feel
      await new Promise(r => setTimeout(r, 2000));
      setProduction(prev => ({ ...prev, statusText: ItemStatus.STITCHING, currentProgress: 65 }));
      await new Promise(r => setTimeout(r, 1500));
      setProduction(prev => ({ ...prev, statusText: ItemStatus.RENDERING_VIDEO, currentProgress: 90 }));
      await new Promise(r => setTimeout(r, 2000));

      const newRecord: SongRecord = {
        id: crypto.randomUUID(),
        request: { ...request },
        plan,
        audioUrl: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3",
        videos: request.videoTypes.map(vt => ({ type: vt, url: visualUrl, status: ItemStatus.COMPLETED })),
        status: ItemStatus.COMPLETED,
        createdAt: Date.now(),
        lastPlaybackPosition: 0
      };

      const newLib = [newRecord, ...library];
      setLibrary(newLib);
      localStorage.setItem('musewave_library', JSON.stringify(newLib));
      setProduction({ isGenerating: false, statusText: ItemStatus.COMPLETED, currentProgress: 100, activeSongId: newRecord.id });
    } catch (e) {
      setProduction({ isGenerating: false, statusText: ItemStatus.FAILED, currentProgress: 0 });
      alert("Kernel Fault: " + (e as Error).message);
    }
  };

  const resetApp = () => {
    if (confirm("Reset MuseWave Terminal? Signal archive will be purged.")) {
      localStorage.clear();
      window.location.reload();
    }
  };

  if (!process.env.API_KEY) {
    return <div className="p-20 text-red-500 font-black text-center text-xl uppercase tracking-widest">Configuration error: GOOGLE_API_KEY is missing or invalid.</div>;
  }

  if (appState === AppState.ONBOARDING) {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-deep">
        <div className="glass max-w-lg w-full p-16 rounded-[4rem] border border-white/5 space-y-12">
          <div className="text-center space-y-2">
            <h1 className="text-6xl font-space font-black tracking-tighter text-glow uppercase">MuseWave</h1>
            <p className="text-zinc-600 text-[10px] font-black uppercase tracking-[0.6em]">Initialize Link</p>
          </div>
          <form onSubmit={handleOnboard} className="space-y-8">
            <Input label="Identity Name" name="name" placeholder="Johnathan Miller" required />
            <Input label="Mobile Freq (Neural Link)" name="mobile" placeholder="+1 000-000-0000" type="tel" required />
            <Button fullWidth type="submit" className="h-20 text-lg font-black muse-gradient rounded-[2rem]">Access Terminal</Button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex bg-deep font-sans">
      {/* LHS Sidebar */}
      <aside className={`fixed h-full bg-[#050505] border-r border-white/5 transition-all duration-500 z-50 ${isSidebarOpen ? 'w-72' : 'w-24'}`}>
        <div className="flex flex-col h-full">
          <div className="p-10 flex items-center justify-between">
            <h2 className={`text-3xl font-space font-black tracking-tighter text-brand uppercase ${isSidebarOpen ? 'opacity-100' : 'opacity-0 hidden'}`}>MW</h2>
            <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="text-zinc-700 hover:text-brand transition-colors text-xl">
              {isSidebarOpen ? '❮' : '❯'}
            </button>
          </div>
          <nav className="flex-1 px-6 space-y-4 mt-12">
            <SidebarItem icon="🏠" label="Home" active={activePage === AppState.HOME} collapsed={!isSidebarOpen} onClick={() => setActivePage(AppState.HOME)} />
            <SidebarItem icon="✨" label="Create Music" active={activePage === AppState.CREATE} collapsed={!isSidebarOpen} onClick={() => setActivePage(AppState.CREATE)} badge={production.isGenerating ? production.statusText : undefined} />
            <SidebarItem icon="📚" label="Dashboard" active={activePage === AppState.DASHBOARD} collapsed={!isSidebarOpen} onClick={() => setActivePage(AppState.DASHBOARD)} />
          </nav>
          <div className="p-8 border-t border-white/5 bg-black/20">
            <div className={`flex items-center gap-4 mb-8 ${isSidebarOpen ? 'opacity-100' : 'opacity-0'}`}>
              <div className="w-10 h-10 rounded-xl bg-zinc-900 flex items-center justify-center text-xs font-black border border-white/10 text-brand">{user?.name[0]}</div>
              <div className="min-w-0">
                <p className="text-xs font-black truncate text-zinc-300">{user?.name}</p>
                <p className="text-[9px] font-bold text-zinc-600 truncate">{user?.phone_number}</p>
              </div>
            </div>
            <button onClick={resetApp} className="w-full text-[9px] font-black uppercase text-zinc-800 hover:text-red-500 text-left px-2">Reset</button>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className={`flex-1 transition-all duration-500 ${isSidebarOpen ? 'ml-72' : 'ml-24'}`}>
        <div className="max-w-7xl mx-auto w-full min-h-screen">
          {activePage === AppState.HOME && <HomePage onStart={() => setActivePage(AppState.CREATE)} />}
          {activePage === AppState.CREATE && (
            <CreatePage 
              request={request} setRequest={setRequest} 
              onSuggest={handleSuggest} onGenerate={handleGenerate} 
              production={production} outputRef={outputRef}
              lastSong={library.find(s => s.id === production.activeSongId)}
            />
          )}
          {activePage === AppState.DASHBOARD && <DashboardPage library={library} onNavigate={() => setActivePage(AppState.CREATE)} />}
        </div>
      </main>
    </div>
  );
};

