      <Button onClick={onStart} className="h-24 px-16 text-xl tracking-[0.3em] rounded-[2.5rem]">Create Your First Track</Button>
    </div>
    <div className="grid grid-cols-1 md:grid-cols-3 gap-16 pt-24 border-t border-white/5">
      <div className="space-y-4">
        <div className="text-6xl mb-6">⚡</div>
        <h3 className="text-2xl font-space font-black uppercase tracking-tighter">1. Describe</h3>
        <p className="text-zinc-500 leading-relaxed font-medium">Define your sonic atmosphere using neural suggestions.</p>
      </div>
      <div className="space-y-4">
        <div className="text-6xl mb-6">👁️</div>
        <h3 className="text-2xl font-space font-black uppercase tracking-tighter">2. Synthesize</h3>
        <p className="text-zinc-500 leading-relaxed font-medium">Real-time PCM synthesis into hi-fidelity WAV master files.</p>
      </div>
      <div className="space-y-4">
        <div className="text-6xl mb-6">⏳</div>
        <h3 className="text-2xl font-space font-black uppercase tracking-tighter">3. Download</h3>
        <p className="text-zinc-500 leading-relaxed font-medium">Export master WAV audio and multiple cinema-grade visual layers.</p>
      </div>
    </div>
  </div>
);

const CreatePage = ({ request, setRequest, onSuggest, onGenerate, production, lastSong, explanations, isSuggesting, formatSeconds }: any) => {
  const [expandedGroups, setExpandedGroups] = useState<number[]>([1]);
  const toggleGroup = (id: number) => setExpandedGroups(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);

  const locked = production.isGenerating;

  return (
    <div className="flex h-screen overflow-hidden">
      {/* LEFT: INPUT PANEL */}
      <div className="flex-1 overflow-y-auto p-16 space-y-10 scroll-smooth pb-60">
        <div className="border-b border-white/5 pb-8">
          <h2 className="text-5xl font-space font-black tracking-tighter uppercase">Creative Workspace</h2>
          <p className="text-zinc-600 font-bold uppercase text-[10px] tracking-[0.5em] mt-2">Neural Parameter Sync</p>
        </div>

        <div className="space-y-6">
          <InputGroup label="Core Idea" active={expandedGroups.includes(1)} onClick={() => toggleGroup(1)}>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-6">
              <Input label="Song Title" placeholder="Linear Field" value={request.title} onChange={e => setRequest({...request, title: e.target.value})} onSuggest={() => onSuggest('title', "Used as the track's display name.")} isSuggesting={isSuggesting['title']} helperText={explanations['title'] || "Used as the track's display name."} disabled={locked} />
              <Input label="Song Idea" placeholder="Dark melodic techno..." isTextArea value={request.description} onChange={e => setRequest({...request, description: e.target.value})} onSuggest={() => onSuggest('description', "Defines the overall creative direction.")} isSuggesting={isSuggesting['description']} helperText={explanations['description'] || "Defines the overall creative direction."} disabled={locked} />
            </div>
          </InputGroup>

          <InputGroup label="Musical Shape" active={expandedGroups.includes(2)} onClick={() => toggleGroup(2)}>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-6">
              <div className="space-y-4">
                <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest text-zinc-700">
                  <span>Duration</span>
                  <span className="text-brand font-space">{formatSeconds(request.durationSeconds)}</span>
                </div>
                <input type="range" min="30" max="72000" step="30" className="w-full h-2 bg-zinc-900 rounded-full accent-brand cursor-pointer" value={request.durationSeconds} onChange={e => setRequest({...request, durationSeconds: parseInt(e.target.value)})} disabled={locked} />
                <p className="text-[9px] text-zinc-600 font-bold uppercase tracking-widest pl-2">Controls total length (up to 20h).</p>
              </div>
              <Input label="Energy Curve" placeholder="Slow rise → long steady phase..." value={request.energyCurve} onChange={e => setRequest({...request, energyCurve: e.target.value})} onSuggest={() => onSuggest('energyCurve', "Defines dynamic movement.")} isSuggesting={isSuggesting['energyCurve']} helperText={explanations['energyCurve'] || "Defines dynamic movement over time."} disabled={locked} />
              <Input label="Structure" placeholder="Intro → Build → Peak → Outro" value={request.structure} onChange={e => setRequest({...request, structure: e.target.value})} onSuggest={() => onSuggest('structure', "Defines how the song unfolds.")} isSuggesting={isSuggesting['structure']} helperText={explanations['structure'] || "Defines how the song unfolds."} disabled={locked} />
            </div>
          </InputGroup>

          <InputGroup label="Sound & Rhythm" active={expandedGroups.includes(3)} onClick={() => toggleGroup(3)}>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-6">
              <Input label="Genre" placeholder="Techno" value={request.genre} onChange={e => setRequest({...request, genre: e.target.value})} onSuggest={() => onSuggest('genre', "Sets the foundational style.")} isSuggesting={isSuggesting['genre']} helperText={explanations['genre'] || "Sets the foundational style."} disabled={locked} />
              <Input label="Sub-Genre" placeholder="Melodic Techno" value={request.subGenre} onChange={e => setRequest({...request, subGenre: e.target.value})} onSuggest={() => onSuggest('subGenre', "Adds stylistic specificity.")} isSuggesting={isSuggesting['subGenre']} helperText={explanations['subGenre'] || "Adds stylistic specificity."} disabled={locked} />
              <div className="grid grid-cols-2 gap-4">
                <Input label="BPM" placeholder="124" value={request.bpm} onChange={e => setRequest({...request, bpm: e.target.value})} onSuggest={() => onSuggest('bpm', "Locks rhythmic center.")} isSuggesting={isSuggesting['bpm']} helperText={explanations['bpm'] || "Locks rhythm."} disabled={locked} />
                <Input label="Key" placeholder="A Minor" value={request.musicalKey} onChange={e => setRequest({...request, musicalKey: e.target.value})} onSuggest={() => onSuggest('musicalKey', "Locks tonal center.")} isSuggesting={isSuggesting['musicalKey']} helperText={explanations['musicalKey'] || "Locks key."} disabled={locked} />
              </div>
            </div>
          </InputGroup>

          <InputGroup label="Vocals & Lyrics" active={expandedGroups.includes(4)} onClick={() => toggleGroup(4)}>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-6">
              <div className="space-y-4">
                <label className="text-[10px] font-black uppercase tracking-widest text-zinc-700">Vocal Mode</label>
                <div className="flex gap-2">
                  {Object.values(VocalMode).map(m => (
                    <button key={m} onClick={() => setRequest({...request, vocalMode: m})} className={`flex-1 py-3 rounded-xl border text-[9px] font-black uppercase tracking-widest transition-all ${request.vocalMode === m ? 'bg-brand/10 border-brand text-white' : 'bg-surface border-white/5 text-zinc-700 hover:border-zinc-500'}`} disabled={locked}>{m}</button>
                  ))}
                </div>
                <p className="text-[9px] text-zinc-600 font-bold uppercase tracking-widest pl-2">Defines vocal usage.</p>
              </div>
              <Input label="Lyrics / Theme" placeholder="Abstract phrases..." value={request.vocalTheme} onChange={e => setRequest({...request, vocalTheme: e.target.value})} onSuggest={() => onSuggest('vocalTheme', "Guides vocal phrasing.")} isSuggesting={isSuggesting['vocalTheme']} helperText={explanations['vocalTheme'] || "Guides vocal phrasing."} disabled={locked} />
            </div>
          </InputGroup>

