            <div className="space-y-8 pt-6">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                {Object.values(VideoType).map(vt => {
                  const active = request.videoTypes.includes(vt);
                  return (
                    <button key={vt} onClick={() => setRequest(prev => ({ ...prev, videoTypes: active ? (prev.videoTypes.length > 1 ? prev.videoTypes.filter(t => t !== vt) : prev.videoTypes) : [...prev.videoTypes, vt] }))} className={`py-6 rounded-2xl border-2 text-[10px] font-black uppercase tracking-widest transition-all ${active ? 'bg-brand/10 border-brand text-white' : 'bg-surface border-white/5 text-zinc-800'}`} disabled={locked}>
                      <div className="text-2xl mb-2 opacity-60">{vt === VideoType.ABSTRACT ? '🌀' : vt === VideoType.LYRICAL ? '🖋️' : '🎬'}</div>
