              <Input label="Video Style" placeholder="Abstract neon geometry..." value={request.videoStyle} onChange={e => setRequest({...request, videoStyle: e.target.value})} onSuggest={() => onSuggest('videoStyle', "Defines visual aesthetic.")} isSuggesting={isSuggesting['videoStyle']} helperText={explanations['videoStyle'] || "Defines visual aesthetic."} disabled={locked} />
