                <div className="aspect-video bg-black rounded-[3rem] overflow-hidden border border-white/5 relative group">
                  <img src={lastSong?.videos[0].url} className="w-full h-full object-cover opacity-60 group-hover:scale-105 transition-all duration-[3s]" />
                  <div className="absolute inset-0 flex items-center justify-center">
                    <button className="w-20 h-20 bg-white text-black rounded-full flex items-center justify-center text-3xl shadow-2xl hover:bg-brand hover:text-white transition-all">▶</button>
                  </div>
                </div>
                <div className="space-y-6">
                  <h2 className="text-5xl font-space font-black uppercase tracking-tighter leading-none">{lastSong?.request.title}</h2>
                  <div className="grid grid-cols-2 gap-8 border-y border-white/5 py-10 my-6">
                    <div>
                      <span className="block text-[10px] font-black text-zinc-800 uppercase tracking-widest mb-1">Length</span>
                      <span className="text-2xl font-black font-space text-zinc-300 tracking-tighter">{formatSeconds(lastSong?.request.durationSeconds || 0)}</span>
                    </div>
                    <div>
                      <span className="block text-[10px] font-black text-zinc-800 uppercase tracking-widest mb-1">Status</span>
                      <span className="text-2xl font-black font-space text-brand tracking-tighter">FINALIZED</span>
                    </div>
                  </div>
                  <audio controls src={lastSong?.audioUrl} className="w-full mb-6 accent-brand" />
                  <div className="space-y-4">
                    <Button fullWidth variant="primary" className="h-16 rounded-2xl text-[10px]">Download Master WAV</Button>
                    <div className="flex gap-4">
                      <Button variant="outline" className="flex-1 h-14 rounded-xl text-[9px]">Regenerate Var</Button>
                      <Button variant="outline" className="flex-1 h-14 rounded-xl text-[9px]" onClick={() => setActivePage(AppState.DASHBOARD)}>Library</Button>
                    </div>
                  </div>
                </div>
              </div>
            )}
          </div>
        ) : (
          <div className="h-full flex flex-col items-center justify-center text-center space-y-8 opacity-20 grayscale">
            <div className="text-[10rem]">📀</div>
            <p className="text-xl font-space italic max-w-xs mx-auto">Your generated music and videos will appear here.</p>
          </div>
        )}
      </div>
    </div>
  );
};

