  <div className={`transition-all duration-500 rounded-[2.5rem] border ${active ? 'border-brand/40 bg-white/[0.02] p-8' : 'border-white/5 p-6 hover:bg-white/[0.01]'}`}>
    <button onClick={onClick} className="w-full flex justify-between items-center group">
      <h3 className={`text-xl font-black uppercase tracking-[0.2em] transition-colors ${active ? 'text-brand' : 'text-zinc-600 group-hover:text-zinc-400'}`}>{label}</h3>
      <span className={`text-xl transition-transform duration-500 ${active ? 'rotate-180 text-brand' : 'text-zinc-800'}`}>▼</span>
    </button>
    {active && children}
  </div>
);

const DashboardPage = ({ library, onNavigate, formatSeconds }: any) => (
  <div className="p-24 space-y-32">
    <div className="flex items-end justify-between border-b border-white/5 pb-20">
