{
  "name": "MuseWave",
  "description": "Standalone AI music + video generation suite designed for extreme durations and high-performance focus soundscapes.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import { GoogleGenAI, Type } from "@google/genai";
import { SongRequest, ImmutableSongPlan } from "../types";

// Always initialize with the environment key for general tasks
const getAi = () => new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

/**
 * AI Suggest: Generates field-specific, context-aware values.
 */
export async function getAISuggestion(field: keyof SongRequest, currentRequest: Partial<SongRequest>): Promise<string> {
  const context = JSON.stringify(currentRequest);
  const prompt = `You are an elite music producer for MuseWave.
  Suggest a UNIQUE, realistic value for the field: "${field.toString()}".

  CONTEXT (Current Configuration): ${context}

  STRICT RULES:
  - Return ONLY the suggested value as a plain string.
  - No explanations, no markdown, no quotes, no conversational filler.
  - If field is "title", generate a cinematic track title.
  - If field is "description", generate a short creative brief.
  - If field is "genre", suggest a trending modern genre.
  - Never repeat suggestions verbatim from context.`;

  try {
    const ai = getAi();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text.trim();
  } catch (error) {
    console.error("AI Suggest failure:", error);
    return "Neural Pulse";
  }
}

/**
 * Immutable Song Plan: Creates the structural backbone for the song.
 */
export async function createProductionPlan(request: SongRequest): Promise<ImmutableSongPlan> {
  const ai = getAi();
  const prompt = `Generate a high-level musical structure for a ${request.durationSeconds}s track.
  Genre: ${request.genre}
  Title: ${request.title}
  Description: ${request.description}

  Split the duration into 30s-60s segments. Ensure BPM and Key are fixed.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          bpm: { type: Type.NUMBER },
          key: { type: Type.STRING },
          scale: { type: Type.STRING },
          instrumentPalette: { type: Type.ARRAY, items: { type: Type.STRING } },
          sections: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                startTime: { type: Type.NUMBER },
                endTime: { type: Type.NUMBER },
                label: { type: Type.STRING },
                energy: { type: Type.NUMBER },
                description: { type: Type.STRING }
              },
              required: ["startTime", "endTime", "label", "energy", "description"]
            }
          },
          macroEnergyCurve: { type: Type.ARRAY, items: { type: Type.NUMBER } },
          textureEvolutionStrategy: { type: Type.STRING }
        },
        required: ["bpm", "key", "scale", "instrumentPalette", "sections", "macroEnergyCurve", "textureEvolutionStrategy"]
      }
    }
  });

  return JSON.parse(response.text);
}

/**
 * Video Generation using Veo 3.1
 * Returns a URL to the generated MP4 file.
 */
export async function generateVeoVideo(prompt: string): Promise<string> {
  // Use the API key provided in the environment (Veo requires paid key handle via UI elsewhere)
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: `Cinematic music video background, high fidelity, 4K, 24fps. Visual style: ${prompt}`,
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: '16:9'
    }
  });

  while (!operation.done) {
    // Wait for 10 seconds before polling again as per guidelines
    await new Promise(resolve => setTimeout(resolve, 10000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!downloadLink) {
    throw new Error("Video generation failed: No URI returned.");
  }

  // Fetch the video bytes using the API key
  const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  if (!response.ok) {
    throw new Error(`Failed to download video: ${response.statusText}`);
  }

  const blob = await response.blob();
  return URL.createObjectURL(blob);
}

/**
 * MuseWave High-Fidelity Audio Synthesis Engine
 * Generates valid WAV files with layered synthesis to provide a "real" musical experience.
 */

export async function generateSynthesizedAudio(durationSeconds: number): Promise<string> {
  const sampleRate = 44100;
  const numChannels = 2;
  const bitsPerSample = 16;
  const byteRate = sampleRate * numChannels * (bitsPerSample / 8);
  const blockAlign = numChannels * (bitsPerSample / 8);
  const dataSize = Math.floor(durationSeconds * byteRate);
  const fileSize = 44 + dataSize;

  const buffer = new ArrayBuffer(fileSize);
  const view = new DataView(buffer);

  /* RIFF identifier */
  writeString(view, 0, 'RIFF');
  /* File length */
  view.setUint32(4, fileSize - 8, true);
  /* RIFF type */
  writeString(view, 8, 'WAVE');
  /* Format chunk identifier */
  writeString(view, 12, 'fmt ');
  /* Format chunk length */
  view.setUint32(16, 16, true);
  /* Sample format (1 is PCM) */
  view.setUint16(20, 1, true);
  /* Channel count */
  view.setUint16(22, numChannels, true);
  /* Sample rate */
  view.setUint32(24, sampleRate, true);
  /* Byte rate */
  view.setUint32(28, byteRate, true);
  /* Block align */
  view.setUint16(32, blockAlign, true);
  /* Bits per sample */
  view.setUint16(34, bitsPerSample, true);
  /* Data chunk identifier */
  writeString(view, 36, 'data');
  /* Data chunk length */
  view.setUint32(40, dataSize, true);

  const startOffset = 44;
  const totalSamples = Math.floor(durationSeconds * sampleRate);

  // Synthesis Parameters
  const bpm = 120;
  const beatDuration = 60 / bpm;

  for (let i = 0; i < totalSamples; i++) {
    const t = i / sampleRate;
    const beatIndex = Math.floor(t / beatDuration);
    const timeInBeat = t % beatDuration;

    // Layer 1: Sub Bass Pulse
    const subFreq = 40;
    const sub = Math.sin(2 * Math.PI * subFreq * t) * 0.4;

    // Layer 2: Rhythmic Pulse (Kick-like)
    const kickEnv = Math.exp(-timeInBeat * 10);
    const kickFreq = 150 * Math.exp(-timeInBeat * 30);
    const kick = Math.sin(2 * Math.PI * kickFreq * timeInBeat) * kickEnv * 0.5;

    // Layer 3: Melodic Arpeggio (Sequence)
    const notes = [220, 261.63, 293.66, 329.63]; // A3, C4, D4, E4
    const note = notes[beatIndex % notes.length];
    const synthEnv = Math.exp(-(t % (beatDuration / 2)) * 5);
    const melody = Math.sin(2 * Math.PI * note * t) * synthEnv * 0.2;

    // Layer 4: Ambient Noise (Hi-hats/Shimmer)
    const noise = (Math.random() * 2 - 1) * Math.exp(-timeInBeat * 20) * 0.1;

    // Master Mix
    let signal = sub + kick + melody + noise;

    // Panning & Soft Clipping
    signal = Math.max(-1, Math.min(1, signal * 0.8));
    const sample = signal * 0x7FFF;

    const bytePos = startOffset + i * 4;
    if (bytePos + 3 < buffer.byteLength) {
      view.setInt16(bytePos, sample, true);     // L
      view.setInt16(bytePos + 2, sample, true); // R
    }
  }

  const blob = new Blob([buffer], { type: 'audio/wav' });
  return URL.createObjectURL(blob);
}

function writeString(view: DataView, offset: number, string: string) {
  for (let i = 0; i < string.length; i++) {
    view.setUint8(offset + i, string.charCodeAt(i));
  }
}

import React, { useState, useEffect } from 'react';
import { 
  AppState, 
  UserLocalProfile, 
  SongRequest, 
  VideoType, 
  SongRecord, 
  ItemStatus, 
  VocalMode,
  GlobalProductionState 
} from './types';
import { Button } from './components/Button';
import { Input } from './components/Input';
import { getAISuggestion, createProductionPlan, generateVeoVideo } from './services/geminiService';
import { generateSynthesizedAudio } from './services/audioService';

const INITIAL_REQUEST: SongRequest = {
  title: '', description: '',
  durationSeconds: 180, energyCurve: '', structure: '',
  genre: '', subGenre: '', bpm: '', musicalKey: '',
  vocalMode: VocalMode.INSTRUMENTAL, vocalTheme: '', vocalStyle: '',
  styleReferences: '', useCase: '',
  videoTypes: [VideoType.ABSTRACT], videoStyle: '',
  visualIntensity: 'Medium', visualEvolution: ''
};

// Check for existence of global window object for aistudio APIs
declare global {
  interface Window {
    aistudio: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
  }
}

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.ONBOARDING);
  const [user, setUser] = useState<UserLocalProfile | null>(null);
  const [library, setLibrary] = useState<SongRecord[]>([]);
  const [request, setRequest] = useState<SongRequest>(INITIAL_REQUEST);
  const [production, setProduction] = useState<GlobalProductionState>({ 
    isGenerating: false, 
    currentProgress: 0, 
    statusText: ItemStatus.IDLE 
  });
  const [activePage, setActivePage] = useState<AppState>(AppState.HOME);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [explanations, setExplanations] = useState<Record<string, string>>({});
  const [isSuggesting, setIsSuggesting] = useState<Record<string, boolean>>({});
  const [needsApiKey, setNeedsApiKey] = useState(false);

  useEffect(() => {
    const profile = localStorage.getItem('musewave_profile');
    const lib = localStorage.getItem('musewave_library');
    if (profile) {
      setUser(JSON.parse(profile));
      setAppState(AppState.HOME);
    }
    if (lib) setLibrary(JSON.parse(lib));

    // Initial check for Veo API key requirement
    if (window.aistudio) {
      window.aistudio.hasSelectedApiKey().then(hasKey => setNeedsApiKey(!hasKey));
    }
  }, []);

  const handleOnboard = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const fd = new FormData(e.currentTarget);
    const prof: UserLocalProfile = {
      user_id: crypto.randomUUID(),
      name: fd.get('name') as string,
      phone_number: fd.get('mobile') as string,
      created_at: Date.now(),
      last_active_at: Date.now()
    };
    localStorage.setItem('musewave_profile', JSON.stringify(prof));
    setUser(prof);
    setAppState(AppState.HOME);
    setActivePage(AppState.HOME);
  };

  const handleOpenKeySelection = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      setNeedsApiKey(false);
    }
  };

  const handleSuggest = async (field: keyof SongRequest, explanation: string) => {
    setIsSuggesting(prev => ({ ...prev, [field]: true }));
    try {
      const val = await getAISuggestion(field, request);
      setRequest(prev => ({ ...prev, [field]: val }));
      setExplanations(prev => ({ ...prev, [field]: explanation }));
    } finally {
      setIsSuggesting(prev => ({ ...prev, [field]: false }));
    }
  };

  const handleGenerate = async () => {
    if (needsApiKey) {
      await handleOpenKeySelection();
      return;
    }

    if (!request.title || !request.description) {
      alert("Terminal requires Title and Description to initiate signal.");
      return;
    }

    setProduction({ isGenerating: true, statusText: ItemStatus.VALIDATING, currentProgress: 0 });

    try {
      // 1. PLANNING_MINIMAL (0–10%)
      setProduction(prev => ({ ...prev, statusText: ItemStatus.PLANNING_MINIMAL, currentProgress: 5 }));
      const plan = await createProductionPlan(request);
      setProduction(prev => ({ ...prev, currentProgress: 10 }));

      // 2. AUDIO_GENERATING (10–70%)
      setProduction(prev => ({ ...prev, statusText: ItemStatus.AUDIO_GENERATING, currentProgress: 15 }));
      const audioUrl = await generateSynthesizedAudio(request.durationSeconds);
      setProduction(prev => ({ ...prev, currentProgress: 70 }));
      setProduction(prev => ({ ...prev, statusText: ItemStatus.AUDIO_COMPLETE }));

      // 3. VIDEO_RENDERING (70–90%)
      setProduction(prev => ({ ...prev, statusText: ItemStatus.VIDEO_RENDERING, currentProgress: 75 }));

      // We generate one high-quality video using Veo for the main visual
      const videoUrl = await generateVeoVideo(`${request.videoStyle} ${request.genre}`);

      const videos: any[] = request.videoTypes.map(vt => ({
        type: vt,
        url: videoUrl,
        status: ItemStatus.DONE
      }));

      // 4. DONE (100%)
      setProduction(prev => ({ ...prev, currentProgress: 100 }));

      const newRecord: SongRecord = {
        id: crypto.randomUUID(),
        request: { ...request },
        plan,
        audioUrl,
        videos,
        status: ItemStatus.DONE,
        createdAt: Date.now(),
        lastPlaybackPosition: 0
      };

      const newLib = [newRecord, ...library];
      setLibrary(newLib);
      localStorage.setItem('musewave_library', JSON.stringify(newLib));
      setProduction({ isGenerating: false, statusText: ItemStatus.DONE, currentProgress: 100, activeSongId: newRecord.id });
    } catch (e) {
      console.error(e);
      setProduction({ isGenerating: false, statusText: ItemStatus.FAILED, currentProgress: 0 });
      alert("Signal Fault: " + (e as Error).message);
    }
  };

  const formatSeconds = (s: number) => {
    const hrs = Math.floor(s / 3600).toString().padStart(2, '0');
    const mins = Math.floor((s % 3600) / 60).toString().padStart(2, '0');
    const secs = Math.floor(s % 60).toString().padStart(2, '0');
    return `${hrs}:${mins}:${secs}`;
  };

  const resetApp = () => {
    if (confirm("Reset MuseWave Terminal? Local archive will be purged.")) {
      localStorage.clear();
      window.location.reload();
    }
  };

  if (!process.env.API_KEY) {
    return <div className="p-20 text-red-500 font-black text-center text-xl uppercase tracking-widest">Configuration error: GOOGLE_API_KEY is missing or invalid.</div>;
  }

  if (appState === AppState.ONBOARDING) {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-deep">
        <div className="glass max-w-lg w-full p-16 rounded-[4rem] border border-white/5 space-y-12">
          <div className="text-center space-y-2">
            <h1 className="text-6xl font-space font-black tracking-tighter text-glow uppercase">MuseWave</h1>
            <p className="text-zinc-600 text-[10px] font-black uppercase tracking-[0.6em]">Establish Identity Link</p>
          </div>
          <form onSubmit={handleOnboard} className="space-y-8">
            <Input label="Full Name" name="name" placeholder="Johnathan Miller" required />
            <Input label="Mobile Number" name="mobile" placeholder="+1 000-000-0000" type="tel" required />
            <Button fullWidth type="submit" className="h-20 text-lg font-black muse-gradient rounded-[2rem]">Continue</Button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex bg-deep font-sans">
      <aside className={`fixed h-full bg-[#050505] border-r border-white/5 transition-all duration-500 z-50 ${isSidebarOpen ? 'w-72' : 'w-24'}`}>
        <div className="flex flex-col h-full">
          <div className="p-10 flex items-center justify-between">
            <h2 className={`text-3xl font-space font-black tracking-tighter text-brand uppercase ${isSidebarOpen ? 'opacity-100' : 'opacity-0 hidden'}`}>MW</h2>
            <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="text-zinc-700 hover:text-brand transition-colors text-xl">
              {isSidebarOpen ? '❮' : '❯'}
            </button>
          </div>
          <nav className="flex-1 px-6 space-y-4 mt-12">
            <SidebarItem icon="🏠" label="Home" active={activePage === AppState.HOME} collapsed={!isSidebarOpen} onClick={() => setActivePage(AppState.HOME)} />
            <SidebarItem 
              icon="✨" 
              label="Create Music" 
              active={activePage === AppState.CREATE} 
              collapsed={!isSidebarOpen} 
              onClick={() => setActivePage(AppState.CREATE)} 
              badge={production.isGenerating ? production.statusText.replace('_', ' ') : undefined} 
            />
            <SidebarItem icon="📚" label="Dashboard" active={activePage === AppState.DASHBOARD} collapsed={!isSidebarOpen} onClick={() => setActivePage(AppState.DASHBOARD)} />
          </nav>
          <div className="p-8 border-t border-white/5 bg-black/20">
            <div className={`flex items-center gap-4 mb-8 ${isSidebarOpen ? 'opacity-100' : 'opacity-0'}`}>
              <div className="w-10 h-10 rounded-xl bg-zinc-900 flex items-center justify-center text-xs font-black border border-white/10 text-brand">{user?.name[0]}</div>
              <div className="min-w-0">
                <p className="text-xs font-black truncate text-zinc-300">{user?.name}</p>
                <p className="text-[9px] font-bold text-zinc-600 truncate">{user?.phone_number}</p>
              </div>
            </div>
            <button onClick={resetApp} className="w-full text-[9px] font-black uppercase text-zinc-800 hover:text-red-500 text-left px-2">Reset App</button>
          </div>
        </div>
      </aside>

      <main className={`flex-1 transition-all duration-500 ${isSidebarOpen ? 'ml-72' : 'ml-24'}`}>
        <div className="max-w-7xl mx-auto w-full min-h-screen relative">
          {activePage === AppState.HOME && <HomePage onStart={() => setActivePage(AppState.CREATE)} />}
          {activePage === AppState.CREATE && (
            <CreatePage 
              request={request} setRequest={setRequest} 
              onSuggest={handleSuggest} onGenerate={handleGenerate} 
              production={production} 
              lastSong={library.find(s => s.id === production.activeSongId)}
              explanations={explanations}
              isSuggesting={isSuggesting}
              formatSeconds={formatSeconds}
              needsApiKey={needsApiKey}
              onSelectKey={handleOpenKeySelection}
              setActivePage={setActivePage}
            />
          )}
          {activePage === AppState.DASHBOARD && <DashboardPage library={library} onNavigate={() => setActivePage(AppState.CREATE)} formatSeconds={formatSeconds} />}
        </div>
      </main>
    </div>
  );
};

const SidebarItem = ({ icon, label, active, collapsed, onClick, badge }: any) => (
  <button onClick={onClick} className={`w-full flex items-center gap-5 px-5 py-5 rounded-[1.5rem] transition-all relative ${active ? 'bg-brand text-white shadow-xl shadow-brand/20' : 'text-zinc-600 hover:bg-white/5 hover:text-zinc-300'}`}>
    <span className="text-2xl">{icon}</span>
    {!collapsed && <span className="text-sm font-black tracking-tight uppercase">{label}</span>}
    {badge && !collapsed && <span className="absolute right-4 top-1/2 -translate-y-1/2 text-[7px] px-2 py-1 bg-white/20 rounded-full animate-pulse border border-white/10 uppercase">{badge}</span>}
  </button>
);

const HomePage = ({ onStart }: any) => (
  <div className="p-24 space-y-32">
    <div className="space-y-12">
      <div className="inline-block px-6 py-2 rounded-full border border-brand/20 bg-brand/5 text-brand text-[10px] font-black uppercase tracking-[0.4em]">Engine Signal Stable</div>
      <h1 className="text-[10rem] font-space font-black tracking-tighter leading-[0.8] text-glow uppercase">Sonic<br/><span className="text-brand">Visual</span></h1>
      <p className="text-4xl text-zinc-500 max-w-3xl leading-relaxed font-light font-space">Infinite audio-visual synthesis for long-form sessions. Up to 20-hour capacity.</p>
      <Button onClick={onStart} className="h-24 px-16 text-xl tracking-[0.3em] rounded-[2.5rem]">Create Your First Track</Button>
    </div>
    <div className="grid grid-cols-1 md:grid-cols-3 gap-16 pt-24 border-t border-white/5">
      <div className="space-y-4">
        <div className="text-6xl mb-6">⚡</div>
        <h3 className="text-2xl font-space font-black uppercase tracking-tighter">1. Describe</h3>
        <p className="text-zinc-500 leading-relaxed font-medium">Define your sonic atmosphere using neural suggestions.</p>
      </div>
      <div className="space-y-4">
        <div className="text-6xl mb-6">👁️</div>
        <h3 className="text-2xl font-space font-black uppercase tracking-tighter">2. Synthesize</h3>
        <p className="text-zinc-500 leading-relaxed font-medium">Real-time PCM synthesis into hi-fidelity WAV master files.</p>
      </div>
      <div className="space-y-4">
        <div className="text-6xl mb-6">⏳</div>
        <h3 className="text-2xl font-space font-black uppercase tracking-tighter">3. Download</h3>
        <p className="text-zinc-500 leading-relaxed font-medium">Export master WAV audio and cinematic video layers.</p>
      </div>
    </div>
  </div>
);

const CreatePage = ({ request, setRequest, onSuggest, onGenerate, production, lastSong, explanations, isSuggesting, formatSeconds, needsApiKey, onSelectKey, setActivePage }: any) => {
  const [expandedGroups, setExpandedGroups] = useState<number[]>([1, 6]);
  const toggleGroup = (id: number) => setExpandedGroups(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);

  const locked = production.isGenerating;

  return (
    <div className="flex h-screen overflow-hidden">
      <div className="flex-1 overflow-y-auto p-16 space-y-10 scroll-smooth pb-60">
        <div className="border-b border-white/5 pb-8">
          <h2 className="text-5xl font-space font-black tracking-tighter uppercase">Creative Workspace</h2>
          <p className="text-zinc-600 font-bold uppercase text-[10px] tracking-[0.5em] mt-2">Neural Parameter Sync</p>
        </div>

        {needsApiKey && (
          <div className="p-10 rounded-[3rem] bg-brand/10 border border-brand/30 space-y-4">
            <p className="text-sm font-black text-brand uppercase tracking-widest">Video Synthesis requires a Paid API Key</p>
            <p className="text-xs text-zinc-400 leading-relaxed">To generate real-time video, you must select an API key from a paid GCP project. Check billing docs at <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="underline">ai.google.dev/gemini-api/docs/billing</a>.</p>
            <Button onClick={onSelectKey} className="h-14 px-8 rounded-2xl bg-brand text-white">Select API Key</Button>
          </div>
        )}

        <div className="space-y-6">
          <InputGroup label="Core Idea" active={expandedGroups.includes(1)} onClick={() => toggleGroup(1)}>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-6">
              <Input label="Song Title" placeholder="Linear Field" value={request.title} onChange={e => setRequest({...request, title: e.target.value})} onSuggest={() => onSuggest('title', "Primary identifier for the generated track.")} isSuggesting={isSuggesting['title']} helperText={explanations['title'] || "Used as the track's display name."} disabled={locked} />
              <Input label="Song Idea" placeholder="Dark melodic techno..." isTextArea value={request.description} onChange={e => setRequest({...request, description: e.target.value})} onSuggest={() => onSuggest('description', "Main prompt for sonic synthesis direction.")} isSuggesting={isSuggesting['description']} helperText={explanations['description'] || "Defines the overall creative direction."} disabled={locked} />
            </div>
          </InputGroup>

          <InputGroup label="Musical Shape" active={expandedGroups.includes(2)} onClick={() => toggleGroup(2)}>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-6">
              <div className="space-y-4">
                <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest text-zinc-700">
                  <span>Duration</span>
                  <span className="text-brand font-space">{formatSeconds(request.durationSeconds)}</span>
                </div>
                <input type="range" min="30" max="1800" step="30" className="w-full h-2 bg-zinc-900 rounded-full accent-brand cursor-pointer" value={request.durationSeconds} onChange={e => setRequest({...request, durationSeconds: parseInt(e.target.value)})} disabled={locked} />
              </div>
              <Input label="Energy Curve" placeholder="Slow rise → steady plateau..." value={request.energyCurve} onChange={e => setRequest({...request, energyCurve: e.target.value})} onSuggest={() => onSuggest('energyCurve', "Defines dynamic intensity.")} isSuggesting={isSuggesting['energyCurve']} helperText={explanations['energyCurve'] || "Defines intensity movement."} disabled={locked} />
            </div>
          </InputGroup>

          <InputGroup label="Sound & Rhythm" active={expandedGroups.includes(3)} onClick={() => toggleGroup(3)}>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-6">
              <Input label="Genre" placeholder="Techno" value={request.genre} onChange={e => setRequest({...request, genre: e.target.value})} onSuggest={() => onSuggest('genre', "The foundational style.")} isSuggesting={isSuggesting['genre']} helperText={explanations['genre'] || "Sets the core genre."} disabled={locked} />
              <div className="grid grid-cols-2 gap-4">
                <Input label="BPM" placeholder="124" value={request.bpm} onChange={e => setRequest({...request, bpm: e.target.value})} onSuggest={() => onSuggest('bpm', "Rhythmic center.")} isSuggesting={isSuggesting['bpm']} helperText={explanations['bpm'] || "Locks track tempo."} disabled={locked} />
                <Input label="Key" placeholder="A Minor" value={request.musicalKey} onChange={e => setRequest({...request, musicalKey: e.target.value})} onSuggest={() => onSuggest('musicalKey', "Tonal foundation.")} isSuggesting={isSuggesting['musicalKey']} helperText={explanations['musicalKey'] || "Locks tonal center."} disabled={locked} />
              </div>
            </div>
          </InputGroup>

          <InputGroup label="Video Output" active={expandedGroups.includes(6)} onClick={() => toggleGroup(6)}>
            <div className="space-y-8 pt-6">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                {Object.values(VideoType).map(vt => {
                  const active = request.videoTypes.includes(vt);
                  return (
                    <button key={vt} onClick={() => setRequest(prev => ({ ...prev, videoTypes: active ? (prev.videoTypes.length > 1 ? prev.videoTypes.filter(t => t !== vt) : prev.videoTypes) : [...prev.videoTypes, vt] }))} className={`py-6 rounded-2xl border-2 text-[10px] font-black uppercase tracking-widest transition-all ${active ? 'bg-brand/10 border-brand text-white shadow-lg' : 'bg-surface border-white/5 text-zinc-800'}`} disabled={locked}>
