                      {vt}
                    </button>
                  );
                })}
              </div>
              <Input label="Video Style" placeholder="Abstract neon geometry..." value={request.videoStyle} onChange={e => setRequest({...request, videoStyle: e.target.value})} onSuggest={() => onSuggest('videoStyle', "Visual aesthetic direction.")} isSuggesting={isSuggesting['videoStyle']} helperText={explanations['videoStyle'] || "Defines the cinematic look."} disabled={locked} />
            </div>
          </InputGroup>
        </div>

        <div className="pt-16">
          <Button fullWidth onClick={onGenerate} loading={production.isGenerating} className="h-24 text-2xl font-black rounded-[2.5rem] muse-gradient">
            {needsApiKey ? 'Select Key to Generate' : 'Generate Music'}
          </Button>
        </div>
      </div>

      <div className="w-[450px] border-l border-white/5 bg-[#050505] overflow-y-auto p-12 flex flex-col justify-center">
        {production.isGenerating || lastSong ? (
          <div className="space-y-12 animate-in fade-in slide-in-from-right duration-500">
            {production.isGenerating ? (
              <div className="text-center space-y-12">
                <div className="relative w-64 h-64 mx-auto">
                  <div className="absolute inset-0 border-4 border-white/5 rounded-full scale-110"></div>
                  <div className="absolute inset-0 border-4 border-brand rounded-full border-t-transparent animate-spin"></div>
                  <div className="absolute inset-0 flex items-center justify-center text-6xl font-space font-black tracking-tighter text-glow">{production.currentProgress}%</div>
                </div>
                <div className="space-y-4">
                  <h3 className="text-3xl font-space font-black uppercase tracking-tight text-white">{production.statusText.replace('_', ' ')}</h3>
                  <p className="text-zinc-600 text-[10px] font-bold uppercase tracking-widest">Generating high-fidelity media. Please wait...</p>
                </div>
              </div>
            ) : (
              <div className="space-y-10 py-10">
                <div className="aspect-video bg-black rounded-[3rem] overflow-hidden border border-white/5 relative group">
                  <video src={lastSong?.videos[0].url} className="w-full h-full object-cover" controls autoPlay loop />
