  </button>
);

const HomePage = ({ onStart }: any) => (
  <div className="p-24 space-y-32">
    <div className="space-y-12">
      <div className="inline-block px-6 py-2 rounded-full border border-brand/20 bg-brand/5 text-brand text-[10px] font-black uppercase tracking-[0.4em]">Engine Signal Stable</div>
