const CreatePage = ({ request, setRequest, onSuggest, onGenerate, production, lastSong, explanations, isSuggesting, formatSeconds, needsApiKey, setActivePage }: any) => {
  const [expandedGroups, setExpandedGroups] = useState<number[]>([1, 6]);
  const toggleGroup = (id: number) => setExpandedGroups(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
  const locked = production.isGenerating;

  return (
    <div className="flex h-screen overflow-hidden">
      <div className="flex-1 overflow-y-auto p-16 space-y-10 scroll-smooth pb-60">
        <div className="border-b border-white/5 pb-8">
          <h2 className="text-5xl font-space font-black tracking-tighter uppercase">Workspace</h2>
          <p className="text-zinc-600 font-bold uppercase text-[10px] tracking-[0.5em] mt-2">Neural Parameter Sync</p>
        </div>

        {needsApiKey && (
          <div className="p-8 rounded-[2rem] bg-brand/10 border border-brand/20 space-y-2">
            <h4 className="text-[10px] font-black text-brand uppercase tracking-widest">Veo Video Generation Enabled</h4>
            <p className="text-[10px] text-zinc-400">Paid API Key selection required for Cinema-Grade Visuals.</p>
          </div>
        )}

        <div className="space-y-6">
          <InputGroup label="Core Idea" active={expandedGroups.includes(1)} onClick={() => toggleGroup(1)}>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-6">
              <Input label="Song Title" placeholder="Linear Field" value={request.title} onChange={e => setRequest({...request, title: e.target.value})} onSuggest={() => onSuggest('title', "Primary identifier.")} isSuggesting={isSuggesting['title']} helperText={explanations['title'] || "Display name."} disabled={locked} />
              <Input label="Song Idea" placeholder="Hypnotic build..." isTextArea value={request.description} onChange={e => setRequest({...request, description: e.target.value})} onSuggest={() => onSuggest('description', "Creative brief.")} isSuggesting={isSuggesting['description']} helperText={explanations['description'] || "Synthesis direction."} disabled={locked} />
            </div>
          </InputGroup>

          <InputGroup label="Musical Shape" active={expandedGroups.includes(2)} onClick={() => toggleGroup(2)}>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-6">
              <div className="space-y-4">
                <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest text-zinc-700">
                  <span>Duration</span>
                  <span className="text-brand font-space">{formatSeconds(request.durationSeconds)}</span>
                </div>
                <input type="range" min="30" max="72000" step="30" className="w-full h-2 bg-zinc-900 rounded-full accent-brand cursor-pointer" value={request.durationSeconds} onChange={e => setRequest({...request, durationSeconds: parseInt(e.target.value)})} disabled={locked} />
              </div>
              <Input label="Energy Curve" placeholder="Slow rise..." value={request.energyCurve} onChange={e => setRequest({...request, energyCurve: e.target.value})} onSuggest={() => onSuggest('energyCurve', "Intensity profile.")} isSuggesting={isSuggesting['energyCurve']} helperText={explanations['energyCurve'] || "Dynamic progression."} disabled={locked} />
            </div>
          </InputGroup>

          <InputGroup label="Video Output" active={expandedGroups.includes(6)} onClick={() => toggleGroup(6)}>
            <div className="space-y-8 pt-6">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                {Object.values(VideoType).map(vt => {
                  const active = request.videoTypes.includes(vt);
                  return (
                    <button key={vt} onClick={() => setRequest(prev => ({ ...prev, videoTypes: active ? (prev.videoTypes.length > 1 ? prev.videoTypes.filter(t => t !== vt) : prev.videoTypes) : [...prev.videoTypes, vt] }))} className={`py-6 rounded-2xl border-2 text-[10px] font-black uppercase tracking-widest transition-all ${active ? 'bg-brand/10 border-brand text-white shadow-lg' : 'bg-surface border-white/5 text-zinc-800'}`} disabled={locked}>
                      {vt}
                    </button>
                  );
                })}
              </div>
              <Input label="Video Style" placeholder="Neon geometry..." value={request.videoStyle} onChange={e => setRequest({...request, videoStyle: e.target.value})} onSuggest={() => onSuggest('videoStyle', "Aesthetic look.")} isSuggesting={isSuggesting['videoStyle']} helperText={explanations['videoStyle'] || "Cinematic direction."} disabled={locked} />
            </div>
          </InputGroup>
        </div>

        <div className="pt-16">
          <Button fullWidth onClick={onGenerate} loading={production.isGenerating} className="h-24 text-2xl font-black rounded-[2.5rem] muse-gradient">Generate Music</Button>
        </div>
      </div>

      <div className="w-[450px] border-l border-white/5 bg-[#050505] overflow-y-auto p-12 flex flex-col justify-center">
        {production.isGenerating || lastSong ? (
          <div className="space-y-12 animate-in fade-in slide-in-from-right duration-500">
            {production.isGenerating ? (
              <div className="text-center space-y-12">
                <div className="relative w-64 h-64 mx-auto">
                  <div className="absolute inset-0 border-4 border-white/5 rounded-full scale-110"></div>
                  <div className="absolute inset-0 border-4 border-brand rounded-full border-t-transparent animate-spin"></div>
                  <div className="absolute inset-0 flex items-center justify-center text-6xl font-space font-black tracking-tighter text-glow">{production.currentProgress}%</div>
                </div>
                <div className="space-y-4">
                  <h3 className="text-3xl font-space font-black uppercase tracking-tight text-white">{production.statusText.replace('_', ' ')}</h3>
                  <p className="text-zinc-600 text-[10px] font-bold uppercase tracking-widest">You can navigate away. We’ll keep working.</p>
                </div>
              </div>
            ) : (
              <div className="space-y-10 py-10">
                <div className="space-y-4">
                  <h2 className="text-5xl font-space font-black uppercase tracking-tighter leading-none">{lastSong?.request.title}</h2>
                  <div className="flex gap-4">
                    {lastSong?.videos.map((v, i) => (
                      <div key={i} className="aspect-video bg-black rounded-3xl overflow-hidden border border-white/5 flex-1">
                        <video src={v.url} className="w-full h-full object-cover" controls autoPlay loop muted />
                      </div>
                    ))}
                  </div>
                </div>
                <div className="space-y-6">
                  <div className="grid grid-cols-2 gap-8 border-y border-white/5 py-10 my-6">
                    <OutputStat label="Length" value={formatSeconds(lastSong?.request.durationSeconds || 0)} />
                    <OutputStat label="Status" value="FINALIZED" color="text-brand" />
                  </div>
                  <audio controls src={lastSong?.audioUrl} className="w-full mb-6 accent-brand" />
                  <div className="space-y-4">
                    <Button fullWidth variant="primary" className="h-16 rounded-2xl text-[10px]" onClick={() => {
                        const link = document.createElement('a');
                        link.href = lastSong?.audioUrl || '';
                        link.download = `${lastSong?.request.title}.wav`;
                        link.click();
                    }}>Download Master WAV</Button>
                    <Button variant="outline" className="w-full h-14 rounded-xl text-[9px]" onClick={() => setActivePage(AppState.DASHBOARD)}>Go to Dashboard</Button>
                  </div>
                </div>
              </div>
            )}
          </div>
        ) : (
          <div className="h-full flex flex-col items-center justify-center text-center space-y-8 opacity-20 grayscale">
            <div className="text-[10rem]">📀</div>
            <p className="text-xl font-space italic max-w-xs mx-auto">Your generated music and videos will appear here.</p>
          </div>
        )}
      </div>
    </div>
  );
};

const InputGroup = ({ label, active, onClick, children }: any) => (
  <div className={`transition-all duration-500 rounded-[2.5rem] border ${active ? 'border-brand/40 bg-white/[0.02] p-8' : 'border-white/5 p-6 hover:bg-white/[0.01]'}`}>
