/**
 * Enhanced Utility to wrap API calls with jittered exponential backoff for 429 errors.
 */
async function withRetry<T>(fn: () => Promise<T>, maxRetries = 5): Promise<T> {
  let delay = 3000; // Increased initial delay to 3s
  for (let i = 0; i < maxRetries; i++) {
    try {
      return await fn();
    } catch (error: any) {
      const isQuotaError = error?.message?.includes('429') || 
                          error?.status === 'RESOURCE_EXHAUSTED' ||
                          error?.message?.includes('quota');

      if (isQuotaError) {
        if (i === maxRetries - 1) throw error;

        // Add jitter: +/- 20% of the delay
        const jitter = delay * 0.2 * (Math.random() * 2 - 1);
        const finalDelay = delay + jitter;

        console.warn(`[MuseWave] Quota exceeded. Attempt ${i + 1}/${maxRetries}. Retrying in ${Math.round(finalDelay)}ms...`);

        await new Promise(resolve => setTimeout(resolve, finalDelay));
        delay *= 2.5; // More aggressive multiplier
        continue;
      }
      throw error;
    }
  }
  throw new Error("Max retries exceeded for AI signal.");
}

