                <div className="text-[10px] font-black uppercase text-zinc-800">Captured {new Date(song.createdAt).toLocaleDateString()}</div>
                <button onClick={() => {
                  const link = document.createElement('a');
                  link.href = song.audioUrl;
                  link.download = `${song.request.title}.wav`;
                  link.click();
                }} className="w-16 h-16 rounded-[1.5rem] bg-white/5 flex items-center justify-center text-xl hover:bg-brand transition-all">💾</button>
              </div>
            </div>
          </div>
        ))}
      </div>
    )}
  </div>
);

