      <div className="flex-1 overflow-y-auto p-16 space-y-10 scroll-smooth pb-60">
        <div className="border-b border-white/5 pb-8">
          <h2 className="text-5xl font-space font-black tracking-tighter uppercase">Workspace</h2>
          <p className="text-zinc-600 font-bold uppercase text-[10px] tracking-[0.5em] mt-2">Neural Parameter Sync</p>
        </div>

        {needsApiKey && (
          <div className="p-8 rounded-[2rem] bg-brand/10 border border-brand/20 space-y-2">
            <h4 className="text-[10px] font-black text-brand uppercase tracking-widest">Veo Video Generation Enabled</h4>
            <p className="text-[10px] text-zinc-400">Paid API Key selection required for Cinema-Grade Visuals. <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noreferrer" className="underline">Billing Info</a></p>
          </div>
