/**
 * MuseWave High-Fidelity Audio Synthesis Engine
 * Generates valid WAV files with layered synthesis to provide a "real" musical experience.
 */

export async function generateSynthesizedAudio(durationSeconds: number): Promise<string> {
  const sampleRate = 44100;
  const numChannels = 2;
  const bitsPerSample = 16;
  const byteRate = sampleRate * numChannels * (bitsPerSample / 8);
  const blockAlign = numChannels * (bitsPerSample / 8);
  const dataSize = Math.floor(durationSeconds * byteRate);
  const fileSize = 44 + dataSize;

  // Browser Limit Protection: 
  // Most browsers fail to allocate ArrayBuffers larger than ~2GB.
  // 1 hour of 44.1k/16bit/Stereo is approx 635MB. 
  // We cap at 1200 seconds (20 mins) for safe head-room, though UI caps at 600.
  if (fileSize > 1024 * 1024 * 1024) { // 1GB limit
    throw new Error("Array buffer allocation failed: Requested duration exceeds safe browser memory limits.");
  }

  let buffer: ArrayBuffer;
  try {
    buffer = new ArrayBuffer(fileSize);
  } catch (e) {
    throw new Error("Array buffer allocation failed: Browser was unable to reserve enough contiguous memory.");
  }

  const view = new DataView(buffer);

  /* RIFF identifier */
  writeString(view, 0, 'RIFF');
  /* File length */
  view.setUint32(4, fileSize - 8, true);
  /* RIFF type */
  writeString(view, 8, 'WAVE');
  /* Format chunk identifier */
  writeString(view, 12, 'fmt ');
  /* Format chunk length */
  view.setUint32(16, 16, true);
  /* Sample format (1 is PCM) */
  view.setUint16(20, 1, true);
  /* Channel count */
  view.setUint16(22, numChannels, true);
  /* Sample rate */
  view.setUint32(24, sampleRate, true);
  /* Byte rate */
  view.setUint32(28, byteRate, true);
  /* Block align */
  view.setUint16(32, blockAlign, true);
  /* Bits per sample */
  view.setUint16(34, bitsPerSample, true);
  /* Data chunk identifier */
  writeString(view, 36, 'data');
  /* Data chunk length */
  view.setUint32(40, dataSize, true);

  const startOffset = 44;
  const totalSamples = Math.floor(durationSeconds * sampleRate);

  // Synthesis Parameters
  const bpm = 120;
  const beatDuration = 60 / bpm;

  for (let i = 0; i < totalSamples; i++) {
    const t = i / sampleRate;
    const beatIndex = Math.floor(t / beatDuration);
    const timeInBeat = t % beatDuration;

    // Layer 1: Sub Bass Pulse
    const subFreq = 40;
    const sub = Math.sin(2 * Math.PI * subFreq * t) * 0.4;

    // Layer 2: Rhythmic Pulse (Kick-like)
    const kickEnv = Math.exp(-timeInBeat * 10);
    const kickFreq = 150 * Math.exp(-timeInBeat * 30);
    const kick = Math.sin(2 * Math.PI * kickFreq * timeInBeat) * kickEnv * 0.5;

    // Layer 3: Melodic Arpeggio (Sequence)
    const notes = [220, 261.63, 293.66, 329.63]; // A3, C4, D4, E4
    const note = notes[beatIndex % notes.length];
    const synthEnv = Math.exp(-(t % (beatDuration / 2)) * 5);
    const melody = Math.sin(2 * Math.PI * note * t) * synthEnv * 0.2;

    // Layer 4: Ambient Noise (Hi-hats/Shimmer)
    const noise = (Math.random() * 2 - 1) * Math.exp(-timeInBeat * 20) * 0.1;

    // Master Mix
    let signal = sub + kick + melody + noise;

    // Panning & Soft Clipping
    signal = Math.max(-1, Math.min(1, signal * 0.8));
    const sample = signal * 0x7FFF;

    const bytePos = startOffset + i * 4;
    if (bytePos + 3 < buffer.byteLength) {
      view.setInt16(bytePos, sample, true);     // L
      view.setInt16(bytePos + 2, sample, true); // R
    }
  }

  const blob = new Blob([buffer], { type: 'audio/wav' });
  return URL.createObjectURL(blob);
}

function writeString(view: DataView, offset: number, string: string) {
  for (let i = 0; i < string.length; i++) {
    view.setUint8(offset + i, string.charCodeAt(i));
  }
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { SongRequest, ImmutableSongPlan } from "../types";

const getAi = () => new GoogleGenAI({ apiKey: process.env.API_KEY as string });

/**
 * Enhanced Utility to wrap API calls with jittered exponential backoff for 429 errors.
 * Now specifically attempts to parse retryDelay from the error message.
 */
async function withRetry<T>(fn: () => Promise<T>, maxRetries = 5): Promise<T> {
  let delay = 3000;
  for (let i = 0; i < maxRetries; i++) {
    try {
      return await fn();
    } catch (error: any) {
      const errorMsg = error?.message || "";
      const isQuotaError = errorMsg.includes('429') || 
                          error?.status === 'RESOURCE_EXHAUSTED' ||
                          errorMsg.toLowerCase().includes('quota');

      if (isQuotaError) {
        if (i === maxRetries - 1) throw error;

        // Attempt to extract "Please retry in 54s" style messages
        let waitTime = delay;
        const retryMatch = errorMsg.match(/retry in ([\d\.]+)s/i);
        if (retryMatch && retryMatch[1]) {
          waitTime = (parseFloat(retryMatch[1]) + 2) * 1000; // Add 2s safety buffer
        } else {
          // Standard exponential backoff with jitter
          const jitter = delay * 0.2 * (Math.random() * 2 - 1);
          waitTime = delay + jitter;
          delay *= 2.5; 
        }

        console.warn(`[MuseWave] Quota exceeded. Attempt ${i + 1}/${maxRetries}. Retrying in ${Math.round(waitTime)}ms...`);

        await new Promise(resolve => setTimeout(resolve, waitTime));
        continue;
      }
      throw error;
    }
  }
  throw new Error("Max retries exceeded for AI signal.");
}

/**
 * AI Suggest: Generates field-specific, context-aware values.
 * Uses 'gemini-flash-lite-latest' for maximum efficiency and higher quota.
 */
export async function getAISuggestion(field: keyof SongRequest, currentRequest: Partial<SongRequest>): Promise<string> {
  const ai = getAi();
  const context = JSON.stringify({
    title: currentRequest.title,
    description: currentRequest.description,
    genre: currentRequest.genre,
    bpm: currentRequest.bpm,
    duration: currentRequest.durationSeconds
  });

  const prompt = `You are an elite music producer for MuseWave. 
  Suggest a UNIQUE value for the track field: "${field.toString()}".
  CONTEXT: ${context}
  STRICT RULES: Output ONLY the value. NO conversational filler.`;

  try {
    const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
      model: 'gemini-flash-lite-latest',
      contents: prompt,
    }));
    return response.text.trim();
  } catch (error) {
    console.error("AI Suggest failure:", error);
    return "Neural Pulse " + Math.floor(Math.random() * 1000);
  }
}

/**
 * Immutable Song Plan: Creates the structural backbone for the song.
 * Switched to 'gemini-flash-lite-latest' to avoid hitting the strict 20-request limit of the 3-series preview models.
 */
export async function createProductionPlan(request: SongRequest): Promise<ImmutableSongPlan> {
  const ai = getAi();
  const prompt = `Generate a high-level musical structure plan for a ${request.durationSeconds}s track.
  Title: ${request.title}
  Genre: ${request.genre}
  Energy: ${request.energyCurve}
  Provide a detailed technical plan including BPM, Key, and structural segments.`;

  const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
    model: 'gemini-flash-lite-latest',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          bpm: { type: Type.NUMBER },
          key: { type: Type.STRING },
          scale: { type: Type.STRING },
          instrumentPalette: { type: Type.ARRAY, items: { type: Type.STRING } },
          sections: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                startTime: { type: Type.NUMBER },
                endTime: { type: Type.NUMBER },
                label: { type: Type.STRING },
                energy: { type: Type.NUMBER },
                description: { type: Type.STRING }
              },
              required: ["startTime", "endTime", "label", "energy", "description"]
            }
          },
          macroEnergyCurve: { type: Type.ARRAY, items: { type: Type.NUMBER } },
          textureEvolutionStrategy: { type: Type.STRING }
        },
        required: ["bpm", "key", "scale", "instrumentPalette", "sections", "macroEnergyCurve", "textureEvolutionStrategy"]
      }
    }
  }));

  return JSON.parse(response.text.trim());
}

/**
 * Video Generation using Veo 3.1.
 */
export async function generateVeoVideo(prompt: string, type: string): Promise<string> {
  const ai = getAi();

  let operation: any = await withRetry(() => ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: `Professional ${type} background. High fidelity, cinematic lighting. Style: ${prompt}`,
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: '16:9'
    }
  }));

  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 10000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!downloadLink) throw new Error("Video synthesis failed.");

  const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  if (!response.ok) throw new Error(`Video stream error: ${response.statusText}`);

  const blob = await response.blob();
  return URL.createObjectURL(blob);
}

import React, { useState, useEffect, useRef } from 'react';
import { 
  AppState, 
  UserLocalProfile, 
  SongRequest, 
  VideoType, 
  SongRecord, 
  ItemStatus, 
  VocalMode,
  GlobalProductionState,
  VideoAsset
} from './types';
import { Button } from './components/Button';
import { Input } from './components/Input';
import { getAISuggestion, createProductionPlan, generateVeoVideo } from './services/geminiService';
import { generateSynthesizedAudio } from './services/audioService';

const INITIAL_REQUEST: SongRequest = {
  title: '', description: '',
  durationSeconds: 180, energyCurve: '', structure: '',
  genre: '', subGenre: '', bpm: '', musicalKey: '',
  vocalMode: VocalMode.INSTRUMENTAL, vocalTheme: '', vocalStyle: '',
  styleReferences: '', useCase: '',
  videoTypes: [VideoType.ABSTRACT], videoStyle: '',
  visualIntensity: 'Medium', visualEvolution: ''
};

declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }
  interface Window {
    // Fixed: Added optional modifier '?' to aistudio to match internal environmental definitions
    aistudio?: AIStudio;
  }
}

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.ONBOARDING);
  const [user, setUser] = useState<UserLocalProfile | null>(null);
  const [library, setLibrary] = useState<SongRecord[]>([]);
  const [request, setRequest] = useState<SongRequest>(INITIAL_REQUEST);
  const [production, setProduction] = useState<GlobalProductionState>({ 
    isGenerating: false, currentProgress: 0, statusText: ItemStatus.IDLE 
  });
  const [activePage, setActivePage] = useState<AppState>(AppState.HOME);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [explanations, setExplanations] = useState<Record<string, string>>({});
  const [isSuggesting, setIsSuggesting] = useState<Record<string, boolean>>({});
  const [needsApiKey, setNeedsApiKey] = useState(false);

  useEffect(() => {
    const profile = localStorage.getItem('musewave_profile');
    const lib = localStorage.getItem('musewave_library');
    if (profile) {
      setUser(JSON.parse(profile));
      setAppState(AppState.HOME);
    }
    if (lib) setLibrary(JSON.parse(lib));

    if (window.aistudio) {
      window.aistudio.hasSelectedApiKey().then(hasKey => setNeedsApiKey(!hasKey));
    }
  }, []);

  const handleOnboard = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const fd = new FormData(e.currentTarget);
    const prof: UserLocalProfile = {
      user_id: crypto.randomUUID(),
      name: fd.get('name') as string,
      phone_number: fd.get('mobile') as string,
      created_at: Date.now(),
      last_active_at: Date.now()
    };
    localStorage.setItem('musewave_profile', JSON.stringify(prof));
    setUser(prof);
    setAppState(AppState.HOME);
    setActivePage(AppState.HOME);
  };

  const handleSuggest = async (field: keyof SongRequest, explanation: string) => {
    setIsSuggesting(prev => ({ ...prev, [field]: true }));
    try {
      const val = await getAISuggestion(field, request);
      setRequest(prev => ({ ...prev, [field]: val }));
      setExplanations(prev => ({ ...prev, [field]: explanation }));
    } finally {
      setIsSuggesting(prev => ({ ...prev, [field]: false }));
    }
  };

  const handleGenerate = async () => {
    if (needsApiKey && window.aistudio) {
      await window.aistudio.openSelectKey();
      setNeedsApiKey(false);
    }

    if (!request.title || !request.description) {
      alert("Terminal requires Title and Description to initiate signal.");
      return;
    }

    setProduction({ isGenerating: true, statusText: ItemStatus.VALIDATING, currentProgress: 0 });

    try {
      setProduction(prev => ({ ...prev, statusText: ItemStatus.PLANNING_MINIMAL, currentProgress: 5 }));
      const plan = await createProductionPlan(request);
      setProduction(prev => ({ ...prev, currentProgress: 10 }));

      setProduction(prev => ({ ...prev, statusText: ItemStatus.AUDIO_GENERATING, currentProgress: 15 }));
      const audioUrl = await generateSynthesizedAudio(request.durationSeconds);
      setProduction(prev => ({ ...prev, currentProgress: 70 }));
      setProduction(prev => ({ ...prev, statusText: ItemStatus.AUDIO_COMPLETE }));

      setProduction(prev => ({ ...prev, statusText: ItemStatus.VIDEO_RENDERING, currentProgress: 75 }));

      // Sequential video generation to respect API rate limits
      const videos: VideoAsset[] = [];
      for (const vt of request.videoTypes) {
        setProduction(prev => ({ ...prev, statusText: `${ItemStatus.VIDEO_RENDERING} (${vt})` as ItemStatus }));
        const url = await generateVeoVideo(request.videoStyle || request.genre, vt);
        videos.push({ type: vt, url, status: ItemStatus.DONE });
        setProduction(prev => ({ ...prev, currentProgress: prev.currentProgress + (25 / request.videoTypes.length) }));
      }

      setProduction(prev => ({ ...prev, currentProgress: 100 }));

      const newRecord: SongRecord = {
        id: crypto.randomUUID(),
        request: { ...request },
        plan,
        audioUrl,
        videos,
        status: ItemStatus.DONE,
        createdAt: Date.now(),
        lastPlaybackPosition: 0
      };

      const newLib = [newRecord, ...library];
      setLibrary(newLib);
      localStorage.setItem('musewave_library', JSON.stringify(newLib));
      setProduction({ isGenerating: false, statusText: ItemStatus.DONE, currentProgress: 100, activeSongId: newRecord.id });
    } catch (e: any) {
      console.error(e);
      setProduction({ isGenerating: false, statusText: ItemStatus.FAILED, currentProgress: 0 });

      const errorMsg = e.message || "";
      const isQuota = errorMsg.includes('429') || e.status === 'RESOURCE_EXHAUSTED' || errorMsg.toLowerCase().includes('quota');

      if (errorMsg.includes("Requested entity was not found")) {
        setNeedsApiKey(true);
      }

      if (isQuota) {
        const retryMatch = errorMsg.match(/retry in ([\d\.]+)s/i);
        const waitTime = retryMatch ? ` Please retry in ${retryMatch[1]}s.` : " Please wait 60 seconds and try again.";
        alert(`Signal Fault: Quota exceeded.${waitTime} High-performance models have strict daily limits on the free tier.`);
      } else if (errorMsg.includes("Array buffer allocation failed")) {
        alert("Signal Fault: Memory Exhaustion. Requested audio duration exceeds browser limits. Try a shorter track.");
      } else {
        alert("Signal Fault: " + errorMsg);
      }
    }
  };

  const formatSeconds = (s: number) => {
    const hrs = Math.floor(s / 3600).toString().padStart(2, '0');
    const mins = Math.floor((s % 3600) / 60).toString().padStart(2, '0');
    const secs = Math.floor(s % 60).toString().padStart(2, '0');
    return `${hrs}:${mins}:${secs}`;
  };

  const resetApp = () => {
    if (confirm("Reset MuseWave Terminal? Local archive will be purged.")) {
      localStorage.clear();
      window.location.reload();
    }
  };

  if (appState === AppState.ONBOARDING) {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-deep">
        <div className="glass max-w-lg w-full p-16 rounded-[4rem] border border-white/5 space-y-12">
          <div className="text-center space-y-2">
            <h1 className="text-6xl font-space font-black tracking-tighter text-glow uppercase">MuseWave</h1>
            <p className="text-zinc-600 text-[10px] font-black uppercase tracking-[0.6em]">Establish Identity Link</p>
          </div>
          <form onSubmit={handleOnboard} className="space-y-8">
            <Input label="Full Name" name="name" placeholder="Johnathan Miller" required />
            <Input label="Mobile Number" name="mobile" placeholder="+1 000-000-0000" type="tel" required />
            <Button fullWidth type="submit" className="h-20 text-lg font-black muse-gradient rounded-[2rem]">Continue</Button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex bg-deep font-sans">
      <aside className={`fixed h-full bg-[#050505] border-r border-white/5 transition-all duration-500 z-50 ${isSidebarOpen ? 'w-72' : 'w-24'}`}>
        <div className="flex flex-col h-full">
          <div className="p-10 flex items-center justify-between">
            <h2 className={`text-3xl font-space font-black tracking-tighter text-brand uppercase ${isSidebarOpen ? 'opacity-100' : 'opacity-0 hidden'}`}>MW</h2>
            <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="text-zinc-700 hover:text-brand transition-colors text-xl">
              {isSidebarOpen ? '❮' : '❯'}
            </button>
          </div>
          <nav className="flex-1 px-6 space-y-4 mt-12">
            <SidebarItem icon="🏠" label="Home" active={activePage === AppState.HOME} collapsed={!isSidebarOpen} onClick={() => setActivePage(AppState.HOME)} />
            <SidebarItem 
              icon="✨" 
              label="Create Music" 
              active={activePage === AppState.CREATE} 
              collapsed={!isSidebarOpen} 
              onClick={() => setActivePage(AppState.CREATE)} 
