const getAi = () => new GoogleGenAI({ apiKey: process.env.API_KEY as string });

/**
 * Global AI Queue to ensure strict sequential execution.
 * Optimized to handle Free Tier RPM limits (typically 15 RPM).
 */
class AIQueue {
  private queue: Promise<any> = Promise.resolve();
  private lastRequestTime: number = 0;
  private readonly COOLDOWN_MS = 6000; // 6s cooldown (max 10 RPM) for extreme safety

  async enqueue<T>(task: () => Promise<T>): Promise<T> {
    const resultPromise = this.queue.then(async () => {
      const now = Date.now();
      const timeSinceLast = now - this.lastRequestTime;

      if (timeSinceLast < this.COOLDOWN_MS) {
        const wait = this.COOLDOWN_MS - timeSinceLast;
        await new Promise(resolve => setTimeout(resolve, wait));
      }

      try {
        const result = await withRetry(task);
        this.lastRequestTime = Date.now();
        return result;
      } catch (error) {
        this.lastRequestTime = Date.now();
        throw error;
      }
    });

    // Ensure the queue chain continues even if this specific request fails
    this.queue = resultPromise.catch(() => {});

    return resultPromise;
  }
}

const globalQueue = new AIQueue();

/**
