import { UserSession, ProjectRecord, AppState } from "../types";

const SESSION_KEY = 'sw_session';
const PROJECTS_KEY = 'sw_projects';

export const db = {
  // Session management
  getSession: (): UserSession | null => {
    const data = localStorage.getItem(SESSION_KEY);
    return data ? JSON.parse(data) : null;
  },

  saveSession: (session: UserSession) => {
    localStorage.setItem(SESSION_KEY, JSON.stringify(session));
  },

  clearSession: () => {
    localStorage.removeItem(SESSION_KEY);
  },

  // Project management
  getProjects: (userId: string): ProjectRecord[] => {
    const data = localStorage.getItem(PROJECTS_KEY);
    const all: ProjectRecord[] = data ? JSON.parse(data) : [];
    return all.filter(p => p.userId === userId).sort((a, b) => b.createdAt - a.createdAt);
  },

  saveProject: (project: ProjectRecord) => {
    const data = localStorage.getItem(PROJECTS_KEY);
    const all: ProjectRecord[] = data ? JSON.parse(data) : [];
    const index = all.findIndex(p => p.id === project.id);
    if (index > -1) {
      all[index] = project;
    } else {
      all.push(project);
    }
    localStorage.setItem(PROJECTS_KEY, JSON.stringify(all));
  },

  deleteProject: (id: string) => {
    const data = localStorage.getItem(PROJECTS_KEY);
    const all: ProjectRecord[] = data ? JSON.parse(data) : [];
    const filtered = all.filter(p => p.id !== id);
    localStorage.setItem(PROJECTS_KEY, JSON.stringify(filtered));
  }
};

import { GoogleGenAI, Type } from "@google/genai";

const getAi = () => new GoogleGenAI({ apiKey: process.env.API_KEY as string });

export async function getFieldSuggestion(field: string, currentValue: string, context: any): Promise<string> {
  const ai = getAi();
  const model = ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `
      You are a professional music consultant for SoundWeave.
      Task: Provide a suggestion for the field "${field}".

      Current Value: "${currentValue || 'EMPTY'}"
      Context of other fields: ${JSON.stringify(context)}

      Rules:
      1. If the current value is EMPTY, generate a unique, high-quality, professional suggestion.
      2. If the current value is FILLED, enhance it for clarity, professional tone, and emotional impact without changing the original user intent.
      3. Return ONLY the suggestion text. No conversational filler.
    `.trim()
  });

  const response = await model;
  return response.text.trim();
}

export async function interpretIntent(project: any) {
  const ai = getAi();
  const prompt = `
    Analyze the following music project intent and generate a production metadata object:
    ${JSON.stringify(project)}

    Output JSON:
    - mood: string
    - energyLevel: 0-100
    - technicalNotes: string
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          mood: { type: Type.STRING },
          energyLevel: { type: Type.NUMBER },
          technicalNotes: { type: Type.STRING }
        }
      }
    }
  });

  return JSON.parse(response.text.trim());
}

export async function generateVeoVideo(style: string, genre: string): Promise<string> {
  const ai = getAi();
  let operation: any = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: `Cinematic visual for ${genre} music. Style: ${style}. Professional, immersive, high quality.`,
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: '16:9'
    }
  });

  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 10000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  const blob = await response.blob();
  return URL.createObjectURL(blob);
}

import React, { useState, useEffect, useRef } from 'react';
