  const handleSuggest = async (field: string, currentValue: string) => {
    setIsSuggesting(true);
    try {
      const context = { mode, title, prompt, selectedGenres, vocalLangs };
      const suggestion = await getFieldSuggestion(field, currentValue, context);
      setAiPreview({ field, value: suggestion });
    } catch (e) {
      alert("AI Suggestion failed. Check API key.");
