    <div className="space-y-3 group">
      <div className="flex justify-between items-center px-1">
        <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 group-focus-within:text-brand transition-colors">{label}</label>
        <button onClick={onSuggest} disabled={suggesting} className="text-[9px] font-black text-brand/40 hover:text-brand transition-all flex items-center gap-2 disabled:opacity-20">
          {suggesting ? <span className="animate-spin text-lg">◌</span> : '✨ AI SUGGEST'}
        </button>
      </div>
      <Component 
        value={value} 
        onChange={(e: any) => onChange(e.target.value)} 
        placeholder={placeholder}
        className={`w-full bg-black/40 border border-white/5 rounded-2xl px-5 py-4 text-white text-sm focus:outline-none focus:border-brand/40 transition-all ${isTextArea ? 'min-h-[140px] resize-none' : ''}`}
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { 
  AppState, 
  UserSession, 
  CreationMode, 
  ProjectRecord, 
  Status, 
  TrackData 
} from './types';
import { db } from './services/dbService';
import { getFieldSuggestion, interpretIntent, generateVeoVideo } from './services/geminiService';
import { generateSynthesizedAudio } from './services/audioService';

const GENRES = [
  "Lo-Fi", "Synthwave", "Neo-Classical", "Cyberpunk", "Deep House", 
  "Ambient", "Industrial", "Orchestral", "Phonk", "Jazz Fusion", "Techno"
];

const LANGUAGES = [
  "Instrumental", "English", "Japanese", "French", "Spanish", "German", "Korean"
];

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.AUTH);
  const [session, setSession] = useState<UserSession | null>(null);
  const [projects, setProjects] = useState<ProjectRecord[]>([]);
  const [activeTab, setActiveTab] = useState<AppState>(AppState.HOME);

  // Form State
  const [mode, setMode] = useState<CreationMode>(CreationMode.SINGLE);
  const [numSongs, setNumSongs] = useState(1);
  const [title, setTitle] = useState('');
  const [prompt, setPrompt] = useState('');
  const [selectedGenres, setSelectedGenres] = useState<string[]>([]);
  const [duration, setDuration] = useState(180);
  const [vocalLangs, setVocalLangs] = useState<string[]>(["Instrumental"]);
  const [lyrics, setLyrics] = useState('');
  const [artistRefs, setArtistRefs] = useState<string[]>([]);
  const [videoEnabled, setVideoEnabled] = useState(false);
  const [videoStyle, setVideoStyle] = useState('');

  const [isProcessing, setIsProcessing] = useState(false);
  // Track which specific fields are currently receiving suggestions
  const [suggestingFields, setSuggestingFields] = useState<Record<string, boolean>>({});

  useEffect(() => {
    const s = db.getSession();
    if (s) {
      setSession(s);
      setAppState(AppState.HOME);
      setProjects(db.getProjects(s.id));
    }
  }, []);

  const handleAuth = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const fd = new FormData(e.currentTarget);
    const mobile = (fd.get('mobile') as string).trim();
    const name = fd.get('name') as string;

    // Indian mobile number validation: starts with 6-9, 10 digits total. 
    // Optional +91 prefix allowed.
    const indianMobileRegex = /^(?:\+91)?[6789]\d{9}$/;

    if (!indianMobileRegex.test(mobile)) {
      alert("Invalid mobile number. Please enter a valid Indian mobile number (e.g., +91 9876543210 or 9876543210).");
      return;
    }

    const newSession: UserSession = { id: crypto.randomUUID(), name, mobile };
    db.saveSession(newSession);
    setSession(newSession);
    setAppState(AppState.HOME);
    setActiveTab(AppState.HOME);
    setProjects(db.getProjects(newSession.id));
  };

  const handleLogout = () => {
    db.clearSession();
    setSession(null);
    setAppState(AppState.AUTH);
  };

  const handleSuggest = async (field: string, currentValue: string) => {
    setSuggestingFields(prev => ({ ...prev, [field]: true }));

    try {
      const context = { mode, title, prompt, selectedGenres, vocalLangs };
      const suggestion = await getFieldSuggestion(field, currentValue, context);

      // Auto-apply the suggestion directly to the state
      if (field === 'title') setTitle(suggestion);
      if (field === 'prompt') setPrompt(suggestion);
      if (field === 'lyrics') setLyrics(suggestion);
      if (field === 'videoStyle') setVideoStyle(suggestion);

    } catch (e) {
      console.error(`AI Suggestion for ${field} failed:`, e);
    } finally {
      setSuggestingFields(prev => ({ ...prev, [field]: false }));
    }
  };

  const startGeneration = async () => {
    if (!title || !prompt || selectedGenres.length === 0) {
      alert("Missing mandatory fields: Title, Prompt, and Genres.");
      return;
    }

    setIsProcessing(true);
    const newProject: ProjectRecord = {
      id: crypto.randomUUID(),
      userId: session!.id,
      mode, title, prompt, 
      genres: selectedGenres,
      durationSeconds: duration,
      vocalLanguages: vocalLangs,
      lyrics,
      artistReferences: artistRefs,
      videoEnabled,
      videoStyle,
      tracks: [],
      status: Status.PROCESSING,
      createdAt: Date.now()
    };

    try {
      const intent = await interpretIntent(newProject);
      const trackCount = mode === CreationMode.ALBUM ? numSongs : 1;
      const tracks: TrackData[] = [];

      for (let i = 0; i < trackCount; i++) {
        const audioUrl = await generateSynthesizedAudio(duration);
        let videoUrl = undefined;
        if (videoEnabled) {
          videoUrl = await generateVeoVideo(videoStyle || "Abstract Visuals", selectedGenres[0]);
        }
        tracks.push({
          id: crypto.randomUUID(),
          title: mode === CreationMode.ALBUM ? `${title} - Track ${i+1}` : title,
          audioUrl,
          videoUrl,
          duration
        });
      }

      newProject.tracks = tracks;
      newProject.status = Status.COMPLETED;
      db.saveProject(newProject);
      setProjects(prev => [newProject, ...prev]);
      setActiveTab(AppState.DASHBOARD);

      // Reset form
      setTitle(''); setPrompt(''); setSelectedGenres([]); setLyrics('');
    } catch (e) {
      newProject.status = Status.FAILED;
      db.saveProject(newProject);
      alert("Generation encountered an error.");
    } finally {
      setIsProcessing(false);
    }
  };

  if (appState === AppState.AUTH) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-deep p-6">
        <div className="glass w-full max-w-md p-10 rounded-3xl space-y-8">
          <div className="text-center">
            <h1 className="text-4xl font-bold tracking-tight text-white mb-2">SoundWeave</h1>
            <p className="text-zinc-500 text-sm">Professional AI Music Studio</p>
          </div>
          <form onSubmit={handleAuth} className="space-y-6">
            <div className="space-y-2">
              <label className="text-xs font-semibold text-zinc-400 uppercase tracking-widest">Display Name</label>
              <input name="name" required className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-brand" placeholder="Maestro" />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-semibold text-zinc-400 uppercase tracking-widest">Indian Mobile Number</label>
              <input name="mobile" type="tel" required className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-brand" placeholder="+91 9876543210" />
              <p className="text-[10px] text-zinc-500">Sign in restricted to Indian mobile numbers only.</p>
            </div>
            <button type="submit" className="w-full bg-brand py-4 rounded-xl font-bold hover:brightness-110 transition-all">Enter Studio</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex bg-deep">
      {/* Sidebar */}
      <aside className="w-72 border-r border-white/5 bg-[#080808] flex flex-col">
        <div className="p-8">
          <h2 className="text-xl font-bold tracking-tighter text-white">SOUNDWEAVE</h2>
        </div>
        <nav className="flex-1 px-4 space-y-2">
          <NavItem active={activeTab === AppState.HOME} onClick={() => setActiveTab(AppState.HOME)} icon="🏠" label="Home" />
          <NavItem active={activeTab === AppState.CREATE} onClick={() => setActiveTab(AppState.CREATE)} icon="✨" label="Create Music" />
          <NavItem active={activeTab === AppState.DASHBOARD} onClick={() => setActiveTab(AppState.DASHBOARD)} icon="📊" label="Dashboard" />
        </nav>
        <div className="p-6 border-t border-white/5 space-y-4">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-brand flex items-center justify-center font-bold">{session?.name[0]}</div>
            <div className="min-w-0">
              <p className="text-sm font-bold truncate">{session?.name}</p>
              <p className="text-[10px] text-zinc-500 truncate">{session?.mobile}</p>
            </div>
          </div>
          <button onClick={handleLogout} className="text-[10px] uppercase font-bold text-zinc-600 hover:text-red-500 transition-colors">Logout</button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto">
        <div className="max-w-5xl mx-auto p-12">
          {activeTab === AppState.HOME && (
            <div className="space-y-12 py-10">
              <h1 className="text-7xl font-bold tracking-tight">Your Music <br/><span className="text-brand">Workspace.</span></h1>
              <div className="grid grid-cols-2 gap-6">
                <button onClick={() => setActiveTab(AppState.CREATE)} className="glass p-12 rounded-[2.5rem] text-left hover:border-brand/40 transition-all group">
                  <span className="text-4xl block mb-6">✨</span>
                  <h3 className="text-2xl font-bold mb-2">Create Music</h3>
                  <p className="text-zinc-500 text-sm">Initiate new neural synthesis projects.</p>
                </button>
                <button onClick={() => setActiveTab(AppState.DASHBOARD)} className="glass p-12 rounded-[2.5rem] text-left hover:border-brand/40 transition-all group">
                  <span className="text-4xl block mb-6">📊</span>
                  <h3 className="text-2xl font-bold mb-2">Dashboard</h3>
                  <p className="text-zinc-500 text-sm">Review and export your completed tracks.</p>
                </button>
              </div>
            </div>
          )}

          {activeTab === AppState.CREATE && (
            <div className={`space-y-12 transition-opacity ${isProcessing ? 'opacity-50 pointer-events-none' : ''}`}>
              <div className="flex justify-between items-end">
                <div>
                  <h2 className="text-4xl font-bold">New Project</h2>
                  <p className="text-zinc-500">Define your creative intent below.</p>
                </div>
                {isProcessing && <div className="text-brand font-mono animate-pulse">GENERATING SIGNAL...</div>}
              </div>

              {/* Mode Selection */}
              <section className="space-y-4">
                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600">Creation Mode</label>
                <div className="flex gap-4">
                  {[CreationMode.SINGLE, CreationMode.ALBUM].map(m => (
                    <button key={m} onClick={() => setMode(m)} className={`px-8 py-4 rounded-xl border font-bold transition-all ${mode === m ? 'border-brand bg-brand/10 text-white' : 'border-white/5 text-zinc-600'}`}>
                      {m}
                    </button>
                  ))}
                </div>
                {mode === CreationMode.ALBUM && (
                  <div className="pt-4 flex items-center gap-6">
                    <label className="text-sm font-bold text-zinc-400">Number of Songs</label>
                    <input type="number" min="2" max="15" value={numSongs} onChange={e => setNumSongs(parseInt(e.target.value))} className="bg-black border border-white/10 rounded-lg px-4 py-2 w-24" />
                  </div>
                )}
              </section>

              {/* Meta */}
              <section className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <Field label="Project Title" value={title} onChange={setTitle} onSuggest={() => handleSuggest('title', title)} suggesting={suggestingFields['title']} />
                <Field label="Music Prompt" isTextArea value={prompt} onChange={setPrompt} onSuggest={() => handleSuggest('prompt', prompt)} suggesting={suggestingFields['prompt']} placeholder="e.g. A melancholic lo-fi beat for rainy nights in Tokyo..." />
              </section>

              {/* Genres */}
              <section className="space-y-4">
                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600">Genres (Multi-select)</label>
                <div className="flex flex-wrap gap-2">
                  {GENRES.map(g => (
                    <button key={g} onClick={() => setSelectedGenres(prev => prev.includes(g) ? prev.filter(x => x !== g) : [...prev, g])} className={`px-4 py-2 rounded-full text-xs font-bold border transition-all ${selectedGenres.includes(g) ? 'bg-brand border-brand text-white' : 'border-white/5 text-zinc-500'}`}>
                      {g}
                    </button>
                  ))}
                </div>
              </section>

              {/* Duration */}
              <section className="space-y-6">
                 <div className="flex justify-between items-end">
                    <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600">Duration</label>
                    <div className="text-2xl font-mono text-brand">{Math.floor(duration/60)}m {duration%60}s</div>
                 </div>
                 <input type="range" min="30" max="600" step="10" value={duration} onChange={e => setDuration(parseInt(e.target.value))} className="w-full h-1 bg-white/10 accent-brand rounded-full cursor-pointer" />
              </section>

              {/* Vocals */}
              <section className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-4">
                  <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600">Languages</label>
                  <div className="grid grid-cols-2 gap-2">
                    {LANGUAGES.map(l => (
                      <button key={l} onClick={() => setVocalLangs(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l])} className={`px-4 py-3 rounded-xl border text-[10px] font-bold uppercase transition-all ${vocalLangs.includes(l) ? 'border-brand bg-brand/5' : 'border-white/5 text-zinc-600'}`}>
                        {l}
                      </button>
                    ))}
                  </div>
                </div>
                <Field label="Lyrics / Vocal Theme" isTextArea value={lyrics} onChange={setLyrics} onSuggest={() => handleSuggest('lyrics', lyrics)} suggesting={suggestingFields['lyrics']} />
              </section>

              {/* Video */}
              <section className="glass p-8 rounded-3xl space-y-6">
                <div className="flex items-center justify-between">
                  <div>
                    <h4 className="font-bold">Visual Generation</h4>
                    <p className="text-xs text-zinc-500">Enable cinema-grade video for your music.</p>
                  </div>
                  <button onClick={() => setVideoEnabled(!videoEnabled)} className={`w-14 h-8 rounded-full transition-all relative ${videoEnabled ? 'bg-brand' : 'bg-white/10'}`}>
                    <div className={`absolute top-1 w-6 h-6 rounded-full bg-white transition-all ${videoEnabled ? 'left-7' : 'left-1'}`} />
                  </button>
                </div>
                {videoEnabled && (
                  <Field label="Video Visual Style" value={videoStyle} onChange={setVideoStyle} onSuggest={() => handleSuggest('videoStyle', videoStyle)} suggesting={suggestingFields['videoStyle']} />
                )}
              </section>

              <button onClick={startGeneration} className="w-full bg-brand py-6 rounded-2xl text-xl font-bold shadow-2xl shadow-brand/20 hover:scale-[1.01] active:scale-[0.99] transition-all">
                SYNTHESIZE PRODUCTION
              </button>
            </div>
          )}

          {activeTab === AppState.DASHBOARD && (
            <div className="space-y-12 py-10">
              <h2 className="text-5xl font-bold tracking-tight">Archive</h2>
              {projects.length === 0 ? (
                <div className="text-center py-40 border-2 border-dashed border-white/5 rounded-[3rem]">
                  <p className="text-zinc-600">No projects found in the stream.</p>
                </div>
              ) : (
                <div className="space-y-6">
                  {projects.map(p => (
                    <div key={p.id} className="glass p-8 rounded-3xl flex items-center justify-between group">
                      <div className="space-y-1">
                        <div className="flex items-center gap-3">
                          <h4 className="text-xl font-bold">{p.title}</h4>
                          <span className={`text-[10px] font-bold px-2 py-0.5 rounded ${p.status === Status.COMPLETED ? 'bg-green-500/20 text-green-500' : 'bg-red-500/20 text-red-500'}`}>{p.status}</span>
                        </div>
                        <p className="text-[10px] text-zinc-500 uppercase tracking-widest">{p.mode} • {p.genres.join(', ')} • {new Date(p.createdAt).toLocaleDateString()}</p>
                      </div>
                      <div className="flex items-center gap-4">
                        {p.tracks.map((t) => (
                           <div key={t.id} className="flex gap-2">
                              <button onClick={() => {
                                const audio = new Audio(t.audioUrl);
                                audio.play();
                              }} className="w-12 h-12 rounded-xl bg-white/5 flex items-center justify-center hover:bg-brand transition-all">▶</button>
                              <a href={t.audioUrl} download={`${t.title}.wav`} className="w-12 h-12 rounded-xl bg-white/5 flex items-center justify-center hover:bg-zinc-800 transition-all">💾</a>
                              {t.videoUrl && <a href={t.videoUrl} download={`${t.title}.mp4`} className="w-12 h-12 rounded-xl bg-brand/20 flex items-center justify-center hover:bg-brand transition-all">🎬</a>}
                           </div>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

const NavItem = ({ active, onClick, icon, label }: any) => (
  <button onClick={onClick} className={`w-full flex items-center gap-4 px-6 py-4 rounded-xl transition-all font-bold ${active ? 'active-tab' : 'text-zinc-600 hover:bg-white/5 hover:text-zinc-300'}`}>
    <span className="text-xl">{icon}</span>
    <span className="text-sm">{label}</span>
  </button>
);

const Field = ({ label, value, onChange, onSuggest, suggesting, isTextArea, placeholder }: any) => {
  const Component = isTextArea ? 'textarea' : 'input';
  return (
    <div className="space-y-3 group">
      <div className="flex justify-between items-center px-1">
        <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 group-focus-within:text-brand transition-colors">{label}</label>
        <button onClick={onSuggest} disabled={suggesting} className="text-[9px] font-black text-brand/40 hover:text-brand transition-all flex items-center gap-2 disabled:opacity-50">
          {suggesting ? <span className="animate-spin text-lg inline-block">◌</span> : '✨ AI SUGGEST'}
        </button>
      </div>
      <div className="relative">
        <Component 
          value={value} 
          onChange={(e: any) => onChange(e.target.value)} 
          placeholder={suggesting ? "Neural link active... generating..." : placeholder}
          className={`w-full bg-black/40 border border-white/5 rounded-2xl px-5 py-4 text-white text-sm focus:outline-none focus:border-brand/40 transition-all ${isTextArea ? 'min-h-[140px] resize-none' : ''} ${suggesting ? 'opacity-50 animate-pulse' : ''}`}
        />
        {suggesting && (
           <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
              <span className="text-[10px] font-mono text-brand/60 uppercase tracking-widest">Optimizing field...</span>
           </div>
        )}
      </div>
    </div>
  );
};

export default App;
